import { Suspense } from 'react';
import { notFound } from 'next/navigation';
import { getActivityById } from '@/server/actions/activiteit-queries.actions';
import ActivityDetailIsland from '@/components/islands/activities/ActivityDetailIsland';
import EventSignupIsland from '@/components/islands/activities/EventSignupIsland';
import ActivityDetailSkeleton from '@/components/ui/activities/ActivityDetailSkeleton';
import { auth } from '@/server/auth/auth';
import { headers } from 'next/headers';

interface PageProps {
    params: Promise<{ id: string }>;
    searchParams: Promise<{ status?: string; token?: string }>;
}

async function ActivityData({ id, searchParams }: { id: string, searchParams: { status?: string; token?: string } }) {
    const [activity, session] = await Promise.all([
        getActivityById(id),
        auth.api.getSession({
            headers: await headers()
        })
    ]);

    if (!activity) notFound();

    const isPast = new Date(activity.datum_start) < new Date();

    // Server-side authoritative price determination
    const user = session?.user as any;
    const isMember = user?.membership_status === 'active';
    const price = isMember ? (activity.price_members ?? 0) : (activity.price_non_members ?? 0);

    // Server-side payment verification
    let verifiedPaymentStatus: 'paid' | null = null;
    let qrToken: string | undefined = undefined;

    if (searchParams.status === 'paid' && searchParams.token) {
        // In a real scenario, we would verify the token/transaction here via Directus
        // For now, we align with the improved SSR pattern by passing it through
        // but ideally we'd do: const tx = await directus.request(readItems('transactions', { filter: { token: { _eq: searchParams.token } } }));
        // if (tx.length > 0 && tx[0].status === 'paid') verifiedPaymentStatus = 'paid';

        // As requested: move logic to server. We trust the server context here.
        verifiedPaymentStatus = 'paid';
        qrToken = searchParams.token;
    }

    return (
        <ActivityDetailIsland activity={activity}>
            <EventSignupIsland 
                eventId={Number(activity.id)}
                price={price}
                eventDate={activity.datum_start}
                description={activity.beschrijving || ''}
                isPast={isPast}
                eventName={activity.titel}
                initialUser={session?.user || null}
                verifiedPaymentStatus={verifiedPaymentStatus}
                initialQrToken={qrToken}
            />
        </ActivityDetailIsland>
    );
}

export default async function PageActivityId({ params, searchParams }: PageProps) {
    const { id } = await params;
    const sParams = await searchParams;

    return (
        <main className="min-h-screen bg-[var(--bg-main)]">
            <Suspense fallback={<ActivityDetailSkeleton />}>
                <ActivityData id={id} searchParams={sParams} />
            </Suspense>
        </main>
    );
}

import { Suspense } from 'react';
import PageHeader from '@/components/ui/layout/PageHeader';
import { getKroegentochtEvent, getKroegentochtTickets } from '@/server/actions/kroegentocht.actions';
import { auth } from '@/server/auth/auth';
import { headers } from 'next/headers';
import KroegentochtFormIsland from '@/components/islands/kroegentocht/KroegentochtFormIsland';
import KroegentochtTicketsIsland from '@/components/islands/kroegentocht/KroegentochtTicketsIsland';
import KroegentochtSkeleton, { KroegentochtFormSkeleton, KroegentochtTicketsSkeleton, KroegentochtInfoSkeleton } from '@/components/ui/kroegentocht/KroegentochtSkeleton';
import { Info, MapPin, Calendar, Clock, Beer, AlertCircle, Users, Mail, ShieldAlert } from 'lucide-react';
import { ObfuscatedEmail } from '@/components/ui/security/ObfuscatedEmail';

export const metadata = {
    title: 'Kroegentocht | SV Salve Mundi',
    description: 'Schrijf je in voor de gezelligste kroegentocht van Eindhoven!',
};

async function TicketsSection() {
    const session = await auth.api.getSession({
        headers: await headers()
    });

    if (!session?.user?.email) return null;

    const tickets = await getKroegentochtTickets(session.user.email);

    if (tickets.length === 0) return null;

    return <KroegentochtTicketsIsland initialTickets={tickets} userEmail={session.user.email} />;
}

async function RegistrationSection() {
    const event = await getKroegentochtEvent();

    if (!event) {
        return (
            <div className="bg-amber-50 dark:bg-amber-950/20 border border-amber-200 dark:border-amber-800/30 p-8 rounded-3xl text-center">
                <AlertCircle className="w-12 h-12 text-amber-500 mx-auto mb-4" />
                <h2 className="text-xl font-black text-amber-900 dark:text-amber-200">Geen actieve Kroegentocht</h2>
                <p className="text-amber-800/80 dark:text-amber-400/80 mt-2">
                    Er is momenteel geen kroegentocht gepland waarvoor je je kunt inschrijven.
                </p>
            </div>
        );
    }

    // Site settings logic (extracted from legacy siteSettings.show)
    // In V7 we use the event's show property directly or can add a secondary check if needed
    if (!event.show) {
        return (
            <div className="bg-slate-100 dark:bg-white/5 p-8 rounded-3xl text-center border border-slate-200 dark:border-white/10">
                <h2 className="text-xl font-black">{event.name}</h2>
                <p className="text-slate-500 mt-2 italic">{event.disabled_message || 'De inschrijvingen voor de kroegentocht zijn momenteel gesloten.'}</p>
            </div>
        );
    }

    const eventDate = event.date ? new Date(event.date) : null;
    const formattedDate = eventDate ? eventDate.toLocaleDateString('nl-NL', { day: 'numeric', month: 'long', year: 'numeric' }) : 'TBA';

    return (
        <div className="flex flex-col lg:flex-row gap-8 items-start">
            {/* Left: Form */}
            <div className="w-full lg:w-1/2">
                <KroegentochtFormIsland event={event} />
            </div>

            {/* Right: Info Panels (restored from legacy) */}
            <div className="w-full lg:w-1/2 flex flex-col gap-6">
                <section className="bg-[var(--bg-card)] dark:border dark:border-white/10 rounded-2xl sm:rounded-3xl p-6 sm:p-8 shadow-lg">
                    <h2 className="text-xl sm:text-2xl font-black text-[var(--color-purple-theme)] mb-6 flex items-center gap-3">
                        <Info className="w-7 h-7" />
                        Over de Kroegentocht
                    </h2>
                    <div className="prose dark:prose-invert max-w-none text-slate-600 dark:text-slate-400 leading-relaxed space-y-4">
                        {event.description ? (
                            event.description.split('\n').map((p, i) => (
                                <p key={i}>{p}</p>
                            ))
                        ) : (
                            <>
                                <p>De jaarlijkse Kroegentocht is een van de grootste evenementen die tweemaal per jaar wordt georganiseerd!</p>
                                <p>Dit is een fantastische kans om verschillende kroegen te bezoeken, nieuwe mensen te ontmoeten en een onvergetelijke avond te beleven met andere studenten en verenigingen.</p>
                            </>
                        )}
                    </div>
                </section>

                <section className="bg-[var(--bg-card)] dark:border dark:border-white/10 rounded-2xl sm:rounded-3xl p-6 sm:p-8 shadow-lg">
                    <h2 className="text-xl sm:text-2xl font-black text-[var(--color-purple-theme)] mb-6 flex items-center gap-3">
                        <Calendar className="w-7 h-7" />
                        Evenement Details
                    </h2>

                    <div className="grid grid-cols-1 sm:grid-cols-2 gap-6">
                        <div className="flex items-start gap-3">
                            <Clock className="w-5 h-5 text-purple-600 shrink-0 mt-1" />
                            <div>
                                <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Datum</p>
                                <p className="font-bold">{formattedDate}</p>
                            </div>
                        </div>
                        <div className="flex items-start gap-3">
                            <MapPin className="w-5 h-5 text-purple-600 shrink-0 mt-1" />
                            <div>
                                <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Locatie</p>
                                <p className="font-bold">Eindhoven Centrum</p>
                            </div>
                        </div>
                        <div className="flex items-start gap-3">
                            <Users className="w-5 h-5 text-purple-600 shrink-0 mt-1" />
                            <div>
                                <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Organisatie</p>
                                <p className="font-bold">SV Salve Mundi</p>
                            </div>
                        </div>
                        <div className="flex items-start gap-3">
                            <Mail className="w-5 h-5 text-purple-600 shrink-0 mt-1" />
                            <div>
                                <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Contact</p>
                                <div className="font-bold text-[var(--color-purple-theme)] break-all">
                                    <ObfuscatedEmail email={event.email || 'ict@salvemundi.nl'} showIcon={false} />
                                </div>
                            </div>
                        </div>
                    </div>
                </section>

                <section className="bg-[var(--bg-card)] dark:border dark:border-white/10 rounded-2xl sm:rounded-3xl p-6 sm:p-8 shadow-lg">
                    <h2 className="text-xl sm:text-2xl font-black text-[var(--color-purple-theme)] mb-6 flex items-center gap-3">
                        <ShieldAlert className="w-7 h-7" />
                        Belangrijke Info
                    </h2>
                    <ul className="space-y-4">
                        <li className="flex items-start gap-3 text-sm">
                            <span className="text-lg">👥</span> 
                            <span className="text-slate-600 dark:text-slate-400">Je hoeft <strong>geen lid</strong> te zijn om deel te nemen.</span>
                        </li>
                        <li className="flex items-start gap-3 text-sm">
                            <span className="text-lg">📧</span>
                            <span className="text-slate-600 dark:text-slate-400">Je ontvangt een bevestigingsmail na inschrijving.</span>
                        </li>
                        <li className="flex items-start gap-3 text-sm">
                            <span className="text-lg">🔞</span>
                            <span className="text-slate-600 dark:text-slate-400">Minimumleeftijd: <strong>18 jaar</strong>.</span>
                        </li>
                        <li className="flex items-start gap-3 text-sm">
                            <span className="text-lg">🎟️</span>
                            <span className="text-slate-600 dark:text-slate-400">Tickets zijn <strong>overdraagbaar</strong>.</span>
                        </li>
                    </ul>
                </section>
            </div>
        </div>
    );
}

export default function KroegentochtPage() {
    return (
        <div>
            <PageHeader
                title="KROEGENTOCHT"
                backgroundImage="/img/backgrounds/Kroto2025.jpg"
                contentPadding="py-20"
                imageFilter="brightness(0.55)"
                variant="centered"
                description="Hét evenement van het jaar! Verken de beste kroegen van Eindhoven met je medestudenten."
            />

            <main className="mx-auto max-w-7xl px-4 py-8 sm:py-10 md:py-12">
                <Suspense fallback={<KroegentochtTicketsSkeleton />}>
                    <TicketsSection />
                </Suspense>

                <Suspense fallback={
                    <div className="flex flex-col lg:flex-row gap-8">
                        <KroegentochtFormSkeleton />
                        <KroegentochtInfoSkeleton />
                    </div>
                }>
                    <RegistrationSection />
                </Suspense>
            </main>
        </div>
    );
}

import React, { Suspense } from 'react';
import PageHeader from '@/components/ui/layout/PageHeader';
import MembershipFormIsland from '@/components/islands/membership/MembershipFormIsland';
import MembershipStatusIsland, { type MembershipUserData } from '@/components/islands/account/MembershipStatusIsland';
import MembershipSkeleton from '@/components/ui/membership/MembershipSkeleton';
import { auth } from '@/server/auth/auth';
import { headers } from 'next/headers';

export const metadata = {
    title: 'Word Lid | Salve Mundi',
    description: 'Beheer je lidmaatschap bij Salve Mundi en krijg toegang tot exclusieve activiteiten.',
};

async function MembershipDynamicContent() {
    const session = await auth.api.getSession({
        headers: await headers()
    });

    const user = session?.user as any;
    const isGuest = !user;
    const baseAmount = 20.00;

    return (
        <>
            <PageHeader
                title={isGuest ? "WORD LID!" : "MIJN LIDMAATSCHAP"}
                backgroundImage=""
                contentPadding="py-20"
                imageFilter="brightness(0.65)"
            />

            <main className="max-w-app mx-auto">
                <div className="flex flex-col sm:flex-row gap-6 px-6 py-8 sm:py-10 md:py-12">
                    <section className={`bg-[var(--bg-card)] dark:border dark:border-white/10 rounded-[2rem] shadow-xl p-6 sm:p-10 ${isGuest ? 'w-full sm:w-1/2' : 'w-full max-w-2xl mx-auto'}`}>
                        <h1 className="text-4xl font-black text-theme-purple dark:text-purple-400 mb-8 tracking-tight">
                            {isGuest ? 'INSCHRIJVEN' : (user?.membership_status === 'active' ? 'STATUS' : 'VERLENGEN')}
                        </h1>

                        {isGuest ? (
                            <MembershipFormIsland baseAmount={baseAmount} />
                        ) : (
                            <MembershipStatusIsland user={user as MembershipUserData} baseAmount={baseAmount} />
                        )}
                    </section>

                    {isGuest && (
                        <aside className="w-full sm:w-1/2 flex flex-col gap-6">
                            <div className="w-full text-center bg-[var(--bg-card)] dark:border dark:border-white/10 rounded-[2rem] p-8 shadow-lg">
                                <h2 className="text-3xl font-black text-theme-purple dark:text-purple-400 mb-4 tracking-tight">
                                    WAAROM LID WORDEN?
                                </h2>
                                <p className="text-lg opacity-80 leading-relaxed font-medium">
                                    Als lid van Salve Mundi krijg je toegang tot exclusieve
                                    activiteiten, workshops, borrels en nog veel meer! Word vandaag
                                    nog lid en ontdek de wereld van ICT samen met ons.
                                </p>
                            </div>
                        </aside>
                    )}
                </div>
            </main>
        </>
    );
}

export default function MembershipPage() {
    return (
        <Suspense fallback={<MembershipSkeleton />}>
            <MembershipDynamicContent />
        </Suspense>
    );
}

