                        <Loader2 className="h-10 w-10 animate-spin text-[var(--theme-purple)] mb-4" />
                        <p className="text-[10px] font-black uppercase tracking-[0.3em] text-[var(--text-muted)] animate-pulse">Kaartgegevens initialiseren...</p>
                    </div>
                }>
                    <StickerMapIsland initialStickers={stickers} user={session?.user || null} />
                </Suspense>
            </div>
        </main>
    );
}

import { Suspense } from 'react';
import { headers } from 'next/headers';
import { getUserEventSignups } from '@/server/actions/profiel.actions';
import { checkAdminAccess } from '@/server/actions/admin.actions';

import { ProfielSkeleton } from '@/components/ui/account/ProfielSkeleton';
import { ProfielIsland } from '@/components/islands/account/ProfielIsland';

export default function ProfielPage() {
    return (
        <div className="min-h-screen bg-[var(--bg-main)]">
            <header className="bg-[var(--bg-soft)] py-12">
                <div className="mx-auto max-w-app px-4 text-center">
                    <h1 className="text-4xl font-extrabold text-[var(--text-main)]">Mijn Account</h1>
                    <p className="text-lg sm:text-xl text-[var(--color-purple-600)] dark:text-white max-w-3xl mt-4 font-medium mx-auto">
                        Beheer je gegevens, lidmaatschap en inschrijvingen.
                    </p>
                </div>
            </header>

            <main className="mx-auto max-w-app px-4 py-12">
                <Suspense fallback={<ProfielSkeleton />}>
                    <ProfielFetcher />
                </Suspense>
            </main>
        </div>
    );
}

async function ProfielFetcher() {
    const { user, impersonation } = await checkAdminAccess();

    // Fallback if somehow not authenticated (though proxy handles this)
    if (!user) return null;

    // Fetch user event signups (respecting current identity)
    const signups = await getUserEventSignups(user.id);

    return (
        <ProfielIsland 
            initialSignups={signups} 
            user={user as any} 
        />
    );
}

import { Suspense } from 'react';
import PageHeader from '@/components/ui/layout/PageHeader';
import { auth } from '@/server/auth/auth';
import { headers } from 'next/headers';
import { ShieldAlert, ArrowLeft } from 'lucide-react';
import Link from 'next/link';
import { notFound } from 'next/navigation';
import ActiviteitAanmeldingenIsland from '@/components/islands/admin/activities/ActiviteitAanmeldingenIsland';
import AanmeldingenListSkeleton from '@/components/ui/admin/activities/AanmeldingenListSkeleton';
import { getSystemDirectus } from '@/lib/directus';
import { readItem, readItems } from '@directus/sdk';

export default async function AanmeldingenPage({ params }: { params: Promise<{ id: string }> }) {
    const resolvedParams = await params;

    return (
        <div className="min-h-screen bg-slate-50 dark:bg-slate-900">
            <Suspense fallback={<AanmeldingenListSkeleton />}>
                <SignupsDataLoader id={resolvedParams.id} />
            </Suspense>
        </div>
    );
}

async function SignupsDataLoader({ id }: { id: string }) {
    const session = await auth.api.getSession({
        headers: await headers()
    });
    if (!session || !session.user) return <UnauthorizedAccess />;

    const user = session.user as any;
    const memberships = user.committees || [];
    const hasPriv = memberships.some((c: any) => {
        const name = (c?.name || '').toString().toLowerCase();
        return name.includes('bestuur') || name.includes('ict') || name.includes('kandi');
    });

    // Fetch Event
    let event;
    try {
        event = await getSystemDirectus().request(
            readItem<any, any, any>('events', id, {
                fields: ['id', 'name', 'price_members', 'committee_id']
            })
        );
    } catch (e) {
        return notFound();
    }

    if (!event) return notFound();

    // RBAC
    let hasAccess = hasPriv;
    if (!hasAccess && event.committee_id) {
        const isMember = memberships.some((c: any) => String(c.id) === String(event.committee_id));
        if (isMember) hasAccess = true;
    }

    if (!hasAccess) return <UnauthorizedAccess specific={true} />;

    // Fetch Signups
    let signups: any[] = [];
    try {
        signups = await getSystemDirectus().request(
            readItems<any, any, any>('event_signups', {
                filter: {
                    event_id: { _eq: id }
                },
                fields: [
                    'id', 
                    'participant_name', 
                    'participant_email', 
                    'participant_phone', 
                    'payment_status', 
                    'checked_in',
                    'checked_in_at'
                ],
                sort: ['-id'], // Use id for sorting instead of date_created if needed
                limit: -1
            })
        );
    } catch (e: any) {
        console.error("Failed to fetch signups:", e.message, e?.errors || e);
    }

    return (
        <>
            <PageHeader
                title={event.name || 'Aanmeldingen'}
                description="Bekijk alle aanmeldingen voor deze activiteit"
                backLink="/beheer/activiteiten"
                className="mb-0"
                contentPadding="pt-0 pb-2 sm:pt-0 sm:pb-2"
                titleClassName="text-sm sm:text-base md:text-xl"
            />
            <ActiviteitAanmeldingenIsland event={event} initialSignups={signups} />
        </>
    );
}

function UnauthorizedAccess({ specific = false }: { specific?: boolean }) {
    return (
        <>
            <PageHeader title="Geen Toegang" description="Onvoldoende rechten" />
            <div className="container mx-auto px-4 py-12 max-w-2xl">
                <div className="bg-white dark:bg-slate-800 rounded-3xl shadow-xl p-8 text-center ring-1 ring-slate-200 dark:ring-slate-700">
                    <div className="mb-6 flex justify-center">
                        <div className="rounded-full bg-red-100 dark:bg-red-900/30 p-6">
                            <ShieldAlert className="h-16 w-16 text-red-600 dark:text-red-400" />
                        </div>
                    </div>
                    <h1 className="text-3xl font-bold text-slate-900 dark:text-white mb-4">Toegang Geweigerd</h1>
                    <p className="text-lg text-slate-500 dark:text-slate-400 mb-8">
                        {specific 
                            ? "Je hebt geen rechten om deze aanmeldingen te bekijken."
                            : "Je hebt geen rechten om activiteiten te beheren."}
                    </p>
                    <div className="flex justify-center">
                        <Link href="/beheer/activiteiten" className="inline-flex items-center justify-center gap-2 rounded-full bg-slate-100 text-slate-700 dark:bg-slate-700 dark:text-slate-200 px-8 py-3 font-semibold hover:bg-slate-200 dark:hover:bg-slate-600 transition-all">
                            <ArrowLeft className="h-5 w-5" /> Terug
                        </Link>
                    </div>
                </div>
            </div>
        </>
    );
}

import { Suspense } from 'react';
import PageHeader from '@/components/ui/layout/PageHeader';
import ActiviteitBewerkenIsland from '@/components/islands/admin/activities/ActiviteitBewerkenIsland';
import ActiviteitBewerkenSkeleton from '@/components/ui/admin/activities/ActiviteitBewerkenSkeleton';
import { auth } from '@/server/auth/auth';
import { headers } from 'next/headers';
import { ShieldAlert, ArrowLeft } from 'lucide-react';
import Link from 'next/link';
import { notFound } from 'next/navigation';
import { getSystemDirectus } from '@/lib/directus';
import { readItems } from '@directus/sdk';

export default async function BewerkenActiviteitPage({ params }: { params: Promise<{ id: string }> }) {
    const resolvedParams = await params;

    return (
        <div className="min-h-screen bg-slate-50 dark:bg-slate-900">
            <PageHeader
                title="Activiteit Bewerken"
                description="Wijzig de gegevens van deze activiteit"
                backLink="/beheer/activiteiten"
                className="mb-0"
                contentPadding="pt-0 pb-2 sm:pt-0 sm:pb-2"
                titleClassName="text-sm sm:text-base md:text-xl"
            />
            <Suspense fallback={<ActiviteitBewerkenSkeleton />}>
                <EditFormLoader id={resolvedParams.id} />
            </Suspense>
        </div>
    );
}

async function EditFormLoader({ id }: { id: string }) {
    const session = await auth.api.getSession({
        headers: await headers()
    });
    if (!session || !session.user) return <UnauthorizedAccess />;

    const user = session.user as any;
    const memberships = user.committees || [];

    try {
        // Fetch Event via SDK
        const event = await getSystemDirectus().request(
            readItems<any, any, any>('events', {
                fields: [
                    'id', 'name', 'description', 'location', 'event_date', 'event_date_end', 
                    'max_sign_ups', 'price_members', 'price_non_members', 'only_members', 
                    'registration_deadline', 'contact', 'image', 'committee_id', 'status', 
                    'publish_date', 'event_time', 'event_time_end'
                ],
                filter: { id: { _eq: id } },
                limit: 1
            })
        );

        if (!event || event.length === 0) return notFound();
        const eventData = event[0];

        // Fetch Committees for the dropdown
        const allCommittees = await getSystemDirectus().request(
            readItems<any, any, any>('committees', {
                fields: ['id', 'name'],
                filter: { is_visible: { _eq: true } },
                limit: -1
            })
        );

        const cleanedCommittees = allCommittees.map((c: any) => ({
            id: c.id,
            name: c.name.replace(/\|\|.*salvemundi.*$/i, '').replace(/\|+$/g, '').trim()
        }));

        // RBAC
        const isPowerful = memberships.some((c: any) => {
            const name = (c?.name || '').toString().toLowerCase();
            return name.includes('bestuur') || name.includes('ict') || name.includes('kandi');
        });

        let hasAccess = isPowerful;
        if (!hasAccess) {
            hasAccess = eventData.committee_id ? memberships.some((c: any) => String(c.id) === String(eventData.committee_id)) : false;
        }

        if (!hasAccess) return <UnauthorizedAccess specific={true} />;

        // Filter allowed committees for the dropdown (only if not powerful, otherwise show all)
        const allowedCommitteesForDropdown = isPowerful 
            ? cleanedCommittees 
            : cleanedCommittees.filter((c: any) => memberships.some((m: any) => String(m.id) === String(c.id)));

        return <ActiviteitBewerkenIsland event={eventData as any} committees={allowedCommitteesForDropdown as any} />;
    } catch (e) {
        console.error("Error loading edit form:", e);
        return <div className="p-8 text-center text-red-500">Er is een fout opgetreden bij het laden van de gegevens.</div>;
    }
}

