                                            <span className="flex items-center gap-1.5 px-3 py-1 bg-green-500/10 text-green-500 text-[9px] font-black uppercase rounded-full ring-1 ring-green-500/20">
                                                <CheckCircle className="h-3 w-3" /> Check-in ✅
