                </button>
            </div>
        </form>
    );
}

'use client';

import { useState } from 'react';
import { 
    Search, 
    Download, 
    AlertCircle, 
    Trash2, 
    Edit, 
    Mail, 
    ExternalLink 
} from 'lucide-react';
import { format } from 'date-fns';
import { nl } from 'date-fns/locale';
import * as XLSX from 'xlsx';

interface SignupListProps {
    signups: any[];
    eventId: number;
    eventName: string;
    onDelete: (id: number) => void;
    onEdit: (id: number) => void;
}

export default function SignupList({
    signups,
    eventId,
    eventName,
    onDelete,
    onEdit
}: SignupListProps) {
    const [searchQuery, setSearchQuery] = useState('');
    const [showAll, setShowAll] = useState(false);

    const filteredSignups = signups.filter(s => {
        const matchesSearch = 
            s.name?.toLowerCase().includes(searchQuery.toLowerCase()) ||
            s.email?.toLowerCase().includes(searchQuery.toLowerCase()) ||
            s.association?.toLowerCase().includes(searchQuery.toLowerCase());

        const matchesStatus = showAll || s.payment_status === 'paid';

        return matchesSearch && matchesStatus;
    });

    const exportToExcel = () => {
        const rows: any[] = [];
        filteredSignups.forEach(signup => {
            const participants = signup.participants || [];
            if (participants.length > 0) {
                participants.forEach((p: any) => {
                    rows.push({
                        'Naam': `${p.name} ${p.initial}.`,
                        'Vereniging': signup.association || '-',
                        'Groep': signup.email
                    });
                });
            } else {
                for (let i = 0; i < signup.amount_tickets; i++) {
                    rows.push({
                        'Naam': i === 0 ? signup.name : '-',
                        'Vereniging': signup.association || '-',
                        'Groep': signup.email
                    });
                }
            }
        });

        const ws = XLSX.utils.json_to_sheet(rows);
        const wb = XLSX.utils.book_new();
        XLSX.utils.book_append_sheet(wb, ws, 'Aanmeldingen');
        ws['!cols'] = [{ wch: 30 }, { wch: 20 }, { wch: 30 }];

        const filename = `kroegentocht-${eventName.replace(/[^a-z0-9]/gi, '-').toLowerCase()}-${format(new Date(), 'yyyy-MM-dd')}.xlsx`;
        XLSX.writeFile(wb, filename);
    };

    return (
        <div className="space-y-6">
            {/* Filters & Actions */}
            <div className="bg-[var(--bg-card)] rounded-[var(--radius-2xl)] shadow-[var(--shadow-card)] ring-1 ring-[var(--border-color)]/30 p-6">
                <div className="flex flex-col lg:flex-row gap-6 justify-between items-stretch">
                    <div className="relative flex-1 group">
                        <Search className="absolute left-4 top-1/2 -translate-y-1/2 h-5 w-5 text-[var(--text-muted)] group-focus-within:text-[var(--theme-purple)] transition-colors" />
                        <input
                            type="text"
                            placeholder="Zoek op naam, email of vereniging..."
                            value={searchQuery}
                            onChange={(e) => setSearchQuery(e.target.value)}
                            autoComplete="off"
                            spellCheck={false}
                            suppressHydrationWarning={true}
                            className="w-full pl-12 pr-4 py-3 bg-[var(--bg-main)]/50 border-2 border-[var(--border-color)]/50 rounded-[var(--radius-xl)] focus:ring-4 focus:ring-[var(--theme-purple)]/10 focus:border-[var(--theme-purple)] transition-all font-medium text-sm text-[var(--text-main)]"
                        />
                    </div>

                    <div className="flex flex-wrap gap-3">
                        <button
                            onClick={() => setShowAll(!showAll)}
                            className={`flex items-center gap-2 px-6 py-3 rounded-[var(--radius-xl)] font-black text-xs uppercase tracking-widest transition-all active:scale-95 border-2 ${
                                showAll
                                ? 'bg-amber-500/10 border-amber-500 text-amber-500'
                                : 'bg-[var(--bg-card)] border-[var(--border-color)] text-[var(--text-light)] hover:border-[var(--theme-purple)]/30'
                            }`}
                        >
                            <AlertCircle className="h-4 w-4" />
                            {showAll ? 'Verberg onbetaald' : 'Toon alles'}
                        </button>

                        <button
                            onClick={exportToExcel}
                            disabled={filteredSignups.length === 0}
                            className="flex items-center gap-2 px-6 py-3 bg-green-600 hover:bg-green-700 text-white font-black text-xs uppercase tracking-widest rounded-[var(--radius-xl)] shadow-lg shadow-green-600/20 transition-all active:scale-95 disabled:opacity-50"
                        >
                            <Download className="h-4 w-4" />
                            Export Excel
                        </button>
                    </div>
                </div>
            </div>

            {/* Table */}
            <div className="bg-[var(--bg-card)] rounded-[var(--radius-2xl)] shadow-[var(--shadow-card)] ring-1 ring-[var(--border-color)]/30 overflow-hidden">
                <div className="overflow-x-auto">
                    <table className="w-full text-left">
                        <thead>
                            <tr className="bg-[var(--bg-main)]/50 border-b border-[var(--border-color)]/30">
                                <th className="px-6 py-4 text-[10px] font-black uppercase tracking-widest text-[var(--text-muted)]">Groep / Deelnemers</th>
                                <th className="px-6 py-4 text-center text-[10px] font-black uppercase tracking-widest text-[var(--text-muted)]">Tickets</th>
                                <th className="px-6 py-4 text-[10px] font-black uppercase tracking-widest text-[var(--text-muted)] hidden md:table-cell">Status</th>
                                <th className="px-6 py-4 text-[10px] font-black uppercase tracking-widest text-[var(--text-muted)] hidden lg:table-cell">Vereniging</th>
                                <th className="px-6 py-4 text-right text-[10px] font-black uppercase tracking-widest text-[var(--text-muted)]">Acties</th>
                            </tr>
                        </thead>
                        <tbody className="divide-y divide-[var(--border-color)]/20">
                            {filteredSignups.length === 0 ? (
                                <tr>
                                    <td colSpan={5} className="px-6 py-16 text-center text-[var(--text-muted)] italic font-medium">
                                        Geen aanmeldingen gevonden voor dit filter.
                                    </td>
                                </tr>
                            ) : (
                                filteredSignups.map((signup) => (
                                    <tr key={signup.id} className="hover:bg-[var(--bg-main)]/30 transition-colors group">
                                        <td className="px-6 py-4">
                                            <div className="flex flex-col gap-1">
                                                <div className="flex items-center gap-2">
                                                    <span className="font-bold text-[var(--text-main)] group-hover:text-[var(--theme-purple)] transition-colors">{signup.name}</span>
                                                    <a href={`mailto:${signup.email}`} className="text-[var(--text-light)] hover:text-[var(--theme-purple)]">
                                                        <Mail className="h-3 w-3" />
                                                    </a>
                                                </div>
                                                <div className="text-[10px] font-mono text-[var(--text-muted)] uppercase">{signup.email}</div>
                                                {signup.participants?.length > 0 && (
                                                    <div className="mt-2 space-y-1 pl-3 border-l-2 border-[var(--theme-purple)]/20">
                                                        {signup.participants.map((p: any, i: number) => (
                                                            <div key={i} className="text-[11px] text-[var(--text-light)] font-medium">
                                                                • {p.name} {p.initial}.
                                                            </div>
                                                        ))}
                                                    </div>
                                                )}
                                            </div>
                                        </td>
                                        <td className="px-6 py-4 text-center">
                                            <span className="inline-flex items-center justify-center w-8 h-8 rounded-full bg-[var(--theme-purple)]/10 text-[var(--theme-purple)] text-xs font-black ring-1 ring-[var(--theme-purple)]/20">
                                                {signup.amount_tickets}
                                            </span>
                                        </td>
                                        <td className="px-6 py-4 hidden md:table-cell">
                                            <span className={`px-3 py-1 rounded-full text-[9px] font-black uppercase tracking-widest ring-1 ${
                                                signup.payment_status === 'paid'
                                                ? 'bg-green-500/10 text-green-500 ring-green-500/20'
                                                : signup.payment_status === 'open'
                                                ? 'bg-amber-500/10 text-amber-500 ring-amber-500/20'
                                                : 'bg-red-500/10 text-red-500 ring-red-500/20'
                                            }`}>
                                                {signup.payment_status === 'paid' ? 'Betaald' : signup.payment_status === 'open' ? 'Open' : signup.payment_status}
                                            </span>
                                        </td>
                                        <td className="px-6 py-4 text-xs font-bold text-[var(--text-subtle)] hidden lg:table-cell">
                                            {signup.association || '-'}
                                        </td>
                                        <td className="px-6 py-4 text-right">
                                            <div className="flex justify-end gap-1">
                                                <button 
                                                    onClick={() => onEdit(signup.id)}
                                                    className="p-2 rounded-lg hover:bg-[var(--theme-purple)]/10 text-[var(--text-muted)] hover:text-[var(--theme-purple)] transition-all active:scale-90"
                                                >
                                                    <Edit className="h-4 w-4" />
                                                </button>
                                                <button 
                                                    onClick={() => onDelete(signup.id)}
                                                    className="p-2 rounded-lg hover:bg-red-500/10 text-[var(--text-muted)] hover:text-red-500 transition-all active:scale-90"
                                                >
                                                    <Trash2 className="h-4 w-4" />
                                                </button>
                                            </div>
                                        </td>
                                    </tr>
                                ))
                            )}
                        </tbody>
                    </table>
                </div>
            </div>
        </div>
    );
}

'use client';

import { Check, EyeOff } from 'lucide-react';

interface GroupSelectorProps {
    pageKey: string;
    selectedTokens: string[];
    allCommittees: any[];
    showAllGroups: boolean;
    onToggleToken: (pageKey: string, token: string) => void;
}

export default function GroupSelector({
    pageKey,
    selectedTokens,
    allCommittees,
    showAllGroups,
    onToggleToken
}: GroupSelectorProps) {
    const visibleGroups = allCommittees.filter(c => c.is_visible !== false);
    const hiddenGroups = allCommittees.filter(c => c.is_visible === false);
    const displayedGroups = showAllGroups ? allCommittees : visibleGroups;

    return (
        <div className="space-y-4">
            <div className="flex items-center justify-between mb-4">
                <p className="text-[10px] font-bold text-[var(--text-muted)] uppercase tracking-widest">Beschikbare Groepen</p>
                {!showAllGroups && hiddenGroups.length > 0 && (
                    <p className="text-[9px] text-[var(--text-light)] italic">
                        (+ {hiddenGroups.length} verborgen groepen)
                    </p>
                )}
            </div>

            <div className="grid grid-cols-2 sm:grid-cols-3 md:grid-cols-4 lg:grid-cols-5 gap-2.5">
                {displayedGroups.map(committee => {
                    const isSelected = selectedTokens.includes(committee.token);
                    const isHidden = !committee.is_visible;

                    return (
                        <button
                            key={committee.id}
                            onClick={() => onToggleToken(pageKey, committee.token)}
                            className={`flex items-center justify-between px-3 py-2 rounded-xl border text-[11px] font-bold transition-all active:scale-95 text-left ${
                                isSelected
                                ? 'bg-[var(--theme-purple)]/10 border-[var(--theme-purple)] text-[var(--theme-purple)] shadow-sm'
                                : isHidden
                                ? 'bg-[var(--bg-main)]/50 border-dashed border-[var(--border-color)]/50 text-[var(--text-light)]/50'
                                : 'bg-[var(--bg-card)] border-[var(--border-color)] text-[var(--text-subtle)] hover:border-[var(--theme-purple)]/50 hover:text-[var(--text-main)]'
                            }`}
                        >
                            <span className="truncate pr-1" title={committee.name}>{committee.name}</span>
                            <div className="flex items-center gap-1 shrink-0">
                                {isHidden && <EyeOff className="h-2.5 w-2.5 opacity-50" />}
                                {isSelected && <Check className="h-3 w-3" />}
                            </div>
                        </button>
                    );
                })}
            </div>

            {displayedGroups.length === 0 && (
                <p className="text-center py-4 text-xs text-[var(--text-muted)] italic">
                    Geen groepen gevonden om weer te geven.
                </p>
            )}
        </div>
    );
}

'use client';

import { Shield, Save, Loader2, Check, X } from 'lucide-react';
import GroupSelector from './GroupSelector';

interface PermissionCardProps {
    id: string;
    label: string;
    description: string;
    pageKey: string;
    currentTokens: string[];
    allCommittees: any[];
    showAllGroups: boolean;
    isSaving: boolean;
    saveStatus: 'success' | 'error' | null;
    onToggleToken: (pageKey: string, token: string) => void;
    onSave: (pageKey: string) => void;
}

export default function PermissionCard({
    label,
    description,
    pageKey,
    currentTokens,
    allCommittees,
    showAllGroups,
    isSaving,
    saveStatus,
    onToggleToken,
    onSave
}: PermissionCardProps) {
    return (
        <div className="bg-[var(--bg-card)] rounded-[var(--radius-2xl)] shadow-[var(--shadow-card)] ring-1 ring-[var(--border-color)] overflow-hidden transition-all hover:ring-[var(--theme-purple)]/30">
            <div className="p-6 border-b border-[var(--border-color)]/30 bg-[var(--bg-main)]/30 flex flex-col md:flex-row md:items-center justify-between gap-4">
                <div>
                    <h2 className="text-xl font-bold text-[var(--text-main)] flex items-center gap-2">
                        <Shield className="h-5 w-5 text-[var(--theme-purple)]" />
                        {label}
                    </h2>
                    <p className="text-sm text-[var(--text-subtle)] mt-1">{description}</p>
                </div>
                <button
                    onClick={() => onSave(pageKey)}
                    disabled={isSaving}
                    className={`flex items-center gap-2 px-6 py-2.5 rounded-[var(--radius-xl)] font-bold transition shadow-lg ${
                        saveStatus === 'success'
                        ? 'bg-green-500 text-white shadow-green-500/20'
                        : saveStatus === 'error'
                        ? 'bg-red-500 text-white shadow-red-500/20'
                        : 'bg-[var(--theme-purple)] text-white shadow-[var(--theme-purple)]/20 hover:opacity-90'
                    } disabled:opacity-50 active:scale-95`}
                >
                    {isSaving ? (
                        <Loader2 className="h-4 w-4 animate-spin" />
                    ) : saveStatus === 'success' ? (
                        <Check className="h-4 w-4" />
                    ) : saveStatus === 'error' ? (
                        <X className="h-4 w-4" />
                    ) : (
                        <Save className="h-4 w-4" />
                    )}
                    {isSaving ? 'Opslaan...' : saveStatus === 'success' ? 'Opgeslagen!' : 'Opslaan'}
                </button>
            </div>

            <div className="p-6">
                <p className="text-[10px] font-bold text-[var(--text-muted)] uppercase tracking-widest mb-4">Geselecteerde Groepen</p>

                <div className="flex flex-wrap gap-2 mb-8 min-h-[40px]">
                    {currentTokens.length === 0 ? (
                        <p className="text-sm text-[var(--text-light)] italic px-1">Geen groepen geselecteerd. Standaard code-permissies worden gebruikt.</p>
                    ) : (
                        currentTokens.map(token => (
                            <span key={token} className="flex items-center gap-1.5 px-3 py-1 bg-[var(--theme-purple)]/10 text-[var(--theme-purple)] rounded-full text-xs font-bold ring-1 ring-[var(--theme-purple)]/20 animate-in zoom-in-95">
                                {token}
                                <button 
                                    onClick={() => onToggleToken(pageKey, token)} 
                                    className="hover:text-[var(--text-main)] transition-colors"
                                >
                                    <X className="h-3 w-3" />
                                </button>
                            </span>
                        ))
                    )}
                </div>

                <div className="border-t border-[var(--border-color)]/30 pt-6">
                    <GroupSelector 
                        pageKey={pageKey}
                        selectedTokens={currentTokens}
                        allCommittees={allCommittees}
                        showAllGroups={showAllGroups}
                        onToggleToken={onToggleToken}
                    />
                </div>
            </div>
        </div>
    );
}

'use client';

import { 
    MapPin, 
    Globe, 
    Award, 
    TrendingUp 
} from 'lucide-react';

interface StickerStatsProps {
    stickers: any[];
}

export default function StickerStats({ stickers }: StickerStatsProps) {
    const total = stickers.length;

    const countries = new Set(stickers.map(s => s.country?.toLowerCase()).filter(Boolean)).size;
    const cities = new Set(stickers.map(s => s.city?.toLowerCase()).filter(Boolean)).size;

    // Top country calculation
    const countryCounts: Record<string, number> = {};
    stickers.forEach(s => {
        if (s.country) {
            countryCounts[s.country] = (countryCounts[s.country] || 0) + 1;
        }
    });

    const topCountry = Object.entries(countryCounts)
        .sort((a, b) => b[1] - a[1])[0] || ['N/A', 0];

    const stats = [
        { 
            label: 'Totaal Stickers', 
            value: total, 
            icon: MapPin, 
            color: 'text-purple-500', 
            bg: 'bg-purple-500/10' 
        },
        { 
            label: 'Landen', 
            value: countries, 
            icon: Globe, 
            color: 'text-blue-500', 
            bg: 'bg-blue-500/10' 
        },
        { 
            label: 'Steden', 
            value: cities, 
            icon: Award, 
            color: 'text-green-500', 
            bg: 'bg-green-500/10' 
        },
        { 
            label: 'Top Land', 
            value: topCountry[0], 
            icon: TrendingUp, 
            color: 'text-amber-500', 
            bg: 'bg-amber-500/10',
            subtitle: `${topCountry[1]} stickers`
        }
    ];

    return (
        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-6 mb-8">
            {stats.map((stat, i) => (
                <div key={i} className="bg-[var(--bg-card)] rounded-[var(--radius-2xl)] p-6 shadow-[var(--shadow-card)] ring-1 ring-[var(--border-color)]/30 hover:ring-[var(--theme-purple)]/30 transition-all group">
                    <div className="flex items-center justify-between mb-4">
                        <div className={`p-3 rounded-[var(--radius-xl)] ${stat.bg} ${stat.color} group-hover:scale-110 transition-transform`}>
                            <stat.icon className="h-6 w-6" />
                        </div>
                        {stat.subtitle && (
                            <span className="text-[10px] font-black uppercase tracking-widest text-[var(--text-muted)]">
                                {stat.subtitle}
                            </span>
                        )}
                    </div>
                    <div>
                        <p className="text-xs font-bold text-[var(--text-muted)] uppercase tracking-widest mb-1">{stat.label}</p>
                        <p className="text-3xl font-black text-[var(--text-main)] tracking-tighter transition-all group-hover:text-[var(--theme-purple)]">
                            {stat.value}
                        </p>
                    </div>
                </div>
            ))}
        </div>
    );
}

