};

'use client';

import Image from 'next/image';
import { useAuth, useAuthActions } from '@/features/auth/providers/auth-provider';
import { Calendar } from 'lucide-react';

interface ActiviteitCardProps {
    id: number | string;
    description: string;
    description_logged_in?: string;
    image?: string;
    date?: string;
    endDate?: string;
    startTime?: string | null;
    endTime?: string | null;
    location?: string | null;
    title: string;
    price?: number;
    isPast?: boolean;
    onSignup?: (data: { title: string; date?: string; description: string; price: number }) => void;
    onShowDetails?: () => void;
    requiresLogin?: boolean;
    isSignedUp?: boolean;
    variant?: 'grid' | 'list';
    committeeName?: string;
    registrationDeadline?: string;
    contact?: string;
    onlyMembers?: boolean;
}

const ActiviteitCard: React.FC<ActiviteitCardProps> = ({
    description,
    image,
    title,
    date,
    endDate,
    startTime,
    endTime,
    location,
    price,
    isPast = false,
    onSignup,
    onShowDetails,
    requiresLogin = false,
    isSignedUp = false,
    variant = 'grid',
    committeeName,
    contact,
    registrationDeadline,
    onlyMembers = false,
}) => {
    const { isAuthenticated, user } = useAuth();
    const { login: loginWithMicrosoft } = useAuthActions();

    const alreadySignedUp = Boolean(isSignedUp);
    const isListVariant = variant === 'list';

    const isDeadlinePassed = registrationDeadline ? new Date(registrationDeadline) < new Date() : false;
    const cannotSignUp = alreadySignedUp || isDeadlinePassed;

    const handleSignupClick = (e: React.MouseEvent) => {
        e.stopPropagation();

        if (onlyMembers && (user as any)?.membership_status !== 'active') {
            if (!isAuthenticated) {
                const returnTo = window.location.pathname + window.location.search;
                localStorage.setItem('auth_return_to', returnTo);
                loginWithMicrosoft();
            } else {
                alert('Deze activiteit is alleen voor leden.');
            }
            return;
        }

        if (requiresLogin && !isAuthenticated) {
            const returnTo = window.location.pathname + window.location.search;
            localStorage.setItem('auth_return_to', returnTo);
            loginWithMicrosoft();
            return;
        }

        onSignup?.({ title, date, description, price: price || 0 });
    };

    const safePrice = (Number(price) || 0).toFixed(2);

    const cleanCommitteeName = (name?: string) => {
        if (!name) return 'Algemene Activiteit';
        return name.replace(/\s*(\|\||[-–—])\s*SALVE MUNDI\s*$/gi, '').trim() || name;
    };

    const committeeLabel = cleanCommitteeName(committeeName);

    const formatDate = (value?: string, endValue?: string) => {
        if (!value) return 'Datum volgt';
        const parsed = new Date(value);
        if (Number.isNaN(parsed.getTime())) {
            return value;
        }

        const options: Intl.DateTimeFormatOptions = { day: 'numeric', month: 'long', year: 'numeric' };
        const startFormatted = parsed.toLocaleDateString('nl-NL', options);

        if (endValue && endValue !== value) {
            const endParsed = new Date(endValue);
            if (!Number.isNaN(endParsed.getTime())) {
                const endFormatted = endParsed.toLocaleDateString('nl-NL', options);
                return `${startFormatted} t/m ${endFormatted}`;
            }
        }

        return startFormatted;
    };

    const formatTime = (time?: string | null) => {
        if (!time) return null;
        const parts = time.split(':');
        if (parts.length >= 2) return `${parts[0]}:${parts[1]}`;
        return time;
    };

    const start = formatTime(startTime);
    const end = formatTime(endTime);
    const timeRange = start ? (end ? `${start} - ${end}` : start) : null;

    if (isListVariant) {
        return (
            <div
                onClick={onShowDetails}
                className={`group relative z-0 overflow-visible w-full rounded-2xl bg-[var(--bg-card)] dark:border dark:border-[var(--color-white)]/10 p-4 shadow-sm transition-all cursor-pointer hover:shadow-md hover:-translate-y-1 group-hover:z-10 ${isPast ? 'opacity-60 filter grayscale' : ''}`}
            >
                <span className="absolute -top-5 -right-5 h-20 w-20 rounded-full bg-[var(--theme-purple)]/20 transition-transform duration-300 group-hover:scale-110 pointer-events-none" />
                <div className="flex flex-col md:flex-row md:items-center gap-4 md:gap-6">
                    <div className="flex-1 min-w-[180px]">
                        <p className="text-xs uppercase tracking-wider text-[var(--theme-purple)]/60 font-semibold">
                            {committeeLabel}
                        </p>
                        <h3 className="text-lg font-bold text-[var(--theme-purple)]/80 leading-snug">{title}</h3>
                        {contact && (
                            <p className="text-sm text-[var(--text-muted)] mt-1">
                                <span className="font-medium text-[var(--theme-purple)]/80">Contact:</span>{' '}
                                <span className="text-[var(--text-muted)]">{contact}</span>
                            </p>
                        )}
                    </div>

                    <div className="flex flex-row flex-wrap gap-4 text-right text-[var(--theme-purple)]/80 font-semibold">
                        <div className="min-w-[160px] text-right">
                            <p className="text-xs text-[var(--theme-purple)]/60 uppercase tracking-wide">Datum & Tijd</p>
                            <p className="text-base">{formatDate(date, endDate)}{timeRange ? ` — ${timeRange}` : ''}</p>
                            {location && <p className="text-xs text-[var(--text-muted)] mt-1 truncate max-w-[220px]">{location}</p>}
                        </div>
                        <div className="min-w-[90px]">
                            <p className="text-xs text-[var(--theme-purple)]/60 uppercase tracking-wide">Prijs</p>
                            <p className="text-base">€{safePrice}</p>
                        </div>
                    </div>
                </div>

                <div className="flex flex-wrap justify-end gap-2 mt-3">
                    <button
                        onClick={(e) => {
                            e.stopPropagation();
                            onShowDetails?.();
                        }}
                        className="px-4 py-2 text-sm font-semibold rounded-full text-[var(--theme-purple)] hover:bg-[var(--theme-purple)] hover:text-[var(--color-white)] transition"
                    >
                        MEER INFO
                    </button>

                    {!isPast && (
                        <button
                            onClick={handleSignupClick}
                            className={`${cannotSignUp ? 'bg-[var(--color-purple-100)] text-[var(--text-muted)] cursor-not-allowed' : 'bg-[var(--theme-purple)] text-[var(--color-white)] shadow-lg shadow-[var(--theme-purple)]/30 hover:-translate-y-0.5 hover:shadow-xl'} px-4 py-2 text-sm font-semibold rounded-full transition-transform`}
                            disabled={cannotSignUp}
                        >
                            {alreadySignedUp ? 'AL AANGEMELD' : isDeadlinePassed ? 'INSCHRIJVEN GESLOTEN' : 'AANMELDEN'}
                        </button>
                    )}
                </div>
            </div>
        );
    }

    return (
        <div
            onClick={onShowDetails}
            className={`group relative z-0 overflow-visible w-full rounded-[1.75rem] bg-[var(--bg-card)] dark:border dark:border-[var(--color-white)]/10 p-5 shadow-sm transition-all cursor-pointer hover:shadow-md hover:-translate-y-1 group-hover:z-10 ${isPast ? 'opacity-60 filter grayscale' : ''}`}
        >
            <span className="absolute -top-10 -right-10 h-32 w-32 rounded-full bg-[var(--theme-purple)]/10 transition-transform duration-500 group-hover:scale-125 pointer-events-none" />

            <div className="relative z-10 h-44 sm:h-48 mb-5 rounded-2xl overflow-hidden shadow-inner bg-[var(--bg-soft)]">
                {image ? (
                    <Image
                        src={image}
                        alt={title}
                        fill
                        sizes="(max-width: 640px) 100vw, (max-width: 768px) 50vw, 33vw"
                        className="object-cover transition-transform duration-500 group-hover:scale-105"
                        loading="lazy"
                        unoptimized
                        onError={(e) => {
                            const target = e.target as HTMLImageElement;
                            target.style.display = 'none';
                        }}
                    />
                ) : (
                    <div className="w-full h-full flex items-center justify-center bg-[var(--theme-purple)]/5">
                        <Calendar className="h-12 w-12 text-[var(--theme-purple)]/20" />
                    </div>
                )}
                {!isPast && (
                    <div className="absolute top-4 right-4 z-20 flex flex-col gap-2 items-end">
                        <span className="bg-[var(--theme-purple)] text-[var(--color-white)] text-[10px] font-bold px-3 py-1 rounded-full shadow-lg uppercase tracking-wider">
                            {committeeLabel}
                        </span>
                        {onlyMembers && (
                            <span className="bg-[var(--theme-warning)] text-[var(--color-white)] text-[10px] font-bold px-3 py-1 rounded-full shadow-lg uppercase tracking-wider">
                                Leden Alleen
                            </span>
                        )}
                    </div>
                )}
            </div>

            <div className="flex flex-col flex-grow relative z-10 space-y-3">
                <h3 className="text-xl font-bold text-[var(--theme-purple)]/80 leading-snug line-clamp-2">
                    {title}
                </h3>

                <div className="flex flex-col gap-2">
                    <div className="flex items-center gap-2 text-sm text-[var(--theme-purple)]/80 font-semibold">
                        <Calendar className="h-4 w-4" />
                        <span>{formatDate(date, endDate)}</span>
                    </div>
                    {timeRange && (
                        <p className="text-sm text-[var(--text-muted)] ml-6">
                            {timeRange}
                        </p>
                    )}
                </div>

                <p className="text-[var(--text-muted)] text-sm line-clamp-3 leading-relaxed">
                    {description}
                </p>

                <div className="flex items-center justify-between pt-4 mt-auto border-t border-[var(--border-color)]">
                    <div className="flex flex-col">
                        <span className="text-[10px] uppercase font-bold text-[var(--theme-purple)]/50">Prijs</span>
                        <span className="text-lg font-bold text-[var(--theme-purple)]/80">€{safePrice}</span>
                    </div>

                    <div className="flex gap-2">
                        {!isPast && (
                            <button
                                onClick={handleSignupClick}
                                className={`${cannotSignUp ? 'bg-[var(--color-white-mute)] text-[var(--text-muted)] cursor-not-allowed' : 'bg-[var(--theme-purple)] text-[var(--color-white)] shadow-lg shadow-[var(--theme-purple)]/20 hover:scale-105'} p-2 rounded-full transition-all`}
                                disabled={cannotSignUp}
                                title={alreadySignedUp ? 'Al aangemeld' : 'Aanmelden'}
                            >
