'use client';

import React, { useState, useEffect, useTransition } from 'react';
import { useAuth } from '@/features/auth/providers/auth-provider';
import { signupForActivity } from '@/server/actions/activiteit-mutations.actions';
import { PhoneInput } from '@/shared/ui/PhoneInput';
import { Input } from '@/shared/ui/Input';
import { Loader2, CheckCircle2, AlertCircle, CreditCard, Send, Users, Ticket, Info } from 'lucide-react';
import QRDisplay from '@/shared/ui/QRDisplay';

interface EventSignupIslandProps {
    eventId: number;
    price: number;
    eventDate: string;
    description: string;
    isPast: boolean;
    eventName: string;
    initialUser?: any;
    verifiedPaymentStatus?: 'paid' | null;
    initialQrToken?: string;
}

export default function EventSignupIsland({
    eventId,
    price,
    eventDate,
    description,
    isPast,
    eventName,
    initialUser,
    verifiedPaymentStatus,
    initialQrToken
}: EventSignupIslandProps) {
    const { user: clientUser } = useAuth();

    // Use initialUser for SSR-safe initial state, fall back to clientUser after mount
    const user = initialUser || clientUser;

    const [isPending, startTransition] = useTransition();
    const [error, setError] = useState<string | null>(null);
    const [success, setSuccess] = useState<string | null>(verifiedPaymentStatus === 'paid' ? 'Betaling geslaagd! Je bent nu ingeschreven.' : null);
    const [fieldErrors, setFieldErrors] = useState<Record<string, string[]>>({});

    // Status tracking (Legacy alignment)
    const [signupStatus, setSignupStatus] = useState<{
        isSignedUp: boolean;
        paymentStatus?: 'paid' | 'open' | 'failed' | 'canceled';
        qrToken?: string;
    }>({ 
        isSignedUp: verifiedPaymentStatus === 'paid',
        paymentStatus: verifiedPaymentStatus || undefined,
        qrToken: initialQrToken
    });

    const [form, setForm] = useState({
        name: user?.name || (user as any)?.first_name ? `${(user as any).first_name} ${(user as any).last_name || ''}`.trim() : '',
        email: user?.email || '',
        phoneNumber: (user as any)?.phone_number || '',
        website: '', // Honeypot
    });

    const isPaid = price > 0;

    // Sync form with user
    useEffect(() => {
        if (user) {
            const userName = user.name || ((user as any).first_name ? `${(user as any).first_name} ${(user as any).last_name || ''}`.trim() : '');
            const userPhone = (user as any).phone_number || '';

            setForm(prev => ({
                ...prev,
                name: prev.name || userName || '',
                email: prev.email || user.email || '',
                phoneNumber: prev.phoneNumber || userPhone || ''
            }));
        }
    }, [user]);

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        setError(null);
        setFieldErrors({});

        startTransition(async () => {
            const result = await signupForActivity({
                event_id: eventId,
                name: form.name,
                email: form.email,
                phoneNumber: form.phoneNumber,
                website: form.website,
            });

            if (result.success) {
                if (result.checkoutUrl) {
                    window.location.href = result.checkoutUrl;
                } else {
                    setSuccess(result.message || 'Inschrijving geslaagd!');
                    setSignupStatus({ isSignedUp: true, paymentStatus: isPaid ? 'open' : 'paid' });
                }
            } else {
                if (result.errors) {
                    setFieldErrors(result.errors);
                } else {
                    setError(result.error || 'Er is iets misgegaan.');
                }
            }
        });
    };

    // Digital Ticket View (Legacy pattern)
    if (signupStatus.paymentStatus === 'paid') {
        return (
            <div className="h-full flex flex-col justify-center space-y-8 p-8 rounded-[2rem] bg-[var(--bg-card)] border border-[var(--color-success)]/30 shadow-2xl shadow-[var(--color-success)]/10 animate-in zoom-in-95 duration-500">
                <div className="text-center space-y-4">
                    <div className="w-20 h-20 bg-[var(--color-success)]/10 rounded-full flex items-center justify-center mx-auto shadow-inner">
                        <CheckCircle2 className="h-10 w-10 text-[var(--color-success)]" />
                    </div>
                    <h3 className="text-3xl font-black text-[var(--text-main)] leading-tight text-center">🎉 Inschrijving Definitief!</h3>
                    <p className="text-[var(--text-muted)] font-medium text-center">
                        Je bent succesvol ingeschreven voor <span className="text-[var(--theme-purple)] font-bold">{eventName}</span> en je betaling is ontvangen.
                    </p>
                </div>

                <div className="relative group">
                    <div className="absolute -inset-1 bg-gradient-to-r from-[var(--theme-purple)] to-[var(--color-purple-400)] rounded-3xl blur opacity-25 group-hover:opacity-40 transition duration-1000 group-hover:duration-200"></div>
                    <div className="relative bg-white p-6 rounded-2xl border-2 border-dashed border-slate-200 flex flex-col items-center">
                        <QRDisplay qrToken={signupStatus.qrToken || 'PENDING_VERIFICATION'} />
                        <div className="mt-4 flex items-center gap-2 text-[10px] uppercase font-black text-slate-400 tracking-widest">
                            <Ticket className="h-3 w-3" />
                            Toon bij de ingang
                        </div>
                    </div>
                </div>

                <p className="text-[11px] text-center text-[var(--text-muted)] font-bold italic mt-4">
                    Dit ticket is ook per e-mail naar je verzonden.
                </p>
            </div>
        );
    }

    if (isPast) {
        return (
            <div className="h-full flex flex-col justify-center items-center p-12 rounded-[2rem] bg-slate-50/50 border border-dashed border-slate-300 dark:border-white/10 text-center space-y-4">
                <AlertCircle className="h-12 w-12 text-slate-300" />
                <div>
                    <h3 className="text-xl font-black text-slate-400 uppercase tracking-tight">Evenement Afgelopen</h3>
                    <p className="text-sm text-slate-400/80 font-medium max-w-[200px] mx-auto">Helaas kun je je voor deze activiteit niet meer aanmelden.</p>
                </div>
            </div>
        );
    }

    return (
        <div className="h-full flex flex-col p-8 rounded-[2rem] bg-[var(--bg-card)] border border-[var(--border-color)] shadow-2xl shadow-[var(--theme-purple)]/5 group transition-all duration-500 hover:shadow-[var(--theme-purple)]/10">
            <div className="flex justify-between items-start mb-8">
                <div>
                    <h3 className="text-2xl font-black text-[var(--theme-purple)] flex items-center gap-3">
                        <Users className="h-6 w-6" />
                        Inschrijven
                    </h3>
                    <p className="text-[10px] uppercase font-black text-[var(--text-muted)] tracking-[0.2em] mt-1 ml-9">Evenement Tickets</p>
                </div>
                <div className="text-right">
                    <span className="block text-[10px] uppercase font-black text-[var(--text-muted)] tracking-[0.2em] mb-1">Prijs</span>
                    <span className="text-2xl font-black text-[var(--theme-purple)]">€{price.toFixed(2)}</span>
                </div>
            </div>

            <form onSubmit={handleSubmit} className="space-y-6 flex-1 flex flex-col">
                <input
                    type="text"
                    name="website"
                    className="hidden"
                    value={form.website}
                    onChange={(e) => setForm({ ...form, website: e.target.value })}
                    tabIndex={-1}
                    autoComplete="off"
                    suppressHydrationWarning
                />

                <div className="space-y-4 flex-1">
                    <div className="space-y-1.5 focus-within:translate-x-1 transition-transform">
                        <label className="text-[10px] uppercase font-black text-[var(--theme-purple)]/50 ml-3 tracking-widest">Naam *</label>
                        <Input
                            required
                            value={form.name}
                            onChange={(e) => setForm({ ...form, name: e.target.value })}
                            placeholder="Naam Achternaam"
                            className="bg-[var(--bg-soft)] border-none rounded-2xl h-14 px-6 focus:ring-2 focus:ring-[var(--theme-purple)]/20 transition-all font-bold text-[var(--text-main)]"
                        />
                        {fieldErrors.name && <p className="text-[10px] text-red-500 ml-3 font-black italic">{fieldErrors.name[0]}</p>}
                    </div>

                    <div className="space-y-1.5 focus-within:translate-x-1 transition-transform">
                        <label className="text-[10px] uppercase font-black text-[var(--theme-purple)]/50 ml-3 tracking-widest">Email *</label>
                        <Input
                            required
                            type="email"
                            value={form.email}
                            onChange={(e) => setForm({ ...form, email: e.target.value })}
                            placeholder="voorbeeld@mail.com"
                            className="bg-[var(--bg-soft)] border-none rounded-2xl h-14 px-6 focus:ring-2 focus:ring-[var(--theme-purple)]/20 transition-all font-bold text-[var(--text-main)]"
                        />
                        {fieldErrors.email && <p className="text-[10px] text-red-500 ml-3 font-black italic">{fieldErrors.email[0]}</p>}
                    </div>

                    <div className="space-y-1.5 focus-within:translate-x-1 transition-transform">
                        <label className="text-[10px] uppercase font-black text-[var(--theme-purple)]/50 ml-3 tracking-widest">Telefoonnummer *</label>
                        <PhoneInput
                            required
                            value={form.phoneNumber}
                            onChange={(e) => setForm({ ...form, phoneNumber: e.target.value })}
                            className="bg-[var(--bg-soft)] border-none rounded-2xl h-14 px-6 focus:ring-2 focus:ring-[var(--theme-purple)]/20 transition-all font-bold text-[var(--text-main)]"
                        />
                        {fieldErrors.phoneNumber && <p className="text-[10px] text-red-500 ml-3 font-black italic">{fieldErrors.phoneNumber[0]}</p>}
                    </div>
                </div>

                {error && (
                    <div className="p-4 rounded-2xl bg-red-50 border border-red-100 flex items-start gap-3 animate-in fade-in slide-in-from-top-2">
                        <AlertCircle className="h-5 w-5 text-red-500 shrink-0 mt-0.5" />
                        <p className="text-xs text-red-700 font-bold italic">{error}</p>
                    </div>
                )}

                <div className="pt-4 space-y-4">
                    <button
                        type="submit"
                        disabled={isPending}
                        className="w-full relative group h-16 bg-gradient-to-br from-[var(--theme-purple)] via-[var(--color-purple-600)] to-[var(--theme-purple)] bg-[length:200%_auto] hover:bg-[position:right_center] text-white font-black rounded-2xl shadow-xl shadow-[var(--theme-purple)]/20 hover:shadow-2xl hover:shadow-[var(--theme-purple)]/40 hover:-translate-y-1 active:scale-95 transition-all duration-500 disabled:opacity-70 disabled:pointer-events-none"
                    >
                        <div className="flex items-center justify-center gap-3">
                            {isPending ? (
                                <>
                                    <Loader2 className="h-6 w-6 animate-spin" />
                                    <span className="tracking-widest">VERWERKEN...</span>
                                </>
                            ) : (
                                <>
                                    {isPaid ? <CreditCard className="h-6 w-6" /> : <Send className="h-6 w-6" />}
                                    <span className="tracking-widest">AANMELDEN (€{price.toFixed(2).replace('.', ',')})</span>
                                </>
                            )}
                        </div>
                    </button>

                    <div className="flex items-center justify-center gap-2 text-[10px] font-black text-[var(--text-muted)] opacity-50 uppercase tracking-tighter">
                        <Info className="h-3 w-3" />
                        <span>Beveiligde verwerking & Directe bevestiging</span>
                    </div>
                </div>
            </form>
        </div>
    );
}

'use client';

import { useState, useEffect } from 'react';
import Link from 'next/link';
import { CheckCircle2, CreditCard, Loader2, Utensils } from 'lucide-react';
import { createTripSignup, getCurrentUserProfileAction } from '@/server/actions/reis.actions';
import type { ReisTrip, ReisTripSignup } from '@salvemundi/validations';
import { authClient } from '@/lib/auth-client';
import { FormField } from '@/shared/ui/FormField';
import { Input } from '@/shared/ui/Input';
import { PhoneInput } from '@/shared/ui/PhoneInput';

interface ReisFormIslandProps {
    nextTrip: ReisTrip | null;
    userSignup: ReisTripSignup | null;
    canSignUp: boolean;
    registrationStartText: string;
    participantsCount: number;
}

export function ReisFormIsland({ nextTrip, userSignup, canSignUp, registrationStartText }: ReisFormIslandProps) {
    const { data: session } = authClient.useSession(); // Access Better Auth session dynamically on client
    const currentUser = session?.user;

    const [form, setForm] = useState({
        first_name: '',
        last_name: '',
        email: '',
        phone_number: '',
        date_of_birth: '' as string,
        terms_accepted: false,
    });
    const [loading, setLoading] = useState(false);
    const [error, setError] = useState<string | null>(null);


    // Prefill form when Better Auth session is present
    useEffect(() => {
        if (!currentUser) return;

        async function prefill() {
            const profile = await getCurrentUserProfileAction();
            if (profile.success && profile.data) {
                setForm(prev => ({
                    ...prev,
                    last_name: prev.last_name || profile.data.last_name || '',
                    email: prev.email || profile.data.email || '',
                    phone_number: prev.phone_number || profile.data.phone_number || '',
                    date_of_birth: prev.date_of_birth || profile.data.date_of_birth || '',
                }));
            } else {
                // Fallback to basic session data if directus fetch fails
                setForm(prev => ({
                    ...prev,
                    email: prev.email || currentUser?.email || '',
                }));
            }
        }

        prefill();
    }, [currentUser]);

    const getSignupStatusDisplay = (signup: ReisTripSignup) => {
        if (signup.status === 'waitlist') return 'Wachtrij';
        if (signup.status === 'cancelled') return 'Geannuleerd';
        if (signup.status === 'registered') return 'Geregistreerd';
        if (signup.status === 'confirmed') {
            if (signup.full_payment_paid) return 'Geregistreerd (Betaald)';
            if (!signup.deposit_paid) return 'Aanbetaling verwacht';
            return 'Restbetaling verwacht';
        }
        return 'In afwachting';
    };


    const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement>) => {
        const { name, value, type } = e.target as HTMLInputElement;
        if (type === 'checkbox') {
            setForm({ ...form, [name]: (e.target as HTMLInputElement).checked });
        } else {
            setForm({ ...form, [name]: value });
        }
        if (error) setError(null);
    };

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        setError(null);

        if (!form.first_name || !form.last_name || !form.email || !form.phone_number || !form.date_of_birth) {
            setError('Vul alle verplichte velden in.');
            return;
        }

        if (!form.terms_accepted) {
            setError('Je moet de algemene voorwaarden accepteren om door te gaan.');
            return;
        }

        if (!nextTrip) {
            setError('Er is momenteel geen reis beschikbaar.');
            return;
        }

        setLoading(true);
        try {
            const formData = {
                ...form
            };

            const result = await createTripSignup(formData as any, nextTrip.id);
            if (!result.success) {
                setError(result.message || 'Fout bij inschrijven.');
            } else {
                window.scrollTo(0, 0);
                window.location.reload();
            }
        } catch {
            setError('Er is een onverwachte fout opgetreden bij het verzenden.');
        } finally {
            setLoading(false);
        }
    };

    return (
        <section className="w-full lg:w-1/2 bg-[var(--bg-card)] dark:border dark:border-white/10 rounded-2xl sm:rounded-3xl shadow-lg p-5 sm:p-6 md:p-8">
            <h1 className="text-2xl sm:text-3xl font-bold text-theme-purple dark:text-theme-white mb-4 sm:mb-6">
                Inschrijven voor de Reis
            </h1>

            {userSignup ? (
                <div className="bg-gradient-to-br from-theme-purple/5 to-theme-purple/10 rounded-2xl p-6 border border-theme-purple/20">
                    {error && (
                        <div className="bg-red-500/10 text-red-500 border border-red-500/20 px-4 py-3 rounded-xl mb-6 text-sm font-medium">
                            {error}
                        </div>
                    )}
                    <div className="flex items-center gap-4 mb-6">
                        <div className="w-14 h-14 rounded-full bg-theme-purple/20 flex items-center justify-center">
                            <CheckCircle2 className="h-8 w-8 text-theme-purple" />
                        </div>
                        <div>
                            <h3 className="text-xl font-bold text-theme-purple dark:text-theme-white">Jouw Status</h3>
                            <p className="text-theme-text-muted text-sm">Je bent al aangemeld voor deze reis</p>
                        </div>
                    </div>

                    <div className="bg-white/50 dark:bg-white/5 rounded-2xl p-6 border border-theme-purple/10 mb-6">
                        <p className="text-sm font-semibold text-theme-text-muted uppercase tracking-wider mb-2">Huidige status</p>
                        <div className="flex flex-wrap items-center justify-between gap-4">
                            <div>
                                <p className="text-2xl sm:text-3xl font-black text-theme-purple dark:text-theme-white break-words">
                                    {getSignupStatusDisplay(userSignup)}
                                </p>
                                {userSignup.status === 'registered' && (
                                    <p className="text-xs text-theme-text-muted mt-1 italic">
                                        Je aanmelding wordt momenteel beoordeeld door de commissie.
                                    </p>
                                )}
                            </div>
                            <div className="px-3 py-1 bg-theme-purple/10 rounded-full text-xs font-bold text-theme-purple uppercase shrink-0">
                                {userSignup.status}
                            </div>
                        </div>
                    </div>

                    {userSignup.status === 'confirmed' && !userSignup.full_payment_paid && (
                        <div className="mt-4 pt-4 border-t border-theme-purple/20">
                            {(!userSignup.deposit_paid || nextTrip?.allow_final_payments) ? (
                                <Link
                                    href={!userSignup.deposit_paid ? `/reis/aanbetaling/${userSignup.id}` : `/reis/restbetaling/${userSignup.id}`}
                                    className="inline-flex items-center gap-2 px-6 py-2 bg-theme-purple text-white rounded-lg hover:bg-theme-purple-dark transition group"
                                >
                                    <CreditCard className="h-5 w-5 group-hover:scale-110 transition-transform" />
                                    Ga naar betaling
                                </Link>
                            ) : (
                                <p className="text-sm italic text-gray-500">
                                    Restbetaling is momenteel nog niet geopend. Je ontvangt bericht zodra dit mogelijk is.
                                </p>
                            )}
                        </div>
                    )}

                    {userSignup.status === 'confirmed' && userSignup.deposit_paid && !userSignup.full_payment_paid && (
                        <div className="mt-4 pt-4 border-t border-theme-purple/20">
                            <Link
                                href={`/reis/activiteiten/${userSignup.id}`}
                                className="inline-flex items-center gap-2 px-6 py-2 bg-blue-600 text-white rounded-lg hover:bg-blue-700 transition group"
                            >
                                <Utensils className="h-5 w-5 group-hover:scale-110 transition-transform" />
                                Activiteiten aanpassen
                            </Link>
                            <p className="text-xs text-theme-text-muted mt-2 italic">
                                Je kunt je activiteiten aanpassen tot je de restbetaling hebt voldaan.
                            </p>
                        </div>
                    )}


                </div>
            ) : (
                <form className="flex flex-col gap-4" onSubmit={handleSubmit}>
                    {error && (
                        <div className="bg-white/20 text-white px-4 py-3 rounded">
                            {error}
                        </div>
                    )}

                    {!canSignUp && nextTrip && (
                        <div className="bg-white/20 text-white px-4 py-3 rounded">
                            De inschrijvingen voor deze reis zijn momenteel gesloten. Houd deze pagina in de gaten!
                        </div>
                    )}

                    {!nextTrip && (
                        <div className="bg-white/20 text-white px-4 py-3 rounded">
                            Momenteel is er geen reis gepland. Houd deze pagina in de gaten voor nieuwe data!
                        </div>
                    )}

                    <p className="text-theme-text dark:text-white/90 text-sm mb-2">
                        Let op: dit is een vrijblijvende aanmelding. De daadwerkelijke betaling volgt later.
                    </p>

                    <div className="flex flex-col gap-4">
                        <div className="grid grid-cols-1 gap-4">
                            <FormField label="Voornaam" required error={error && !form.first_name ? 'Verplicht' : undefined}>
                                <Input
                                    name="first_name"
                                    value={form.first_name}
                                    onChange={handleChange}
                                    required
                                    placeholder="Voornaam"
                                    autoComplete="given-name"
                                />
                                <span className="text-xs text-theme-text-muted/80 mt-1 block font-normal">
                                    Gebruik je volledige naam zoals op je paspoort/ID
                                </span>
                            </FormField>
                        </div>

                        <FormField label="Tussenvoegsel & Achternaam" required error={error && !form.last_name ? 'Verplicht' : undefined}>
                            <Input
                                name="last_name"
                                value={form.last_name}
                                onChange={handleChange}
                                required
                                placeholder="Achternaam (incl. tussenvoegsel)"
                                autoComplete="family-name"
                            />
                        </FormField>

                        <FormField label="E-mailadres" required error={error && !form.email ? 'Verplicht' : undefined}>
                            <Input
                                type="email"
                                name="email"
                                value={form.email}
                                onChange={handleChange}
                                required
                                placeholder="jouw@email.nl"
                                autoComplete="email"
                            />
                        </FormField>

                        <FormField label="Geboortedatum" required error={error && !form.date_of_birth ? 'Verplicht' : undefined}>
                            <Input
                                type="date"
                                name="date_of_birth"
                                value={form.date_of_birth}
                                onChange={handleChange}
                                required
                                autoComplete="bday"
                            />
                        </FormField>

                        <FormField label="Telefoonnummer" required error={error && !form.phone_number ? 'Verplicht' : undefined}>
                            <PhoneInput
                                name="phone_number"
                                value={form.phone_number}
                                onChange={handleChange}
                                required
                                autoComplete="tel"
                            />
                        </FormField>
                    </div>

                    <label className="flex items-start gap-2 text-theme-text dark:text-white mt-2">
                        <input
                            type="checkbox"
                            name="terms_accepted"
                            checked={form.terms_accepted}
                            onChange={handleChange}
                            required
                            className="mt-1 h-5 w-5 rounded accent-theme-purple"
                        />
                        <span className="text-sm">
                            Ik accepteer de{' '}
                            <a href="/reisvoorwaarden.pdf" download className="underline font-semibold text-theme-purple" target="_blank" rel="noopener noreferrer">
                                algemene voorwaarden
                            </a>
                        </span>
                    </label>

                    <button
                        type="submit"
                        disabled={loading || !canSignUp || !nextTrip}
                        className="form-button mt-4 group"
                    >
                        <span>
                            {loading
                                ? 'Bezig met aanmelden...'
                                : (canSignUp && nextTrip)
                                    ? 'Aanmelden voor de reis'
                                    : registrationStartText}
                        </span>
                        {!loading && (canSignUp && nextTrip) && <span className="group-hover:translate-x-1 transition-transform inline-block ml-2">→</span>}
                    </button>
                </form>
            )}
        </section>
    );
}

'use client';

import { useState, Fragment } from 'react';
import { useRouter } from 'next/navigation';
import { Search, Download, Users, Plane, Edit, Trash2, Loader2, AlertCircle, UserCheck, UserX, Send } from 'lucide-react';
import { format } from 'date-fns';
import type { Trip, TripSignup, TripSignupActivity } from '@salvemundi/validations';
import { updateSignupStatus, deleteTripSignup } from '@/server/actions/reis-admin-signups.actions';
import { sendPaymentEmail } from '@/server/actions/reis-admin-mail.actions';

interface AdminReisTableIslandProps {
    initialSignups: TripSignup[];
    initialSignupActivities: Record<number, TripSignupActivity[]>;
    trip: Trip;
    stats: {
        total: number;
        confirmed: number;
        waitlist: number;
        depositPaid: number;
        fullPaid: number;
    }
}

export default function AdminReisTableIsland({ initialSignups, initialSignupActivities, trip, stats }: AdminReisTableIslandProps) {
    const router = useRouter();
    const [signups, setSignups] = useState<TripSignup[]>(initialSignups);
    const [searchQuery, setSearchQuery] = useState('');
    const [statusFilter, setStatusFilter] = useState<string>('all');
    const [roleFilter, setRoleFilter] = useState<string>('all');

    const [expandedIds, setExpandedIds] = useState<number[]>([]);
    const [signupActivitiesMap] = useState<Record<number, TripSignupActivity[]>>(initialSignupActivities);
    const [sendingEmailTo, setSendingEmailTo] = useState<{ signupId: number; type: string } | null>(null);

    const filteredSignups = signups.filter(signup => {
        if (searchQuery) {
            const query = searchQuery.toLowerCase();
            const fullName = `${signup.first_name} ${signup.last_name}`.toLowerCase();
            if (!fullName.includes(query) && !signup.email.toLowerCase().includes(query)) return false;
        }
        if (statusFilter !== 'all' && signup.status !== statusFilter) return false;
        if (roleFilter !== 'all' && signup.role !== roleFilter) return false;
        return true;
    });

    const [actionStates, setActionStates] = useState({
        delete: new Set<number>(),
        status: new Set<number>()
    });

    const toggleExpand = (signup: TripSignup) => {
        if (expandedIds.includes(signup.id)) {
            setExpandedIds(prev => prev.filter(id => id !== signup.id));
            return;
        }
        setExpandedIds(prev => [...prev, signup.id]);
    };

    const handleStatusChange = async (id: number, newStatus: string) => {
        setActionStates(prev => ({ ...prev, status: new Set(prev.status).add(id) }));
        const signup = signups.find(s => s.id === id);

        if (signup && newStatus === 'confirmed' && !signup.deposit_paid) {
            if (!confirm(`Let op: Door de status naar 'Bevestigd' te wijzigen, wordt er automatisch een e-mail met het aanbetalingsverzoek naar ${signup.first_name} gestuurd.\n\nWeet je zeker dat je door wilt gaan?`)) {
                setActionStates(prev => {
                    const newSet = new Set(prev.status);
                    newSet.delete(id);
                    return { ...prev, status: newSet };
                });
                return;
            }
        }

        try {
            const res = await updateSignupStatus(id, newStatus);
            if (res.success) {
                setSignups(signups.map(s => s.id === id ? { ...s, status: newStatus as any } : s));
            } else {
                alert(res.error || 'Er is een fout opgetreden bij het updaten van de status.');
            }
        } catch (error) {
            console.error('Failed to update status:', error);
            alert('Er is een fout opgetreden bij het updaten van de status.');
        } finally {
            setActionStates(prev => {
                const newSet = new Set(prev.status);
                newSet.delete(id);
                return { ...prev, status: newSet };
            });
        }
    };

    const handleDelete = async (id: number) => {
        if (!confirm('Weet je zeker dat je deze aanmelding wilt verwijderen?')) return;

        setActionStates(prev => ({ ...prev, delete: new Set(prev.delete).add(id) }));
        try {
            const res = await deleteTripSignup(id);
            if (res.success) {
                setSignups(signups.filter(s => s.id !== id));
            } else {
                alert(res.error || 'Er is een fout opgetreden bij het verwijderen van de aanmelding.');
            }
        } catch (error) {
            console.error('Failed to delete signup:', error);
            alert('Er is een fout opgetreden bij het verwijderen van de aanmelding.');
        } finally {
            setActionStates(prev => {
                const newSet = new Set(prev.delete);
                newSet.delete(id);
                return { ...prev, delete: newSet };
            });
        }
    };

    const handleResendPaymentEmail = async (signupId: number, paymentType: 'deposit' | 'final') => {
        const signup = signups.find(s => s.id === signupId);
        if (!signup) return;

        if (paymentType === 'deposit' && signup.deposit_paid) {
            if (!confirm('Deze persoon heeft de aanbetaling al betaald. Wil je toch een betaalverzoek sturen?')) return;
        }

        if (paymentType === 'final') {
            if (!signup.deposit_paid) {
                alert('Deze persoon heeft de aanbetaling nog niet betaald. Stuur eerst een aanbetalingsverzoek.');
                return;
            }
            if (signup.full_payment_paid) {
                if (!confirm('Deze persoon heeft al volledig betaald. Wil je toch een betaalverzoek sturen?')) return;
            }
        }

        setSendingEmailTo({ signupId, type: paymentType });

        try {
            const res = await sendPaymentEmail(signupId, trip.id, paymentType);

            if (res.success) {
                alert(`${paymentType === 'deposit' ? 'Aanbetaling' : 'Restbetaling'}sverzoek is succesvol verzonden naar ${signup.email}`);
                setSignups(prev => prev.map(s => s.id === signupId ? {
                    ...s,
                    [paymentType === 'deposit' ? 'deposit_email_sent' : 'final_email_sent']: true
                } : s));
            } else {
                throw new Error(res.error);
            }
        } catch (error) {
            const message = error instanceof Error ? error.message : 'Onbekende fout';
            console.error('Failed to send payment email:', error);
            alert(`Er is een fout opgetreden bij het verzenden van de email: ${message}`);
        } finally {
            setSendingEmailTo(null);
        }
    };

    const downloadExcel = async () => {
        if (filteredSignups.length === 0) return;

        try {
            const XLSX = await import('xlsx');

            const excelData = filteredSignups.map(signup => {
                const idDoc = signup.id_document || '';
                const idDocLabel = idDoc === 'passport' ? 'Paspoort' : idDoc === 'id_card' ? 'ID Kaart' : idDoc;

                const activities = signupActivitiesMap[signup.id] || [];
                const activitiesStr = activities.map(a => a.trip_activity_id?.name || a.trip_activity_id).join(', ');

                return {
                    'Voornaam': signup.first_name,
                    'Achternaam': signup.last_name,
                    'Volledige naam': `${signup.first_name} ${signup.last_name}`.trim(),
                    'E-mailadres': signup.email,
                    'Telefoonnummer': signup.phone_number,
                    'Geboortedatum': signup.date_of_birth ? format(new Date(signup.date_of_birth), 'dd-MM-yyyy') : '',
                    'ID Type': idDocLabel,
                    'Document nummer': signup.document_number || '',
                    'Allergieën': signup.allergies || '',
                    'Bijzonderheden': signup.special_notes || '',
                    'Activiteiten': activitiesStr,
                    'Wil rijden': signup.willing_to_drive ? 'Ja' : 'Nee',
                    'Rol': signup.role === 'crew' ? 'Crew' : 'Deelnemer',
                    'Status': getStatusBadge(signup.status).label,
                    'Betalingstatus': getPaymentStatus(signup).label,
                    'Aanbetaling betaald op': signup.deposit_paid_at ? format(new Date(signup.deposit_paid_at), 'dd-MM-yyyy HH:mm') : '',
                    'Volledige betaling op': signup.full_payment_paid_at ? format(new Date(signup.full_payment_paid_at), 'dd-MM-yyyy HH:mm') : '',
                    'Aangemeld op': signup.date_created ? format(new Date(signup.date_created), 'dd-MM-yyyy HH:mm') : '',
                };
            });

            const worksheet = XLSX.utils.json_to_sheet(excelData);
            const workbook = XLSX.utils.book_new();
            XLSX.utils.book_append_sheet(workbook, worksheet, 'Aanmeldingen');

            const maxWidth = 50;
            const colWidths = Object.keys(excelData[0] || {}).map(key => ({
                wch: Math.min(maxWidth, Math.max(key.length, ...excelData.map(row => String(row[key as keyof typeof row] || '').length)))
            }));
            worksheet['!cols'] = colWidths;

            XLSX.writeFile(workbook, `reis-aanmeldingen-${trip.name || 'export'}-${format(new Date(), 'yyyy-MM-dd')}.xlsx`);
        } catch (error) {
            console.error('Failed to export excel:', error);
            alert('Export mislukt - kon de Excel bibliotheek niet laden.');
        }
    };

    const getPaymentStatus = (signup: TripSignup) => {
        if (signup.full_payment_paid) {
            return { label: 'Volledig betaald', color: 'bg-[var(--theme-success)]/10 text-[var(--theme-success)]' };
        } else if (signup.deposit_paid) {
            return { label: 'Aanbetaling voldaan', color: 'bg-[var(--theme-warning)]/10 text-[var(--theme-warning)]' };
        } else {
            return { label: 'Nog geen betaling', color: 'bg-[var(--theme-error)]/10 text-[var(--theme-error)]' };
        }
    };

    const getStatusBadge = (status: string) => {
        const statusMap: Record<string, { label: string; color: string }> = {
            registered: { label: 'Geregistreerd', color: 'bg-[var(--theme-info)]/10 text-[var(--theme-info)]' },
            waitlist: { label: 'Wachtlijst', color: 'bg-[var(--theme-warning)]/10 text-[var(--theme-warning)]' },
            confirmed: { label: 'Bevestigd', color: 'bg-[var(--theme-success)]/10 text-[var(--theme-success)]' },
            cancelled: { label: 'Geannuleerd', color: 'bg-[var(--text-light)]/10 text-[var(--text-light)]' },
        };
        return statusMap[status] || { label: status, color: 'bg-[var(--text-light)]/10 text-[var(--text-light)]' };
    };

    return (
        <>
            {/* Statistics */}
            <div className="grid grid-cols-2 sm:grid-cols-3 md:grid-cols-5 gap-3 sm:gap-4 mb-8">
                <div className="bg-admin-card rounded-lg shadow p-4 sm:p-6 border-l-4 border-blue-500">
                    <div className="flex items-center justify-between">
                        <div>
                            <p className="text-admin-muted text-xs sm:text-sm">Totaal</p>
                            <p className="text-xl sm:text-2xl font-bold text-admin">{stats.total}</p>
                        </div>
                        <Users className="h-6 w-6 sm:h-8 sm:w-8 text-blue-500" />
                    </div>
                </div>

                <div className="bg-admin-card rounded-lg shadow p-4 sm:p-6 border-l-4 border-green-500">
                    <div className="flex items-center justify-between">
                        <div>
                            <p className="text-admin-muted text-xs sm:text-sm">Bevestigd</p>
                            <p className="text-xl sm:text-2xl font-bold text-admin">{stats.confirmed}</p>
                        </div>
                        <UserCheck className="h-6 w-6 sm:h-8 sm:w-8 text-green-500" />
                    </div>
                </div>

                <div className="bg-admin-card rounded-lg shadow p-4 sm:p-6 border-l-4 border-orange-500">
                    <div className="flex items-center justify-between">
                        <div>
                            <p className="text-admin-muted text-xs sm:text-sm">Wachtlijst</p>
                            <p className="text-xl sm:text-2xl font-bold text-admin">{stats.waitlist}</p>
                        </div>
                        <UserX className="h-6 w-6 sm:h-8 sm:w-8 text-orange-500" />
                    </div>
                </div>

                <div className="bg-admin-card rounded-lg shadow p-4 sm:p-6 border-l-4 border-yellow-500">
                    <div className="flex items-center justify-between">
                        <div>
                            <p className="text-admin-muted text-xs sm:text-sm">Aanbetaling</p>
                            <p className="text-xl sm:text-2xl font-bold text-admin">{stats.depositPaid}</p>
                        </div>
                        <Plane className="h-6 w-6 sm:h-8 sm:w-8 text-yellow-500" />
                    </div>
                </div>

                <div className="bg-admin-card rounded-lg shadow p-4 sm:p-6 border-l-4 border-purple-500">
                    <div className="flex items-center justify-between">
                        <div>
                            <p className="text-admin-muted text-xs sm:text-sm">Volledig betaald</p>
                            <p className="text-xl sm:text-2xl font-bold text-admin">{stats.fullPaid}</p>
                        </div>
                        <Plane className="h-6 w-6 sm:h-8 sm:w-8 text-purple-500" />
                    </div>
                </div>
            </div>

            {/* Filters and Actions */}
            <div className="bg-admin-card rounded-lg shadow p-4 sm:p-6 mb-6">
                <div className="grid grid-cols-1 md:grid-cols-4 gap-3 sm:gap-4">
                    <div className="md:col-span-2 relative">
                        <Search className="absolute left-3 top-1/2 transform -translate-y-1/2 text-admin-muted h-5 w-5" />
                        <input
                            type="text"
                            placeholder="Zoek op naam of e-mailadres..."
                            value={searchQuery}
                            onChange={(e) => setSearchQuery(e.target.value)}
                            className="w-full pl-10 pr-4 py-2 border border-admin bg-admin-card text-admin rounded-lg focus:ring-2 focus:ring-theme-purple focus:border-transparent"
                        />
                    </div>
                    <div>
                        <select
                            value={statusFilter}
                            onChange={(e) => setStatusFilter(e.target.value)}
                            className="w-full px-4 py-2 border border-admin bg-admin-card text-admin rounded-lg focus:ring-2 focus:ring-theme-purple focus:border-transparent"
                        >
                            <option value="all">Alle statussen</option>
                            <option value="registered">Geregistreerd</option>
                            <option value="confirmed">Bevestigd</option>
                            <option value="waitlist">Wachtlijst</option>
                            <option value="cancelled">Geannuleerd</option>
                        </select>
                    </div>
                    <div>
                        <select
                            value={roleFilter}
                            onChange={(e) => setRoleFilter(e.target.value)}
                            className="w-full px-4 py-2 border border-admin bg-admin-card text-admin rounded-lg focus:ring-2 focus:ring-theme-purple focus:border-transparent"
                        >
                            <option value="all">Alle rollen</option>
                            <option value="participant">Deelnemer</option>
                            <option value="crew">Crew</option>
                        </select>
                    </div>
                </div>

                <div className="flex flex-col sm:flex-row flex-wrap gap-3 sm:gap-4 mt-4">
                    <button
                        onClick={downloadExcel}
                        disabled={filteredSignups.length === 0}
                        className="flex items-center justify-center gap-2 px-4 py-2 bg-[var(--theme-success)] text-white rounded-lg hover:opacity-90 transition disabled:opacity-50 disabled:cursor-not-allowed w-full sm:w-auto">
                        <Download className="h-5 w-5" />
                        Export naar Excel
                    </button>
                    <button
                        onClick={() => router.push('/beheer/reis/instellingen')}
                        className="flex items-center justify-center gap-2 px-4 py-2 bg-theme-purple text-white rounded-lg hover:bg-theme-purple-dark transition w-full sm:w-auto"
                    >
                        <Edit className="h-5 w-5" />
                        Reis Instellingen
                    </button>
                </div>
            </div>

            {/* Signups Table */}
            <div className="bg-admin-card rounded-lg shadow overflow-hidden">
                {filteredSignups.length === 0 ? (
                    <div className="text-center py-12">
                        <AlertCircle className="h-12 w-12 text-admin-muted mx-auto mb-4" />
                        <p className="text-admin-muted">Geen aanmeldingen gevonden</p>
                    </div>
                ) : (
                    <div className="overflow-x-auto">
                        <table className="w-full">
                            <thead className="bg-admin-card-soft border-b border-admin">
                                <tr>
                                    <th className="px-3 sm:px-6 py-3 text-left text-xs font-medium text-admin-muted uppercase tracking-wider">Naam</th>
                                    <th className="px-3 sm:px-6 py-3 text-left text-xs font-medium text-admin-muted uppercase tracking-wider hidden sm:table-cell">Geboortedatum</th>
                                    <th className="px-3 sm:px-6 py-3 text-left text-xs font-medium text-admin-muted uppercase tracking-wider hidden md:table-cell">Rol</th>
                                    <th className="px-3 sm:px-6 py-3 text-left text-xs font-medium text-admin-muted uppercase tracking-wider">Status</th>
                                    <th className="px-3 sm:px-6 py-3 text-left text-xs font-medium text-admin-muted uppercase tracking-wider hidden sm:table-cell">Betalingstatus</th>
                                    <th className="px-2 sm:px-6 py-3 text-right text-xs font-medium text-admin-muted uppercase tracking-wider">Acties</th>
                                </tr>
                            </thead>
                            <tbody className="bg-admin-card divide-y divide-admin">
                                {filteredSignups.map(signup => {
                                    const paymentStatus = getPaymentStatus(signup);
                                    const statusBadge = getStatusBadge(signup.status);

                                    return (
                                        <Fragment key={signup.id}>
                                            <tr onClick={() => toggleExpand(signup)} className="hover:bg-admin-hover cursor-pointer">
                                                <td className="px-3 sm:px-6 py-3 sm:py-4">
                                                    <div className="text-xs sm:text-sm font-medium text-admin">
                                                        {signup.first_name} {signup.last_name}
                                                    </div>
                                                    <div className="text-xs sm:text-sm text-admin-muted">{signup.email}</div>
                                                </td>
                                                <td className="px-3 sm:px-6 py-3 sm:py-4 whitespace-nowrap text-xs sm:text-sm text-admin hidden sm:table-cell">
                                                    {signup.date_of_birth ? format(new Date(signup.date_of_birth), 'dd-MM-yyyy') : '-'}
                                                </td>
                                                <td className="px-3 sm:px-6 py-3 sm:py-4 whitespace-nowrap hidden md:table-cell">
                                                    <span className={`px-2 py-1 text-xs font-semibold rounded-full ${signup.role === 'crew' ? 'bg-[var(--theme-purple)]/10 text-[var(--theme-purple)]' : 'bg-[var(--text-light)]/10 text-[var(--text-light)]'}`}>
                                                        {signup.role === 'crew' ? 'Crew' : 'Deelnemer'}
                                                    </span>
                                                </td>
                                                <td className="px-3 sm:px-6 py-3 sm:py-4 whitespace-nowrap">
                                                    {actionStates.status.has(signup.id) ? (
                                                        <Loader2 className="h-5 w-5 animate-spin text-theme-purple" />
                                                    ) : (
                                                        <select
                                                            value={signup.status}
                                                            onClick={(e) => e.stopPropagation()}
                                                            onChange={(e) => handleStatusChange(signup.id, e.target.value)}
                                                            className={`px-1.5 sm:px-2 py-1 text-xs font-semibold rounded-full border-0 ${statusBadge.color} dark:bg-opacity-20 w-full sm:w-auto`}>
                                                            <option value="registered">Geregistreerd</option>
                                                            <option value="confirmed">Bevestigd</option>
                                                            <option value="waitlist">Wachtlijst</option>
                                                            <option value="cancelled">Geannuleerd</option>
                                                        </select>
                                                    )}
                                                </td>
                                                <td className="px-3 sm:px-6 py-3 sm:py-4 whitespace-nowrap hidden sm:table-cell">
                                                    <span className={`px-2 py-1 text-xs font-semibold rounded-full ${paymentStatus.color}`}>
                                                        {paymentStatus.label}
                                                    </span>
                                                </td>
                                                <td className="px-2 sm:px-6 py-3 sm:py-4 whitespace-nowrap text-right text-sm font-medium">
                                                    <div className="flex justify-end gap-1 sm:gap-2">
                                                        <button 
                                                            onClick={(e) => { e.stopPropagation(); router.push(`/beheer/reis/deelnemer/${signup.id}`); }}
                                                            className="text-theme-purple hover:text-theme-purple-dark p-1 sm:p-0" 
                                                            title="Bewerken"
                                                        >
                                                            <Edit className="h-4 w-4 sm:h-5 sm:w-5" />
                                                        </button>
                                                        <button
                                                            onClick={(e) => { e.stopPropagation(); handleDelete(signup.id); }}
                                                            disabled={actionStates.delete.has(signup.id)}
                                                            className="text-red-600 hover:text-red-800 p-1 sm:p-0 disabled:opacity-50"
                                                            title="Verwijderen"
                                                        >
                                                            {actionStates.delete.has(signup.id) ? (
                                                                <Loader2 className="h-4 w-4 sm:h-5 sm:w-5 animate-spin" />
                                                            ) : (
                                                                <Trash2 className="h-4 w-4 sm:h-5 sm:w-5" />
                                                            )}
                                                        </button>
                                                        <button className="text-admin-muted p-1 sm:p-0 focus:outline-none">
                                                            <span className="text-xs sm:text-sm">{expandedIds.includes(signup.id) ? '▲' : '▼'}</span>
                                                        </button>
                                                    </div>
                                                </td>
                                            </tr>
                                            {expandedIds.includes(signup.id) && (
                                                <tr className="bg-admin-card-soft">
                                                    <td colSpan={6} className="px-6 py-4">
                                                        <div className="grid grid-cols-1 md:grid-cols-3 gap-4 mb-4">
                                                            <div>
                                                                <p className="text-sm font-semibold text-admin">Contact</p>
                                                                <p className="text-sm text-admin"><span className="opacity-60">E-mailadres:</span> {signup.email}</p>
                                                                <p className="text-sm text-admin"><span className="opacity-60">Telefoonnummer:</span> {signup.phone_number || '-'}</p>
                                                                <p className="text-sm text-admin">ID Type: {signup.id_document === 'passport' ? 'Paspoort' : signup.id_document === 'id_card' ? 'ID Kaart' : (signup.id_document || '-')}</p>
                                                                <p className="text-sm text-admin">Document nummer: {signup.document_number || '-'}</p>
                                                            </div>
                                                            <div>
                                                                <p className="text-sm font-semibold text-admin">Extra informatie</p>
                                                                <p className="text-sm text-admin">Allergieën: {signup.allergies || '-'}</p>
                                                                <p className="text-sm text-admin">Bijzonderheden: {signup.special_notes || '-'}</p>
                                                            </div>
                                                            <div>
                                                                <p className="text-sm font-semibold text-admin">Activiteiten</p>
                                                                {signupActivitiesMap[signup.id] ? (
                                                                    signupActivitiesMap[signup.id].length > 0 ? (
                                                                        signupActivitiesMap[signup.id].map(a => (
                                                                            <div key={a.id} className="flex items-center justify-between text-sm text-admin">
                                                                                <span>{a.trip_activity_id?.name || 'Activiteit ID ' + a.trip_activity_id}</span>
                                                                            </div>
                                                                        ))
                                                                    ) : (
                                                                        <p className="text-sm text-admin-muted">Geen activiteiten geselecteerd</p>
                                                                    )
                                                                ) : (
                                                                    <p className="text-sm text-admin-muted">Geen data beschikbaar</p>
                                                                )}
                                                            </div>
                                                        </div>

                                                        <div className="border-t border-admin pt-4 mt-4">
                                                            <p className="text-sm font-semibold text-admin mb-2">Betaalverzoek versturen (internationaal)</p>
                                                            <div className="flex flex-col sm:flex-row gap-2">
                                                                <button
                                                                    onClick={(e) => { e.stopPropagation(); handleResendPaymentEmail(signup.id, 'deposit'); }}
                                                                    disabled={sendingEmailTo?.signupId === signup.id && sendingEmailTo?.type === 'deposit'}
                                                                    className={`flex items-center justify-center gap-2 px-4 py-2 ${signup.deposit_email_sent ? 'bg-admin-hover text-admin' : 'bg-yellow-600 text-white'} text-sm rounded-lg hover:opacity-80 transition disabled:opacity-50 disabled:cursor-not-allowed`}
                                                                >
                                                                    {sendingEmailTo?.signupId === signup.id && sendingEmailTo?.type === 'deposit' ? <Loader2 className="h-4 w-4 animate-spin" /> : <Send className="h-4 w-4" />}
                                                                    Aanbetaling {signup.deposit_email_sent && <span className="ml-1 text-[10px] font-bold uppercase opacity-60">(Verzonden)</span>}
                                                                </button>
                                                                <button
                                                                    onClick={(e) => { e.stopPropagation(); handleResendPaymentEmail(signup.id, 'final'); }}
                                                                    disabled={(sendingEmailTo?.signupId === signup.id && sendingEmailTo?.type === 'final') || !trip.allow_final_payments}
                                                                    className={`flex items-center justify-center gap-2 px-4 py-2 ${signup.final_email_sent ? 'bg-admin-hover text-admin' : 'bg-green-600 text-white'} text-sm rounded-lg hover:opacity-80 transition disabled:opacity-50 disabled:cursor-not-allowed`}
                                                                >
                                                                    {sendingEmailTo?.signupId === signup.id && sendingEmailTo?.type === 'final' ? <Loader2 className="h-4 w-4 animate-spin" /> : <Send className="h-4 w-4" />}
                                                                    Restbetaling {signup.final_email_sent && <span className="ml-1 text-[10px] font-bold uppercase opacity-60">(Verzonden)</span>}
                                                                </button>
                                                                {!trip.allow_final_payments && <span className="text-[10px] text-red-500 italic flex items-center">Restbetalingen nog niet geopend</span>}
                                                            </div>
                                                        </div>
                                                    </td>
                                                </tr>
                                            )}
                                        </Fragment>
                                    );
                                })}
                            </tbody>
                        </table>
                    </div>
                )}
            </div>
        </>
    );
}

'use client';

import React, { useState, useEffect, useMemo } from 'react';
import { 
    Shield, CheckCircle, XCircle, RefreshCw, Clock, 
    Tag, Loader2, ArrowRight, Filter, 
    CheckSquare, Square
} from 'lucide-react';
import { 
    getPendingSignupsAction, 
    approveSignupAction, 
    rejectSignupAction,
    getAuditSettingsAction,
    updateAuditSettingsAction,
    getSystemLogsAction
} from '@/server/actions/audit.actions';
import { PendingSignup } from '@salvemundi/validations';

export default function AuditLogIsland() {
    const [activeTab, setActiveTab] = useState<'pending' | 'logs'>('pending');
    const [signups, setSignups] = useState<PendingSignup[]>([]);
    const [logs, setLogs] = useState<any[]>([]);
    const [isLoading, setIsLoading] = useState(true);
    const [isProcessing, setIsProcessing] = useState<string | null>(null);
    const [manualApproval, setManualApproval] = useState(false);

    // Filters
    const [filterType, setFilterType] = useState<string>('all');
    const [selectedIds, setSelectedIds] = useState<Set<string>>(new Set());

    const loadData = async () => {
        setIsLoading(true);
        try {
            const [signupsRes, settingsRes, logsRes] = await Promise.all([
                getPendingSignupsAction(),
                getAuditSettingsAction(),
                getSystemLogsAction(50)
            ]);

            if (signupsRes.success && signupsRes.data) setSignups(signupsRes.data);
            if (settingsRes.success && settingsRes.data) setManualApproval(settingsRes.data.manual_approval);
            if (logsRes.success && logsRes.data) setLogs(logsRes.data);
        } catch (err) {
            console.error("Failed to load audit data", err);
        } finally {
            setIsLoading(false);
        }
    };

    useEffect(() => {
        loadData();
    }, []);

    const filteredSignups = useMemo(() => {
        if (filterType === 'all') return signups;
        return signups.filter(s => s.type === filterType);
    }, [signups, filterType]);

    const handleApprove = async (id: string, type: string) => {
        setIsProcessing(id);
        try {
            const res = await approveSignupAction(id, type);
            if (res.success) {
                setSignups(prev => prev.filter(s => s.id !== id));
                // Reload logs to show the approval
                const logsRes = await getSystemLogsAction(50);
                if (logsRes.success && logsRes.data) setLogs(logsRes.data);
            }
        } finally {
            setIsProcessing(null);
        }
    };

    const handleReject = async (id: string, type: string) => {
        if (!confirm('Weet je zeker dat je deze inschrijving wilt afwijzen?')) return;
        setIsProcessing(id);
        try {
            const res = await rejectSignupAction(id, type);
            if (res.success) {
                setSignups(prev => prev.filter(s => s.id !== id));
                // Reload logs to show the rejection
                const logsRes = await getSystemLogsAction(50);
                if (logsRes.success && logsRes.data) setLogs(logsRes.data);
            }
        } finally {
            setIsProcessing(null);
        }
    };

    const toggleManualApproval = async () => {
        const newValue = !manualApproval;
        setManualApproval(newValue);
        await updateAuditSettingsAction(newValue);
        // Reload logs
        const logsRes = await getSystemLogsAction(50);
        if (logsRes.success && logsRes.data) setLogs(logsRes.data);
    };

    const toggleSelectAll = () => {
        if (selectedIds.size === filteredSignups.length) {
            setSelectedIds(new Set());
        } else {
            setSelectedIds(new Set(filteredSignups.map(s => s.id)));
        }
    };

    const toggleSelectOne = (id: string) => {
        const newSet = new Set(selectedIds);
        if (newSet.has(id)) newSet.delete(id);
        else newSet.add(id);
        setSelectedIds(newSet);
    };

    return (
        <div className="space-y-6 pb-20">
            {/* Settings & Stats */}
            <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
                <div className="lg:col-span-2 bg-white dark:bg-slate-800 p-6 rounded-3xl border border-slate-100 dark:border-slate-700 shadow-sm flex items-center justify-between">
                    <div>
                        <h3 className="font-bold text-slate-900 dark:text-white flex items-center gap-2">
                            <Shield className="h-5 w-5 text-purple-600" />
                            Goedkeuringsmodus
                        </h3>
                        <p className="text-sm text-slate-500 dark:text-slate-400 mt-1">
                            {manualApproval 
                                ? "Handmatige goedkeuring is ACTIEF. Alle nieuwe aanmeldingen moeten worden gecontroleerd."
                                : "Automatische goedkeuring is ACTIEF. Aanmeldingen worden direct verwerkt."}
                        </p>
                    </div>
                    <button 
                        onClick={toggleManualApproval}
                        className={`relative inline-flex h-6 w-11 items-center rounded-full transition-colors focus:outline-none ${manualApproval ? 'bg-purple-600' : 'bg-slate-300 dark:bg-slate-600'}`}
                    >
                        <span className={`inline-block h-4 w-4 transform rounded-full bg-white transition-transform ${manualApproval ? 'translate-x-6' : 'translate-x-1'}`} />
                    </button>
                </div>

                <div className="bg-purple-600 p-6 rounded-3xl shadow-lg shadow-purple-200 dark:shadow-none text-white overflow-hidden relative">
                    <div className="relative z-10">
                        <p className="text-purple-100 text-sm font-medium">In afwachting</p>
                        <h3 className="text-4xl font-black mt-1">{signups.length}</h3>
                    </div>
                    <Clock className="absolute -right-4 -bottom-4 h-24 w-24 text-white/10" />
                </div>
            </div>

            {/* Tabs Navigation */}
            <div className="flex gap-1 bg-slate-100 dark:bg-slate-900/50 p-1 rounded-2xl w-fit">
                <button
                    onClick={() => setActiveTab('pending')}
                    className={`flex items-center gap-2 px-6 py-2.5 rounded-xl font-bold transition-all text-sm ${activeTab === 'pending' ? 'bg-white dark:bg-slate-800 shadow-sm text-purple-600' : 'text-slate-500 hover:text-slate-700 dark:hover:text-slate-300'}`}
                >
                    <Clock className="h-4 w-4" /> Wachtrij
                </button>
                <button
                    onClick={() => setActiveTab('logs')}
                    className={`flex items-center gap-2 px-6 py-2.5 rounded-xl font-bold transition-all text-sm ${activeTab === 'logs' ? 'bg-white dark:bg-slate-800 shadow-sm text-purple-600' : 'text-slate-500 hover:text-slate-700 dark:hover:text-slate-300'}`}
                >
                    <Tag className="h-4 w-4" /> Logboek
                </button>
            </div>

            {/* Main Content Area */}
            {activeTab === 'pending' ? (
                <div className="bg-white dark:bg-slate-800 rounded-3xl border border-slate-100 dark:border-slate-700 shadow-xl overflow-hidden">
                    <div className="p-6 border-b border-slate-100 dark:border-slate-700 flex flex-wrap items-center justify-between gap-4">
                        <div className="flex items-center gap-4 overflow-x-auto pb-1 custom-scrollbar">
                            {['all', 'event', 'trip', 'pub_crawl'].map(type => (
                                <button
                                    key={type}
                                    onClick={() => setFilterType(type)}
                                    className={`px-4 py-2 rounded-xl text-sm font-medium transition-all whitespace-nowrap ${filterType === type 
                                        ? 'bg-slate-900 dark:bg-white text-white dark:text-slate-900' 
                                        : 'text-slate-500 hover:bg-slate-50 dark:hover:bg-slate-700'}`}
                                >
                                    {type.charAt(0).toUpperCase() + type.slice(1).replace('_', ' ')}
                                </button>
                            ))}
                        </div>

                        <button 
                            onClick={loadData}
                            disabled={isLoading}
                            className="p-2 text-slate-400 hover:text-purple-600 transition-colors"
                        >
                            <RefreshCw className={`h-5 w-5 ${isLoading ? 'animate-spin' : ''}`} />
                        </button>
                    </div>

                    <div className="overflow-x-auto">
                        <table className="w-full text-left">
                            <thead>
                                <tr className="bg-slate-50 dark:bg-slate-900/50 border-b border-slate-100 dark:border-slate-700">
                                    <th className="p-4 w-12 text-center">
                                        <button onClick={toggleSelectAll} className="text-slate-400 hover:text-purple-600">
                                            {selectedIds.size > 0 && selectedIds.size === filteredSignups.length ? <CheckSquare className="h-5 w-5 text-purple-600" /> : <Square className="h-5 w-5" />}
                                        </button>
                                    </th>
                                    <th className="p-4 text-xs font-bold text-slate-400 uppercase tracking-wider">Datum</th>
                                    <th className="p-4 text-xs font-bold text-slate-400 uppercase tracking-wider">Naam</th>
                                    <th className="p-4 text-xs font-bold text-slate-400 uppercase tracking-wider">Product</th>
                                    <th className="p-4 text-xs font-bold text-slate-400 uppercase tracking-wider text-center">Status</th>
                                    <th className="p-4 text-xs font-bold text-slate-400 uppercase tracking-wider text-right">Acties</th>
                                </tr>
                            </thead>
                            <tbody className="divide-y divide-slate-100 dark:divide-slate-700">
                                {isLoading ? (
                                    [...Array(5)].map((_, i) => (
                                        <tr key={i} className="animate-pulse">
                                            <td colSpan={6} className="p-8">
                                                <div className="h-4 bg-slate-100 dark:bg-slate-700 rounded w-full" />
                                            </td>
                                        </tr>
                                    ))
                                ) : filteredSignups.length === 0 ? (
                                    <tr>
                                        <td colSpan={6} className="p-20 text-center">
                                            <div className="flex flex-col items-center">
                                                <CheckCircle className="h-12 w-12 text-green-500 mb-4 opacity-20" />
                                                <h4 className="text-slate-900 dark:text-white font-bold">Alles bijgewerkt!</h4>
                                                <p className="text-slate-500 dark:text-slate-400 text-sm">Er zijn geen inschrijvingen die op goedkeuring wachten.</p>
                                            </div>
                                        </td>
                                    </tr>
                                ) : (
                                    filteredSignups.map(s => (
                                        <tr key={s.id} className={`hover:bg-slate-50 dark:hover:bg-slate-900/20 transition-colors ${selectedIds.has(s.id) ? 'bg-purple-50 dark:bg-purple-900/10' : ''}`}>
                                            <td className="p-4 text-center">
                                                <button onClick={() => toggleSelectOne(s.id)} className={`transition-colors ${selectedIds.has(s.id) ? 'text-purple-600' : 'text-slate-300'}`}>
                                                    {selectedIds.has(s.id) ? <CheckSquare className="h-5 w-5" /> : <Square className="h-5 w-5" />}
                                                </button>
                                            </td>
                                            <td className="p-4 text-sm text-slate-500 dark:text-slate-400 whitespace-nowrap">
                                                {new Date(s.created_at).toLocaleDateString('nl-NL', { day: 'numeric', month: 'short', hour: '2-digit', minute: '2-digit' })}
                                            </td>
                                            <td className="p-4">
                                                <div className="flex flex-col min-w-0">
                                                    <span className="font-bold text-slate-900 dark:text-white truncate">{s.first_name} {s.last_name}</span>
                                                    <span className="text-xs text-slate-400 truncate">{s.email}</span>
                                                </div>
                                            </td>
                                            <td className="p-4">
                                                <div className="flex items-center gap-2">
                                                    <Tag className="h-3.5 w-3.5 text-slate-400" />
                                                    <span className="text-sm text-slate-600 dark:text-slate-300 font-medium">{s.product_name}</span>
                                                </div>
                                            </td>
                                            <td className="p-4 text-center">
                                                <span className={`inline-flex items-center px-2 py-1 rounded-full text-[10px] font-bold uppercase tracking-wider ${s.payment_status === 'paid' ? 'bg-green-100 dark:bg-green-900/30 text-green-700 dark:text-green-400' : 'bg-amber-100 dark:bg-amber-900/30 text-amber-700 dark:text-amber-400'}`}>
                                                    {s.payment_status}
                                                </span>
                                            </td>
                                            <td className="p-4">
                                                <div className="flex items-center justify-end gap-2">
                                                    <button 
                                                        onClick={() => handleApprove(s.id, s.type)}
                                                        disabled={!!isProcessing}
                                                        className="p-2 bg-green-50 dark:bg-green-900/20 text-green-600 dark:text-green-400 rounded-xl hover:bg-green-100 dark:hover:bg-green-900/40 transition-all disabled:opacity-50"
                                                    >
                                                        {isProcessing === s.id ? <Loader2 className="h-4 w-4 animate-spin" /> : <CheckCircle className="h-4 w-4" />}
                                                    </button>
                                                    <button 
                                                        onClick={() => handleReject(s.id, s.type)}
                                                        disabled={!!isProcessing}
                                                        className="p-2 bg-red-50 dark:bg-red-900/20 text-red-600 dark:text-red-400 rounded-xl hover:bg-red-100 dark:hover:bg-red-900/40 transition-all disabled:opacity-50"
                                                    >
                                                        {isProcessing === s.id ? <Loader2 className="h-4 w-4 animate-spin" /> : <XCircle className="h-4 w-4" />}
                                                    </button>
                                                </div>
                                            </td>
                                        </tr>
                                    ))
                                )}
                            </tbody>
                        </table>
                    </div>
                </div>
            ) : (
                <div className="bg-white dark:bg-slate-800 rounded-3xl border border-slate-100 dark:border-slate-700 shadow-xl overflow-hidden">
                    <div className="p-6 border-b border-slate-100 dark:border-slate-700 flex justify-between items-center">
                        <h3 className="text-lg font-bold text-slate-800 dark:text-white">Activiteitslogboek</h3>
                        <button 
                            onClick={loadData}
                            disabled={isLoading}
                            className="p-2 text-slate-400 hover:text-purple-600 transition-colors"
                        >
                            <RefreshCw className={`h-5 w-5 ${isLoading ? 'animate-spin' : ''}`} />
                        </button>
                    </div>
                    <div className="overflow-x-auto">
                        <table className="w-full text-left">
                            <thead>
                                <tr className="bg-slate-50 dark:bg-slate-900/50 border-b border-slate-100 dark:border-slate-700 text-xs font-bold text-slate-400 uppercase tracking-wider">
                                    <th className="p-4">Datum</th>
                                    <th className="p-4">Type</th>
                                    <th className="p-4">Admin</th>
                                    <th className="p-4">Details</th>
                                    <th className="p-4 text-center">Status</th>
                                </tr>
                            </thead>
                            <tbody className="divide-y divide-slate-100 dark:divide-slate-700">
                                {isLoading ? (
                                    [...Array(5)].map((_, i) => (
                                        <tr key={i} className="animate-pulse">
                                            <td colSpan={5} className="p-8"><div className="h-4 bg-slate-100 dark:bg-slate-700 rounded w-full" /></td>
                                        </tr>
                                    ))
                                ) : logs.length === 0 ? (
                                    <tr>
                                        <td colSpan={5} className="p-20 text-center text-slate-400 italic">Geen logboekvermeldingen gevonden.</td>
                                    </tr>
                                ) : (
                                    logs.map(log => (
                                        <tr key={log.id} className="hover:bg-slate-50 dark:hover:bg-slate-900/20 transition-colors">
                                            <td className="p-4 text-sm text-slate-500 whitespace-nowrap">
                                                {new Date(log.created_at).toLocaleString('nl-NL')}
                                            </td>
                                            <td className="p-4">
                                                <span className="font-bold text-slate-700 dark:text-slate-200 text-sm">
                                                    {log.type}
                                                </span>
                                            </td>
                                            <td className="p-4 text-sm text-slate-600 dark:text-slate-400">
                                                {log.payload?.admin_name || 'Systeem'}
                                            </td>
                                            <td className="p-4">
                                                <div className="text-xs text-slate-600 dark:text-slate-300 max-w-md break-all">
                                                    {log.payload && typeof log.payload === 'object' ? (
                                                        <div className="space-y-1">
                                                            {Object.entries(log.payload)
                                                                .filter(([key]) => !['admin_id', 'admin_name', 'timestamp'].includes(key))
                                                                .map(([key, val]) => (
                                                                    <div key={key} className="flex gap-2">
                                                                        <span className="font-bold opacity-50">{key}:</span>
                                                                        <span>{typeof val === 'object' ? JSON.stringify(val) : String(val)}</span>
                                                                    </div>
                                                                ))}
                                                        </div>
                                                    ) : (
                                                        <span>{String(log.payload || '-')}</span>
                                                    )}
                                                </div>
                                            </td>
                                            <td className="p-4 text-center">
                                                <span className={`inline-flex items-center px-2 py-0.5 rounded-full text-[10px] font-black uppercase tracking-wider ${log.status === 'SUCCESS' ? 'bg-green-100 text-green-700' : 'bg-red-100 text-red-700'}`}>
                                                    {log.status}
                                                </span>
                                            </td>
                                        </tr>
                                    ))
                                )}
                            </tbody>
                        </table>
                    </div>
                </div>
            )}
        </div>
    );
}

'use client';

import React, { useState, useEffect, useCallback } from 'react';
import {
    RefreshCw, User, CheckCircle, AlertCircle,
    Loader2, ArrowRight, Settings, Info,
    Check, X, AlertTriangle, Users
} from 'lucide-react';
import { triggerFullSyncAction, getSyncStatusAction, stopSyncAction, triggerUserSyncAction } from '@/server/actions/azure-sync.actions';
import SyncSkeleton from '@/components/ui/admin/SyncSkeleton';

interface SyncStatus {
    jobId?: string;
    active: boolean;
    status: 'idle' | 'running' | 'completed' | 'failed' | 'aborted';
    total: number;
    processed: number;
    errorCount: number;
    warningCount: number;
    missingDataCount: number;
    successCount: number;
    excludedCount: number;
    createdCount: number;
    errors: { email: string; message: string; timestamp: string }[];
    warnings: { email: string; message: string }[];
    missingData: { email: string; reason: string }[];
    successfulUsers: { email: string }[];
    excludedUsers: { email: string }[];
    createdUsers: { email: string }[];
    startTime?: string;
    endTime?: string;
    lastHeartbeat?: string;
    abortRequested?: boolean;
}

const syncFieldOptions = [
    { id: 'membership_expiry', label: 'Lidmaatschap vervaldatum' },
    { id: 'geboortedatum', label: 'Geboortedatum' },
    { id: 'phone_number', label: 'Mobiel nummer' },
    { id: 'committees', label: 'Commissies' },
];

export default function AzureSyncIsland() {
    const [mounted, setMounted] = useState(false);
    const [status, setStatus] = useState<SyncStatus | null>(null);
    const [isStartingSync, setIsStartingSync] = useState(false);
    const [isStopping, setIsStopping] = useState(false);
    const [isUserSyncLoading, setIsUserSyncLoading] = useState(false);
    const [userId, setUserId] = useState('');
    const [error, setError] = useState<string | null>(null);
    const [lastUpdated, setLastUpdated] = useState<Date | null>(null);
    const [isLoading, setIsLoading] = useState(true);

    const [selectedSyncFields, setSelectedSyncFields] = useState<string[]>(['membership_expiry', 'geboortedatum', 'phone_number', 'committees']);
    const [forceLink, setForceLink] = useState(false);
    const [activeOnly, setActiveOnly] = useState(false);
    const [resultFilter, setResultFilter] = useState<'all' | 'success' | 'created' | 'warnings' | 'missing' | 'errors' | 'excluded'>('all');

    const fetchStatus = useCallback(async () => {
        try {
            const data = await getSyncStatusAction();
            if (data && 'status' in data) {
                setStatus(data as SyncStatus);
                setLastUpdated(new Date());
            }
        } catch (err) {
            console.error('Failed to fetch sync status:', err);
        } finally {
            setIsLoading(false);
        }
    }, []);

    // Initial fetch
    useEffect(() => {
        setMounted(true);
        fetchStatus();
    }, [fetchStatus]);

    // Polling while active or starting (Serial approach to prevent request piling)
    useEffect(() => {
        if (!mounted) return;

        let timeout: NodeJS.Timeout;
        const shouldPoll = status?.active || status?.status === 'running' || isStartingSync;

        const poll = async () => {
            if (!shouldPoll) return;
            await fetchStatus();
            timeout = setTimeout(poll, 2000); // Wait 2s AFTER fetch completes
        };

        if (shouldPoll) {
            poll();
        }

        return () => clearTimeout(timeout);
    }, [status?.active, status?.status, isStartingSync, fetchStatus, mounted]);

    if (!mounted || (isLoading && !status)) return <SyncSkeleton />;

    const handleFullSync = async () => {
        setIsStartingSync(true);
        setError(null);
        try {
            const result = await triggerFullSyncAction({
                fields: selectedSyncFields,
                forceLink,
                activeOnly
            });
            if (!result.success) {
                setError(result.error || 'Kon sync niet starten');
            } else {
                fetchStatus();
            }
        } catch (err) {
            setError('Netwerkfout bij het starten van de sync.');
        } finally {
            setIsStartingSync(false);
        }
    };

    const handleStopSync = async () => {
        setIsStopping(true);
        setError(null);
        try {
            const result = await stopSyncAction();
            if (!result.success) {
                setError(result.error || 'Kon sync niet stoppen');
            } else {
                fetchStatus();
            }
        } catch (err) {
            setError('Netwerkfout bij het stoppen van de sync.');
        } finally {
            setIsStopping(false);
        }
    };

    const handleUserSync = async (e: React.FormEvent) => {
        e.preventDefault();
        if (!userId.trim()) return;
        setIsUserSyncLoading(true);
        setError(null);
        try {
            const result = await triggerUserSyncAction(userId.trim());
            if (!result.success) {
                setError(result.error || 'Fout bij individuele sync');
            } else {
                setUserId('');
            }
        } catch (err) {
            setError('Netwerkfout bij het synchroniseren van de gebruiker.');
        } finally {
            setIsUserSyncLoading(false);
        }
    };

    const toggleField = (id: string) => {
        setSelectedSyncFields(prev => 
            prev.includes(id) ? prev.filter(f => f !== id) : [...prev, id]
        );
    };

    const progress = status ? (status.total > 0 ? (status.processed / status.total) * 100 : 0) : 0;

    return (
        <div className="space-y-8 animate-in fade-in duration-500">
            {/* Global Error Banner */}
            {error && (
                <div className="flex items-center gap-3 p-4 bg-red-500/10 border border-red-500/20 rounded-2xl text-red-500 animate-in slide-in-from-top-2">
                    <AlertCircle className="h-5 w-5 shrink-0" />
                    <p className="text-sm font-medium">{error}</p>
                    <button onClick={() => setError(null)} className="ml-auto hover:bg-red-500/10 p-1 rounded-lg">
                        <X className="h-4 w-4" />
                    </button>
                </div>
            )}

            <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
                {/* Configuration Card */}
                <div className="lg:col-span-2 space-y-8">
                    <section className="bg-white dark:bg-slate-800 p-8 rounded-[2rem] shadow-sm ring-1 ring-slate-200 dark:ring-slate-700/50">
                        <div className="flex items-center justify-between mb-8">
                            <div className="flex items-center gap-4">
                                <div className="p-3 bg-indigo-500/10 rounded-2xl text-indigo-500">
                                    <Settings className="h-6 w-6" />
                                </div>
                                <h3 className="text-xl font-bold dark:text-white">Configuratie</h3>
                            </div>
                        </div>

                        <div className="space-y-6">
                            <div>
                                <label className="text-sm font-semibold text-slate-500 dark:text-slate-400 mb-4 block uppercase tracking-wider">
                                    Te synchroniseren velden
                                </label>
                                <div className="flex flex-wrap gap-2">
                                    {syncFieldOptions.map(option => (
                                        <button
                                            key={option.id}
                                            onClick={() => toggleField(option.id)}
                                            className={`px-4 py-2 rounded-xl text-sm font-medium transition-all duration-300 border ${
                                                selectedSyncFields.includes(option.id)
                                                    ? 'bg-indigo-500 text-white border-indigo-500 shadow-lg shadow-indigo-500/20'
                                                    : 'bg-slate-100 dark:bg-white/5 text-slate-600 dark:text-slate-400 border-transparent hover:border-slate-300 dark:hover:border-white/10'
                                            }`}
                                        >
                                            <div className="flex items-center gap-2">
                                                {selectedSyncFields.includes(option.id) && <Check className="h-4 w-4" />}
                                                {option.label}
                                            </div>
                                        </button>
                                    ))}
                                </div>
                            </div>

                            <div className="grid grid-cols-1 md:grid-cols-2 gap-4 pt-4 border-t border-slate-100 dark:border-white/5">
                                <label className="flex items-center gap-3 p-4 rounded-2xl bg-slate-50 dark:bg-white/5 cursor-pointer group hover:bg-slate-100 dark:hover:bg-white/10 transition-colors border border-transparent hover:border-indigo-500/20">
                                    <input 
                                        type="checkbox" 
                                        checked={forceLink} 
                                        onChange={e => setForceLink(e.target.checked)}
                                        className="h-5 w-5 rounded-lg border-2 border-slate-300 dark:border-white/20 text-indigo-500 focus:ring-indigo-500 transition-all cursor-pointer"
                                    />
                                    <div>
                                        <div className="text-sm font-bold dark:text-white group-hover:text-indigo-500 transition-colors">Force Link</div>
                                        <div className="text-xs text-slate-500 dark:text-slate-400">Koppel bestaande accounts op e-mail</div>
                                    </div>
                                </label>
                                <label className="flex items-center gap-3 p-4 rounded-2xl bg-slate-50 dark:bg-white/5 cursor-pointer group hover:bg-slate-100 dark:hover:bg-white/10 transition-colors border border-transparent hover:border-indigo-500/20">
                                    <input 
                                        type="checkbox" 
                                        checked={activeOnly} 
                                        onChange={e => setActiveOnly(e.target.checked)}
                                        className="h-5 w-5 rounded-lg border-2 border-slate-300 dark:border-white/20 text-indigo-500 focus:ring-indigo-500 transition-all cursor-pointer"
                                    />
                                    <div>
                                        <div className="text-sm font-bold dark:text-white group-hover:text-indigo-500 transition-colors">Active Only</div>
                                        <div className="text-xs text-slate-500 dark:text-slate-400">Synchroniseer alleen actieve leden</div>
                                    </div>
                                </label>
                            </div>

                            {status?.active ? (
                                <button
                                    onClick={handleStopSync}
                                    disabled={isStopping || status?.abortRequested}
                                    className="w-full mt-4 py-4 px-6 bg-red-500 hover:bg-red-600 text-white font-bold rounded-2xl shadow-xl shadow-red-500/20 transition-all flex items-center justify-center gap-3 active:scale-95 disabled:opacity-50"
                                >
                                    {isStopping ? (
                                        <Loader2 className="h-6 w-6 animate-spin" />
                                    ) : (
                                        <>
                                            <X className="h-6 w-6" />
                                            <span>{status?.abortRequested ? 'Stoppen aangevraagd...' : 'Synchronisatie Stoppen'}</span>
                                        </>
                                    )}
                                </button>
                            ) : (
                                <button
                                    onClick={handleFullSync}
                                    disabled={isStartingSync}
                                    className="w-full mt-4 py-4 px-6 bg-gradient-to-r from-indigo-600 to-purple-600 hover:from-indigo-700 hover:to-purple-700 text-white font-bold rounded-2xl shadow-xl shadow-indigo-500/20 transition-all flex items-center justify-center gap-3 disabled:opacity-50 disabled:grayscale active:scale-95"
                                >
                                    {isStartingSync ? (
                                        <Loader2 className="h-6 w-6 animate-spin" />
                                    ) : (
                                        <>
                                            <RefreshCw className="h-6 w-6" />
                                            <span>Start Volledige Synchronisatie</span>
                                        </>
                                    )}
                                </button>
                            )}
                        </div>
                    </section>
                </div>

                {/* Individual Sync Card */}
                <div className="space-y-8">
                    <section className="bg-white dark:bg-slate-800 p-8 rounded-[2rem] shadow-sm ring-1 ring-slate-200 dark:ring-slate-700/50 h-full">
                        <div className="flex items-center gap-4 mb-8">
                            <div className="p-3 bg-blue-500/10 rounded-2xl text-blue-500">
                                <User className="h-6 w-6" />
                            </div>
                            <h3 className="text-xl font-bold dark:text-white">Single Sync</h3>
                        </div>

                        <p className="text-sm text-slate-500 dark:text-slate-400 mb-8 leading-relaxed">
                            Synchroniseer direct een specifiek lid door hun Azure Entra ID in te voeren. 
                        </p>

                        <form onSubmit={handleUserSync} className="space-y-4">
                            <input 
                                value={userId}
                                onChange={e => setUserId(e.target.value)}
                                placeholder="Azure Entra ID (bijv. d3a1b2...)"
                                autoComplete="off"
                                className="w-full p-4 bg-slate-50 dark:bg-slate-900 border border-slate-200 dark:border-slate-700/50 rounded-2xl focus:outline-none focus:ring-2 focus:ring-blue-500/20 focus:border-blue-500 transition-all dark:text-white"
                            />
                            <button
                                type="submit"
                                disabled={isUserSyncLoading || !userId.trim()}
                                className="w-full py-4 px-6 bg-slate-100 dark:bg-slate-700 hover:bg-slate-200 dark:hover:bg-slate-600 font-bold rounded-2xl shadow-sm transition-all active:scale-95 disabled:opacity-50 text-slate-900 dark:text-white"
                            >
                                {isUserSyncLoading ? <Loader2 className="h-5 w-5 animate-spin mx-auto" /> : 'Nu via Azure Syncen'}
                            </button>
                        </form>
                    </section>
                </div>
            </div>

            {/* Progress & Results Section */}
            {status && (
                <section className="bg-white dark:bg-slate-800 p-8 rounded-[2rem] shadow-sm ring-1 ring-slate-200 dark:ring-slate-700/50 animate-in slide-in-from-bottom-4 duration-700">
                    <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4 mb-10">
                        <div className="space-y-1">
                            <div className="flex items-center gap-3">
                                <h3 className="text-2xl font-black dark:text-white">Live Voortgang</h3>
                                {status.active && <div className="h-2 w-2 rounded-full bg-green-500 animate-pulse" />}
                            </div>
                            <div className="flex items-center gap-2 text-xs text-slate-500 font-medium">
                                <p>Status: <span className="capitalize font-bold text-indigo-500">{status.status}</span></p>
                                {lastUpdated && (
                                    <>
                                        <span>•</span>
                                        <p>Laatst bijgewerkt: {lastUpdated.toLocaleTimeString()}</p>
                                    </>
                                )}
                            </div>
                        </div>
                        <div className="text-right">
                            <div className="text-3xl font-black text-indigo-500">{Math.round(progress)}%</div>
                            <div className="text-xs font-bold text-slate-400 uppercase tracking-widest">{status.processed} / {status.total} Leden</div>
                        </div>
                    </div>

                    {/* Thick Progress Bar */}
                    <div className="h-6 w-full bg-slate-100 dark:bg-white/5 rounded-full overflow-hidden mb-12 flex items-center p-1.5 border border-slate-200 dark:border-white/10 shadow-inner">
                        <div 
                            className="h-full bg-gradient-to-r from-indigo-500 via-purple-500 to-indigo-500 bg-[length:200%_100%] animate-shimmer rounded-full transition-all duration-1000 ease-out shadow-lg"
                            style={{ width: `${Math.max(progress, 3)}%` }}
                        />
                    </div>

                    {/* Stats Grid */}
                    <div className="grid grid-cols-2 md:grid-cols-5 gap-4 mb-12">
                        <StatCard icon={<CheckCircle className="text-green-500" />} label="Geslaagd" count={status.successCount} color="green" />
                        <StatCard icon={<Users className="text-purple-500" />} label="Nieuw" count={status.createdCount || 0} color="purple" />
                        <StatCard icon={<AlertTriangle className="text-amber-500" />} label="Warnings" count={status.warningCount} color="amber" />
                        <StatCard icon={<Info className="text-blue-500" />} label="Missend" count={status.missingDataCount} color="blue" />
                        <StatCard icon={<AlertCircle className="text-red-500" />} label="Fouten" count={status.errorCount} color="red" />
                    </div>

                    {/* Results Explorer */}
                    <div className="space-y-6">
                        <div className="flex bg-slate-100 dark:bg-slate-900/50 p-1.5 rounded-2xl overflow-x-auto gap-1">
                            <FilterTab active={resultFilter === 'all'} label="Alles" count={status.processed} onClick={() => setResultFilter('all')} />
                            <FilterTab active={resultFilter === 'success'} label="Success" count={status.successCount} onClick={() => setResultFilter('success')} color="green" />
                            <FilterTab active={resultFilter === 'created'} label="Nieuw" count={status.createdCount || 0} onClick={() => setResultFilter('created')} color="purple" />
                            <FilterTab active={resultFilter === 'warnings'} label="Warnings" count={status.warningCount} onClick={() => setResultFilter('warnings')} color="amber" />
                            <FilterTab active={resultFilter === 'missing'} label="Missend" count={status.missingDataCount} onClick={() => setResultFilter('missing')} color="blue" />
                            <FilterTab active={resultFilter === 'errors'} label="Errors" count={status.errorCount} onClick={() => setResultFilter('errors')} color="red" />
                            <FilterTab active={resultFilter === 'excluded'} label="Excluded" count={status.excludedCount} onClick={() => setResultFilter('excluded')} color="slate" />
                        </div>

                        <div className="bg-white dark:bg-slate-800 rounded-2xl ring-1 ring-slate-200 dark:ring-slate-700/50 overflow-hidden">
                            <div className="max-h-[30rem] overflow-y-auto custom-scrollbar p-1">
                                <ResultsList filter={resultFilter} status={status} />
                            </div>
                        </div>
                    </div>
                </section>
            )}

            {/* Documentation Alert */}
            <div className="bg-gradient-to-br from-indigo-500/5 to-purple-500/5 p-8 rounded-[2.5rem] border border-indigo-500/10 dark:border-white/5 flex gap-6 items-start">
                <div className="p-3 bg-indigo-500/10 rounded-2xl text-indigo-500 shrink-0">
                    <Info className="h-6 w-6" />
                </div>
                <div className="space-y-2">
                    <h4 className="font-bold dark:text-white">Hoe werkt de Azure Synchronisatie?</h4>
                    <p className="text-sm text-slate-600 dark:text-slate-400 leading-relaxed">
                        Dit proces koppelt de Microsoft 365 groepen van Salve Mundi aan de commissies in deze portal. 
                        Tevens worden verloopdata van lidmaatschappen en andere profielgegevens ververst op basis van Azure AD attributes. 
                        <strong>Let op:</strong> Dit heeft invloed op wie toegang heeft tot de Beheer-secties en commissie-rechten.
                    </p>
                </div>
            </div>
        </div>
    );
}

function StatCard({ icon, label, count, color }: { icon: React.ReactNode; label: string; count: number; color: string }) {
    const colorClasses: Record<string, string> = {
        green: 'border-green-500/10 bg-green-500/5',
        amber: 'border-amber-500/10 bg-amber-500/5',
        blue: 'border-blue-500/10 bg-blue-500/5',
        red: 'border-red-500/10 bg-red-500/5',
        purple: 'border-purple-500/10 bg-purple-500/5',
    };

    return (
        <div className={`p-6 rounded-3xl border transition-all hover:scale-[1.02] duration-300 ${colorClasses[color] || ''}`}>
            <div className="flex items-center gap-3 mb-2">
                {icon}
                <span className="text-xs font-bold text-slate-500 uppercase tracking-widest">{label}</span>
            </div>
            <div className="text-3xl font-black dark:text-white">{count}</div>
        </div>
    );
}

function FilterTab({ active, label, count, onClick, color = 'indigo' }: { active: boolean; label: string; count: number; onClick: () => void; color?: string }) {
    const colorVariants: Record<string, string> = {
        indigo: 'bg-indigo-500 text-white',
        green: 'bg-green-500 text-white',
        amber: 'bg-amber-500 text-white',
        blue: 'bg-blue-500 text-white',
        red: 'bg-red-500 text-white',
        slate: 'bg-slate-500 text-white',
        purple: 'bg-purple-500 text-white',
    };

    return (
        <button
            onClick={onClick}
            className={`px-5 py-2.5 rounded-xl text-sm font-bold transition-all whitespace-nowrap flex items-center gap-2 ${
                active 
                    ? `${colorVariants[color]} shadow-lg` 
                    : 'text-slate-500 dark:text-slate-400 hover:bg-slate-200 dark:hover:bg-white/5'
            }`}
        >
            {label}
            <span className={`px-2 py-0.5 rounded-full text-[10px] font-black ${active ? 'bg-white/20' : 'bg-slate-200 dark:bg-white/10'}`}>
                {count}
            </span>
        </button>
    );
}

function ResultsList({ filter, status }: { filter: string; status: SyncStatus }) {
    let items: React.ReactNode[] = [];

    if (filter === 'all' || filter === 'success') {
        items.push(...status.successfulUsers.map((u, i) => (
            <ResultRow key={`s-${i}`} email={u.email} type="success" />
        )));
    }
    if (filter === 'all' || filter === 'created') {
        items.push(...(status.createdUsers || []).map((u, i) => (
            <ResultRow key={`c-${i}`} email={u.email} type="success" message="Nieuw lid aangemaakt" />
        )));
    }
    if (filter === 'all' || filter === 'warnings') {
        items.push(...status.warnings.map((w, i) => (
            <ResultRow key={`w-${i}`} email={w.email} message={w.message} type="warning" />
        )));
    }
    if (filter === 'all' || filter === 'missing') {
        items.push(...status.missingData.map((m, i) => (
            <ResultRow key={`m-${i}`} email={m.email} message={m.reason} type="info" />
        )));
    }
    if (filter === 'all' || filter === 'errors') {
        items.push(...status.errors.map((e, i) => (
            <ResultRow key={`e-${i}`} email={e.email} message={e.message} type="error" />
        )));
    }
    if (filter === 'all' || filter === 'excluded') {
        items.push(...status.excludedUsers.map((u, i) => (
            <ResultRow key={`ex-${i}`} email={u.email} type="excluded" />
        )));
    }

    if (items.length === 0) {
        return (
            <div className="flex flex-col items-center justify-center p-20 text-slate-400">
                <Users className="h-12 w-12 mb-4 opacity-20" />
                <p className="font-medium">Geen resultaten gevonden voor dit filter.</p>
            </div>
        );
    }

    return <div className="divide-y divide-slate-200 dark:divide-white/5">{items}</div>;
}

function ResultRow({ email, message, type }: { email: string; message?: string; type: 'success' | 'warning' | 'error' | 'info' | 'excluded' }) {
    const icons = {
        success: <CheckCircle className="h-4 w-4 text-green-500" />,
        warning: <AlertTriangle className="h-4 w-4 text-amber-500" />,
        error: <X className="h-4 w-4 text-red-500" />,
        info: <Info className="h-4 w-4 text-blue-500" />,
        excluded: <Users className="h-4 w-4 text-slate-400" />,
    };

    return (
        <div className="p-4 flex items-start gap-4 hover:bg-slate-100 dark:hover:bg-white/5 transition-colors">
            <div className="mt-0.5">{icons[type]}</div>
            <div className="min-w-0">
                <div className="text-sm font-bold dark:text-white truncate">{email}</div>
                {message && <div className="text-xs text-slate-500 dark:text-slate-400 mt-1">{message}</div>}
            </div>
            <div className="ml-auto text-[10px] font-black uppercase tracking-widest text-slate-300 dark:text-slate-600">
                {type}
            </div>
        </div>
    );
}

'use client';

import { useState, useCallback } from 'react';
import { Users, Heart, FileText, Calendar, Download, Mail, Plus, Trash2, Edit, Save, X, Search, Bell, ChevronDown, ChevronUp, Loader2, LayoutGrid, List, AlertCircle, Eye, EyeOff } from 'lucide-react';
import { format } from 'date-fns';
import { nl } from 'date-fns/locale';
import type { IntroBlog, IntroPlanningItem } from '@salvemundi/validations';
import {
    getIntroSignups,
    getIntroParentSignups,
    deleteIntroSignup,
    deleteIntroParentSignup,
    getIntroBlogs,
    upsertIntroBlog,
    deleteIntroBlog,
    getIntroPlanning,
    upsertIntroPlanning,
    deleteIntroPlanning,
    toggleIntroVisibility,
    sendIntroCustomNotification,
} from '@/server/actions/admin-intro.actions';

type TabType = 'signups' | 'parents' | 'blogs' | 'planning';

type IntroSignupRow = {
    id: number;
    first_name: string;
    last_name: string;
    email: string;
    phone_number: string;
    date_of_birth?: string;
    favorite_gif?: string;
    date_created?: string;
};

type IntroParentRow = {
    id: number;
    first_name?: string;
    last_name?: string;
    email?: string;
    phone_number?: string;
    motivation?: string;
    date_created?: string;
};

interface Props {
    initialSignups: IntroSignupRow[];
    initialParents: IntroParentRow[];
    initialBlogs: IntroBlog[];
    initialPlanning: IntroPlanningItem[];
    initialIntroVisible: boolean;
}

export default function IntroManagementIsland({ initialSignups, initialParents, initialBlogs, initialPlanning, initialIntroVisible }: Props) {
    const [activeTab, setActiveTab] = useState<TabType>('signups');

    // Data
    const [signups, setSignups] = useState(initialSignups);
    const [parents, setParents] = useState(initialParents);
    const [blogs, setBlogs] = useState(initialBlogs);
    const [planning, setPlanning] = useState(initialPlanning);
    const [introVisible, setIntroVisible] = useState(initialIntroVisible);

    // Search state
    const [signupSearch, setSignupSearch] = useState('');
    const [parentSearch, setParentSearch] = useState('');

    // Expand rows
    const [expandedSignups, setExpandedSignups] = useState<number[]>([]);
    const [expandedParents, setExpandedParents] = useState<number[]>([]);

    // Blog editing
    const [editingBlog, setEditingBlog] = useState<Partial<IntroBlog> | null>(null);
    const [savingBlog, setSavingBlog] = useState(false);

    // Planning editing
    const [editingPlanning, setEditingPlanning] = useState<Partial<IntroPlanningItem> | null>(null);
    const [savingPlanning, setSavingPlanning] = useState(false);
    const [planningView, setPlanningView] = useState<'calendar' | 'list'>('list');

    // Loading states
    const [deletingSignup, setDeletingSignup] = useState<number | null>(null);
    const [deletingParent, setDeletingParent] = useState<number | null>(null);
    const [deletingBlog, setDeletingBlog] = useState<number | null>(null);
    const [deletingPlanning, setDeletingPlanning] = useState<number | null>(null);
    const [togglingVisibility, setTogglingVisibility] = useState(false);

    // Notification modal
    const [showNotifModal, setShowNotifModal] = useState(false);
    const [notif, setNotif] = useState({ title: '', body: '', includeParents: false });
    const [sendingNotif, setSendingNotif] = useState(false);

    // Filtered data
    const filteredSignups = signups.filter(s => {
        if (!signupSearch) return true;
        const q = signupSearch.toLowerCase();
        return `${s.first_name} ${s.last_name}`.toLowerCase().includes(q) ||
            s.email.toLowerCase().includes(q) || s.phone_number.includes(q);
    });

    const filteredParents = parents.filter(p => {
        if (!parentSearch) return true;
        const q = parentSearch.toLowerCase();
        return `${p.first_name || ''} ${p.last_name || ''}`.toLowerCase().includes(q) ||
            (p.email || '').toLowerCase().includes(q);
    });

    // Reload helpers
    const reloadSignups = useCallback(async () => setSignups(await getIntroSignups()), []);
    const reloadParents = useCallback(async () => setParents(await getIntroParentSignups()), []);
    const reloadBlogs = useCallback(async () => setBlogs(await getIntroBlogs()), []);
    const reloadPlanning = useCallback(async () => setPlanning(await getIntroPlanning()), []);

    const handleDeleteSignup = async (id: number) => {
        if (!confirm('Weet je zeker dat je deze aanmelding wilt verwijderen?')) return;
        setDeletingSignup(id);
        const res = await deleteIntroSignup(id);
        if (res.success) setSignups(prev => prev.filter(s => s.id !== id));
        else alert(res.error || 'Verwijderen mislukt');
        setDeletingSignup(null);
    };

    const handleDeleteParent = async (id: number) => {
        if (!confirm('Weet je zeker dat je deze aanmelding wilt verwijderen?')) return;
        setDeletingParent(id);
        const res = await deleteIntroParentSignup(id);
        if (res.success) setParents(prev => prev.filter(p => p.id !== id));
        else alert(res.error || 'Verwijderen mislukt');
        setDeletingParent(null);
    };

    const handleSaveBlog = async () => {
        if (!editingBlog) return;
        if (!editingBlog.title || !editingBlog.content) { alert('Vul titel en content in.'); return; }
        setSavingBlog(true);
        const res = await upsertIntroBlog(editingBlog);
        if (res.success) { await reloadBlogs(); setEditingBlog(null); }
        else alert(res.error || 'Opslaan mislukt');
        setSavingBlog(false);
    };

    const handleDeleteBlog = async (id: number) => {
        if (!confirm('Weet je zeker dat je deze blog wilt verwijderen?')) return;
        setDeletingBlog(id);
        const res = await deleteIntroBlog(id);
        if (res.success) setBlogs(prev => prev.filter(b => b.id !== id));
        else alert(res.error || 'Verwijderen mislukt');
        setDeletingBlog(null);
    };

    const handleSavePlanning = async () => {
        if (!editingPlanning) return;
        if (!editingPlanning.date || !editingPlanning.time_start || !editingPlanning.title || !editingPlanning.description) {
            alert('Datum, starttijd, titel en beschrijving zijn verplicht.');
            return;
        }
        setSavingPlanning(true);
        const res = await upsertIntroPlanning(editingPlanning);
        if (res.success) { await reloadPlanning(); setEditingPlanning(null); }
        else alert(res.error || 'Opslaan mislukt');
        setSavingPlanning(false);
    };

    const handleDeletePlanning = async (id: number) => {
        if (!id || !confirm('Weet je zeker dat je dit planning item wilt verwijderen?')) return;
        setDeletingPlanning(id);
        const res = await deleteIntroPlanning(id);
        if (res.success) setPlanning(prev => prev.filter(p => p.id !== id));
        else alert(res.error || 'Verwijderen mislukt');
        setDeletingPlanning(null);
    };

    const handleToggleVisibility = async () => {
        setTogglingVisibility(true);
        const res = await toggleIntroVisibility(introVisible);
        if (res.success) setIntroVisible(res.show ?? !introVisible);
        else alert(res.error || 'Bijwerken mislukt');
        setTogglingVisibility(false);
    };

    const handleSendNotification = async () => {
        if (!notif.title || !notif.body) { alert('Vul een titel en bericht in'); return; }
        setSendingNotif(true);
        const res = await sendIntroCustomNotification(notif.title, notif.body, notif.includeParents);
        if (res.success) {
            alert(`Notificatie verstuurd naar ${res.sent ?? 0} gebruiker(s)!`);
            setShowNotifModal(false);
            setNotif({ title: '', body: '', includeParents: false });
        } else alert(res.error || 'Verzenden mislukt');
        setSendingNotif(false);
    };

    const exportSignupsToCSV = () => {
        const rows = [
            ['Voornaam', 'Tussenvoegsel', 'Achternaam', 'Email', 'Telefoon', 'Geboortedatum', 'Favoriete GIF', 'Aangemeld op'],
            ...signups.map(s => [
                s.first_name, s.last_name, s.email, s.phone_number,
                s.date_of_birth || '', s.favorite_gif || '',
            ])
        ];
        const csv = rows.map(r => r.map(c => `"${String(c).replace(/"/g, '""')}"`).join(',')).join('\n');
        const blob = new Blob([csv], { type: 'text/csv;charset=utf-8;' });
        const url = URL.createObjectURL(blob);
        const a = document.createElement('a');
        a.href = url;
        a.download = `intro-aanmeldingen-${format(new Date(), 'yyyy-MM-dd')}.csv`;
        a.click();
    };

    const exportParentsToCSV = () => {
        const rows = [
            ['Voornaam', 'Achternaam', 'Email', 'Telefoon', 'Motivatie', 'Aangemeld op'],
            ...parents.map(p => [
                p.first_name || '', p.last_name || '', p.email || '', p.phone_number || '',
                p.motivation || '',
            ])
        ];
        const csv = rows.map(r => r.map(c => `"${String(c).replace(/"/g, '""')}"`).join(',')).join('\n');
        const blob = new Blob([csv], { type: 'text/csv;charset=utf-8;' });
        const url = URL.createObjectURL(blob);
        const a = document.createElement('a');
        a.href = url;
        a.download = `intro-ouders-${format(new Date(), 'yyyy-MM-dd')}.csv`;
        a.click();
    };

    const tabClass = (tab: TabType) => `flex items-center gap-2 px-5 py-3 font-semibold text-sm transition-colors border-b-2 ${
        activeTab === tab
            ? 'text-[var(--theme-purple)] border-[var(--theme-purple)]'
            : 'text-[var(--text-muted)] border-transparent hover:text-[var(--text-main)]'
    }`;

    return (
        <div className="container mx-auto px-4 py-8 max-w-7xl">
            {/* Visibility Toggle */}
            <div className="flex items-center justify-between mb-6 bg-[var(--bg-card)] rounded-2xl px-6 py-4 ring-1 ring-[var(--border-color)]">
                <div>
                    <p className="font-bold text-[var(--text-main)]">Intro zichtbaar voor publiek</p>
                    <p className="text-xs text-[var(--text-muted)] mt-0.5">Toggle of de intro sectie en inschrijfpagina zichtbaar zijn.</p>
                </div>
                <button
                    onClick={handleToggleVisibility}
                    disabled={togglingVisibility}
                    className={`relative w-14 h-7 rounded-full transition-colors disabled:opacity-50 ${introVisible ? 'bg-[var(--theme-purple)]' : 'bg-[var(--border-color)]'}`}
                >
                    {togglingVisibility
                        ? <Loader2 className="h-4 w-4 absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 animate-spin text-white" />
                        : <span className={`absolute top-1 w-5 h-5 bg-white rounded-full shadow transition-all ${introVisible ? 'left-8' : 'left-1'}`} />
                    }
                </button>
            </div>

            {/* Tabs */}
            <div className="flex flex-wrap gap-0 border-b border-[var(--border-color)] mb-8">
                <button onClick={() => setActiveTab('signups')} className={tabClass('signups')}>
                    <Users className="h-4 w-4" /> Aanmeldingen ({signups.length})
                </button>
                <button onClick={() => setActiveTab('parents')} className={tabClass('parents')}>
                    <Heart className="h-4 w-4" /> Ouders ({parents.length})
                </button>
                <button onClick={() => setActiveTab('blogs')} className={tabClass('blogs')}>
                    <FileText className="h-4 w-4" /> Blogs ({blogs.length})
                </button>
                <button onClick={() => setActiveTab('planning')} className={tabClass('planning')}>
                    <Calendar className="h-4 w-4" /> Planning ({planning.length})
                </button>
            </div>

            {/* ── Signups Tab ── */}
            {activeTab === 'signups' && (
                <div>
                    <div className="flex flex-col sm:flex-row gap-3 mb-5">
                        <div className="flex-1 relative">
                            <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-[var(--text-muted)]" />
                            <input
                                type="text"
                                placeholder="Zoek op naam, email of telefoon..."
                                value={signupSearch}
                                onChange={e => setSignupSearch(e.target.value)}
                                className="w-full pl-9 pr-4 py-2.5 rounded-xl bg-[var(--bg-card)] border border-[var(--border-color)] text-[var(--text-main)] text-sm focus:ring-2 focus:ring-[var(--theme-purple)] focus:outline-none"
                            />
                        </div>
                        <button onClick={() => {
                            const emails = signups.map(s => s.email).join(',');
                            window.location.href = `mailto:?bcc=${emails}&subject=Intro${encodeURIComponent(' Aanmeldingen')}`;
                        }} className="flex items-center gap-2 px-4 py-2.5 bg-blue-600 text-white rounded-xl text-sm font-bold hover:opacity-90 transition">
                            <Mail className="h-4 w-4" /> Mail BCC
                        </button>
                        <button onClick={exportSignupsToCSV} className="flex items-center gap-2 px-4 py-2.5 bg-[var(--theme-success,_#22c55e)] text-white rounded-xl text-sm font-bold hover:opacity-90 transition">
                            <Download className="h-4 w-4" /> Export CSV
                        </button>
                    </div>

                    <div className="bg-[var(--bg-card)] rounded-2xl ring-1 ring-[var(--border-color)] overflow-hidden">
                        {filteredSignups.length === 0 ? (
                            <div className="py-16 text-center text-[var(--text-muted)]">
                                <AlertCircle className="h-10 w-10 mx-auto mb-3 opacity-30" />
                                <p>Geen aanmeldingen gevonden</p>
                            </div>
                        ) : (
                            <table className="w-full text-sm">
                                <thead className="bg-[var(--bg-card-soft,_#f8f8f8)] border-b border-[var(--border-color)]">
                                    <tr>
                                        <th className="px-5 py-3 text-left font-semibold text-[var(--text-muted)] text-xs uppercase tracking-wider">Naam</th>
                                        <th className="px-5 py-3 text-left font-semibold text-[var(--text-muted)] text-xs uppercase tracking-wider hidden sm:table-cell">Email</th>
                                        <th className="px-5 py-3 text-left font-semibold text-[var(--text-muted)] text-xs uppercase tracking-wider hidden md:table-cell">Telefoon</th>
                                        <th className="px-5 py-3 text-right font-semibold text-[var(--text-muted)] text-xs uppercase tracking-wider">Acties</th>
                                    </tr>
                                </thead>
                                <tbody className="divide-y divide-[var(--border-color)]">
                                    {filteredSignups.map(s => (
                                        <>
                                            <tr key={s.id} className="hover:bg-[var(--bg-card-soft,_#f8f8f8)] transition-colors">
                                                <td className="px-5 py-3">
                                                    <button
                                                        onClick={() => setExpandedSignups(prev => prev.includes(s.id) ? prev.filter(x => x !== s.id) : [...prev, s.id])}
                                                        className="flex items-center gap-1.5 text-[var(--text-main)] font-medium hover:text-[var(--theme-purple)]"
                                                    >
                                                        {expandedSignups.includes(s.id) ? <ChevronUp className="h-3.5 w-3.5" /> : <ChevronDown className="h-3.5 w-3.5" />}
                                                        {s.first_name} {s.last_name}
                                                    </button>
                                                </td>
                                                <td className="px-5 py-3 text-[var(--text-muted)] hidden sm:table-cell">{s.email}</td>
                                                <td className="px-5 py-3 text-[var(--text-muted)] hidden md:table-cell">{s.phone_number}</td>
                                                <td className="px-5 py-3 text-right">
                                                    <button
                                                        onClick={() => handleDeleteSignup(s.id)}
                                                        disabled={deletingSignup === s.id}
                                                        className="p-1.5 text-red-500 hover:bg-red-50 dark:hover:bg-red-900/20 rounded-lg transition"
                                                    >
                                                        {deletingSignup === s.id ? <Loader2 className="h-4 w-4 animate-spin" /> : <Trash2 className="h-4 w-4" />}
                                                    </button>
                                                </td>
                                            </tr>
                                            {expandedSignups.includes(s.id) && (
                                                <tr key={`${s.id}-expanded`} className="bg-[var(--bg-card-soft,_#f8f8f8)]">
                                                    <td colSpan={5} className="px-8 py-3 text-sm text-[var(--text-muted)] space-y-1">
                                                        {s.date_of_birth && <p><strong>Geboortedatum:</strong> {s.date_of_birth}</p>}
                                                        {s.favorite_gif && <p><strong>Favoriete GIF:</strong> <a href={s.favorite_gif} target="_blank" rel="noopener noreferrer" className="text-[var(--theme-purple)] hover:underline">Bekijk</a></p>}
                                                        <p className="block sm:hidden"><strong>Email:</strong> {s.email}</p>
                                                    </td>
                                                </tr>
                                            )}
                                        </>
                                    ))}
                                </tbody>
                            </table>
                        )}
                    </div>
                </div>
            )}

            {/* ── Parents Tab ── */}
            {activeTab === 'parents' && (
                <div>
                    <div className="flex flex-col sm:flex-row gap-3 mb-5">
                        <div className="flex-1 relative">
                            <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-[var(--text-muted)]" />
                            <input
                                type="text"
                                placeholder="Zoek op naam of email..."
                                value={parentSearch}
                                onChange={e => setParentSearch(e.target.value)}
                                className="w-full pl-9 pr-4 py-2.5 rounded-xl bg-[var(--bg-card)] border border-[var(--border-color)] text-[var(--text-main)] text-sm focus:ring-2 focus:ring-[var(--theme-purple)] focus:outline-none"
                            />
                        </div>
                        <button onClick={() => setShowNotifModal(true)} className="flex items-center gap-2 px-4 py-2.5 bg-[var(--theme-purple)] text-white rounded-xl text-sm font-bold hover:opacity-90 transition">
                            <Bell className="h-4 w-4" /> Notificatie sturen
                        </button>
                        <button onClick={exportParentsToCSV} className="flex items-center gap-2 px-4 py-2.5 bg-[var(--theme-success,_#22c55e)] text-white rounded-xl text-sm font-bold hover:opacity-90 transition">
                            <Download className="h-4 w-4" /> Export CSV
                        </button>
                    </div>

                    <div className="bg-[var(--bg-card)] rounded-2xl ring-1 ring-[var(--border-color)] overflow-hidden">
                        {filteredParents.length === 0 ? (
                            <div className="py-16 text-center text-[var(--text-muted)]">
                                <AlertCircle className="h-10 w-10 mx-auto mb-3 opacity-30" />
                                <p>Geen ouder-aanmeldingen gevonden</p>
                            </div>
                        ) : (
                            <table className="w-full text-sm">
                                <thead className="bg-[var(--bg-card-soft,_#f8f8f8)] border-b border-[var(--border-color)]">
                                    <tr>
                                        <th className="px-5 py-3 text-left font-semibold text-[var(--text-muted)] text-xs uppercase tracking-wider">Naam</th>
                                        <th className="px-5 py-3 text-left font-semibold text-[var(--text-muted)] text-xs uppercase tracking-wider hidden sm:table-cell">Email</th>
                                        <th className="px-5 py-3 text-left font-semibold text-[var(--text-muted)] text-xs uppercase tracking-wider hidden md:table-cell">Telefoon</th>
                                        <th className="px-5 py-3 text-right font-semibold text-[var(--text-muted)] text-xs uppercase tracking-wider">Acties</th>
                                    </tr>
                                </thead>
                                <tbody className="divide-y divide-[var(--border-color)]">
                                    {filteredParents.map(p => (
                                        <>
                                            <tr key={p.id} className="hover:bg-[var(--bg-card-soft,_#f8f8f8)] transition-colors">
                                                <td className="px-5 py-3">
                                                    <button
                                                        onClick={() => setExpandedParents(prev => prev.includes(p.id) ? prev.filter(x => x !== p.id) : [...prev, p.id])}
                                                        className="flex items-center gap-1.5 text-[var(--text-main)] font-medium hover:text-[var(--theme-purple)]"
                                                    >
                                                        {expandedParents.includes(p.id) ? <ChevronUp className="h-3.5 w-3.5" /> : <ChevronDown className="h-3.5 w-3.5" />}
                                                        {p.first_name} {p.last_name}
                                                    </button>
                                                </td>
                                                <td className="px-5 py-3 text-[var(--text-muted)] hidden sm:table-cell">{p.email}</td>
                                                <td className="px-5 py-3 text-[var(--text-muted)] hidden md:table-cell">{p.phone_number}</td>
                                                <td className="px-5 py-3 text-right">
                                                    <button
                                                        onClick={() => handleDeleteParent(p.id)}
                                                        disabled={deletingParent === p.id}
                                                        className="p-1.5 text-red-500 hover:bg-red-50 dark:hover:bg-red-900/20 rounded-lg transition"
                                                    >
                                                        {deletingParent === p.id ? <Loader2 className="h-4 w-4 animate-spin" /> : <Trash2 className="h-4 w-4" />}
                                                    </button>
                                                </td>
                                            </tr>
                                            {expandedParents.includes(p.id) && p.motivation && (
                                                <tr key={`${p.id}-expanded`} className="bg-[var(--bg-card-soft,_#f8f8f8)]">
                                                    <td colSpan={4} className="px-8 py-3 text-sm text-[var(--text-muted)]">
                                                        <strong>Motivatie:</strong> {p.motivation}
                                                    </td>
                                                </tr>
                                            )}
                                        </>
                                    ))}
                                </tbody>
                            </table>
                        )}
                    </div>
                </div>
            )}

            {/* ── Blogs Tab ── */}
            {activeTab === 'blogs' && (
                <div>
                    {/* Blog Form */}
                    {editingBlog !== null ? (
                        <div className="bg-[var(--bg-card)] rounded-2xl ring-1 ring-[var(--border-color)] p-6 mb-6">
                            <h3 className="font-bold text-lg text-[var(--text-main)] mb-5">
                                {editingBlog.id ? 'Blog Bewerken' : 'Nieuwe Blog'}
                            </h3>
                            <div className="space-y-4">
                                <Field label="Titel *">
                                    <input type="text" value={editingBlog.title || ''} onChange={e => setEditingBlog({ ...editingBlog, title: e.target.value })} className={inputClass} />
                                </Field>
                                <Field label="Slug">
                                    <input type="text" value={editingBlog.slug || ''} onChange={e => setEditingBlog({ ...editingBlog, slug: e.target.value })} className={inputClass} />
                                </Field>
                                <Field label="Excerpt">
                                    <textarea value={editingBlog.excerpt || ''} onChange={e => setEditingBlog({ ...editingBlog, excerpt: e.target.value })} rows={2} className={inputClass} />
                                </Field>
                                <Field label="Content *">
                                    <textarea value={editingBlog.content || ''} onChange={e => setEditingBlog({ ...editingBlog, content: e.target.value })} rows={6} className={inputClass} />
                                </Field>
                                <Field label="Type">
                                    <select value={editingBlog.blog_type || 'update'} onChange={e => setEditingBlog({ ...editingBlog, blog_type: e.target.value as any })} className={inputClass}>
                                        <option value="update">Update</option>
                                        <option value="pictures">Foto's</option>
                                        <option value="event">Event</option>
                                        <option value="announcement">Aankondiging</option>
                                    </select>
                                </Field>
                                <div className="flex items-center gap-2">
                                    <input type="checkbox" id="blog-published" checked={editingBlog.is_published || false} onChange={e => setEditingBlog({ ...editingBlog, is_published: e.target.checked })} className="rounded" />
                                    <label htmlFor="blog-published" className="text-sm font-medium text-[var(--text-main)]">Gepubliceerd</label>
                                </div>
                                <div className="flex gap-3 pt-2">
                                    <button onClick={handleSaveBlog} disabled={savingBlog} className="flex items-center gap-2 px-5 py-2.5 bg-[var(--theme-purple)] text-white rounded-xl font-bold text-sm hover:opacity-90 transition disabled:opacity-50">
                                        {savingBlog ? <Loader2 className="h-4 w-4 animate-spin" /> : <Save className="h-4 w-4" />} Opslaan
                                    </button>
                                    <button onClick={() => setEditingBlog(null)} className="px-5 py-2.5 rounded-xl text-sm font-bold text-[var(--text-muted)] hover:bg-[var(--border-color)] transition">Annuleren</button>
                                </div>
                            </div>
                        </div>
                    ) : (
                        <button onClick={() => setEditingBlog({ title: '', content: '', blog_type: 'update', is_published: false })} className="flex items-center gap-2 px-5 py-2.5 bg-[var(--theme-purple)] text-white rounded-xl font-bold text-sm hover:opacity-90 transition mb-6">
                            <Plus className="h-4 w-4" /> Nieuwe Blog
                        </button>
                    )}

                    <div className="grid gap-4">
                        {blogs.map(blog => (
                            <div key={blog.id} className="bg-[var(--bg-card)] rounded-2xl ring-1 ring-[var(--border-color)] p-5 flex items-start justify-between gap-4">
                                <div className="flex-1 min-w-0">
                                    <div className="flex items-center gap-2 mb-1">
                                        <h4 className="font-bold text-[var(--text-main)] truncate">{blog.title}</h4>
                                        <span className={`text-[10px] font-bold uppercase px-2 py-0.5 rounded-full ${blog.is_published ? 'bg-green-100 text-green-700' : 'bg-gray-100 text-gray-500'}`}>
                                            {blog.is_published ? 'Gepubliceerd' : 'Concept'}
                                        </span>
                                    </div>
                                    <p className="text-xs text-[var(--text-muted)]">{blog.blog_type}</p>
                                    {blog.excerpt && <p className="text-sm text-[var(--text-muted)] mt-1 line-clamp-2">{blog.excerpt}</p>}
                                </div>
                                <div className="flex gap-2 flex-shrink-0">
                                    <button onClick={() => setEditingBlog(blog)} className="p-2 text-[var(--theme-purple)] hover:bg-[var(--theme-purple)]/10 rounded-lg transition"><Edit className="h-4 w-4" /></button>
                                    <button onClick={() => handleDeleteBlog(blog.id!)} disabled={deletingBlog === blog.id} className="p-2 text-red-500 hover:bg-red-50 dark:hover:bg-red-900/20 rounded-lg transition">
                                        {deletingBlog === blog.id ? <Loader2 className="h-4 w-4 animate-spin" /> : <Trash2 className="h-4 w-4" />}
                                    </button>
                                </div>
                            </div>
                        ))}
                        {blogs.length === 0 && (
                            <div className="py-16 text-center text-[var(--text-muted)]">
                                <FileText className="h-10 w-10 mx-auto mb-3 opacity-30" />
                                <p>Nog geen blogs aangemaakt</p>
                            </div>
                        )}
                    </div>
                </div>
            )}

            {/* ── Planning Tab ── */}
            {activeTab === 'planning' && (
                <div>
                    <div className="flex items-center justify-between mb-6">
                        {editingPlanning === null && (
                            <button onClick={() => setEditingPlanning({ date: '', time_start: '', title: '', description: '' })} className="flex items-center gap-2 px-5 py-2.5 bg-[var(--theme-purple)] text-white rounded-xl font-bold text-sm hover:opacity-90 transition">
                                <Plus className="h-4 w-4" /> Nieuw Item
                            </button>
                        )}
                        <div className="flex gap-1 bg-[var(--bg-card)] ring-1 ring-[var(--border-color)] rounded-xl p-1 ml-auto">
                            <button onClick={() => setPlanningView('list')} className={`flex items-center gap-1.5 px-3 py-1.5 rounded-lg text-sm font-bold transition ${planningView === 'list' ? 'bg-[var(--theme-purple)] text-white' : 'text-[var(--text-muted)] hover:text-[var(--text-main)]'}`}>
                                <List className="h-4 w-4" /> Lijst
                            </button>
                            <button onClick={() => setPlanningView('calendar')} className={`flex items-center gap-1.5 px-3 py-1.5 rounded-lg text-sm font-bold transition ${planningView === 'calendar' ? 'bg-[var(--theme-purple)] text-white' : 'text-[var(--text-muted)] hover:text-[var(--text-main)]'}`}>
                                <LayoutGrid className="h-4 w-4" /> Kalender
                            </button>
                        </div>
                    </div>

                    {/* Planning Form */}
                    {editingPlanning !== null && (
                        <div className="bg-[var(--bg-card)] rounded-2xl ring-1 ring-[var(--border-color)] p-6 mb-6">
                            <h3 className="font-bold text-lg text-[var(--text-main)] mb-5">
                                {editingPlanning.id ? 'Planning Bewerken' : 'Nieuw Planning Item'}
                            </h3>
                            <div className="space-y-4">
                                <Field label="Datum *">
                                    <input type="date" value={editingPlanning.date || ''} onChange={e => setEditingPlanning({ ...editingPlanning, date: e.target.value })} className={inputClass} />
                                </Field>
                                <div className="grid grid-cols-2 gap-4">
                                    <Field label="Starttijd *">
                                        <input type="time" value={editingPlanning.time_start || ''} onChange={e => setEditingPlanning({ ...editingPlanning, time_start: e.target.value })} className={inputClass} />
                                    </Field>
                                    <Field label="Eindtijd">
                                        <input type="time" value={editingPlanning.time_end || ''} onChange={e => setEditingPlanning({ ...editingPlanning, time_end: e.target.value })} className={inputClass} />
                                    </Field>
                                </div>
                                <Field label="Titel *">
                                    <input type="text" value={editingPlanning.title || ''} onChange={e => setEditingPlanning({ ...editingPlanning, title: e.target.value })} className={inputClass} />
                                </Field>
                                <Field label="Beschrijving *">
                                    <textarea value={editingPlanning.description || ''} onChange={e => setEditingPlanning({ ...editingPlanning, description: e.target.value })} rows={3} className={inputClass} />
                                </Field>
                                <Field label="Locatie">
                                    <input type="text" value={editingPlanning.location || ''} onChange={e => setEditingPlanning({ ...editingPlanning, location: e.target.value })} className={inputClass} />
                                </Field>
                                <div className="flex gap-3 pt-2">
                                    <button onClick={handleSavePlanning} disabled={savingPlanning} className="flex items-center gap-2 px-5 py-2.5 bg-[var(--theme-purple)] text-white rounded-xl font-bold text-sm hover:opacity-90 transition disabled:opacity-50">
                                        {savingPlanning ? <Loader2 className="h-4 w-4 animate-spin" /> : <Save className="h-4 w-4" />} Opslaan
                                    </button>
                                    <button onClick={() => setEditingPlanning(null)} className="px-5 py-2.5 rounded-xl text-sm font-bold text-[var(--text-muted)] hover:bg-[var(--border-color)] transition">Annuleren</button>
                                </div>
                            </div>
                        </div>
                    )}

                    {/* List view */}
                    {planningView === 'list' && (
                        <div className="grid gap-3">
                            {planning.map(item => (
                                <div key={item.id} className="bg-[var(--bg-card)] rounded-2xl ring-1 ring-[var(--border-color)] p-5 flex items-start justify-between gap-4">
                                    <div className="flex-1">
                                        <div className="flex items-center gap-2 mb-1">
                                            <span className="text-xs font-bold text-[var(--theme-purple)] uppercase">{item.day || ''}</span>
                                            {item.date && <span className="text-xs text-[var(--text-muted)]">{format(new Date(item.date), 'd MMM yyyy', { locale: nl })}</span>}
                                        </div>
                                        <h4 className="font-bold text-[var(--text-main)]">{item.title}</h4>
                                        <p className="text-xs text-[var(--text-muted)] mt-0.5">{item.time_start}{item.time_end ? ` - ${item.time_end}` : ''}{item.location ? ` · ${item.location}` : ''}</p>
                                        {item.description && <p className="text-sm text-[var(--text-muted)] mt-1">{item.description}</p>}
                                    </div>
                                    <div className="flex gap-2 flex-shrink-0">
                                        <button onClick={() => setEditingPlanning(item)} className="p-2 text-[var(--theme-purple)] hover:bg-[var(--theme-purple)]/10 rounded-lg transition"><Edit className="h-4 w-4" /></button>
                                        <button onClick={() => handleDeletePlanning(item.id!)} disabled={deletingPlanning === item.id} className="p-2 text-red-500 hover:bg-red-50 dark:hover:bg-red-900/20 rounded-lg transition">
                                            {deletingPlanning === item.id ? <Loader2 className="h-4 w-4 animate-spin" /> : <Trash2 className="h-4 w-4" />}
                                        </button>
                                    </div>
                                </div>
                            ))}
                            {planning.length === 0 && (
                                <div className="py-16 text-center text-[var(--text-muted)]">
                                    <Calendar className="h-10 w-10 mx-auto mb-3 opacity-30" />
                                    <p>Geen planning items aangemaakt</p>
                                </div>
                            )}
                        </div>
                    )}

                    {/* Calendar view - day-based grid */}
                    {planningView === 'calendar' && planning.length > 0 && (() => {
                        const dayOrder = ['maandag', 'dinsdag', 'woensdag', 'donderdag', 'vrijdag', 'zaterdag', 'zondag'];
                        const byDay = planning.reduce((acc, item) => {
                            const key = (item.day || 'overig').toLowerCase();
                            if (!acc[key]) acc[key] = [];
                            acc[key].push(item);
                            return acc;
                        }, {} as Record<string, IntroPlanningItem[]>);
                        const sorted = Object.keys(byDay).sort((a, b) => dayOrder.indexOf(a) - dayOrder.indexOf(b));
                        return (
                            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4">
                                {sorted.map(day => (
                                    <div key={day} className="bg-[var(--bg-card)] rounded-2xl ring-1 ring-[var(--border-color)] p-4">
                                        <h3 className="font-black text-[var(--theme-purple)] uppercase text-sm mb-3 capitalize">{day}</h3>
                                        <div className="space-y-2">
                                            {byDay[day].sort((a, b) => (a.time_start || '').localeCompare(b.time_start || '')).map(item => (
                                                <div key={item.id} className="bg-[var(--bg-card-soft,_#f8f8f8)] rounded-xl p-3">
                                                    <div className="flex items-start justify-between gap-1">
                                                        <div>
                                                            <p className="font-bold text-sm text-[var(--text-main)]">{item.title}</p>
                                                            <p className="text-xs text-[var(--text-muted)]">{item.time_start}{item.time_end ? ` - ${item.time_end}` : ''}</p>
                                                        </div>
                                                        <div className="flex gap-1">
                                                            <button onClick={() => setEditingPlanning(item)} className="p-1 text-[var(--theme-purple)] hover:opacity-70 transition"><Edit className="h-3.5 w-3.5" /></button>
                                                            <button onClick={() => handleDeletePlanning(item.id!)} className="p-1 text-red-500 hover:opacity-70 transition"><Trash2 className="h-3.5 w-3.5" /></button>
                                                        </div>
                                                    </div>
                                                </div>
                                            ))}
                                        </div>
                                    </div>
                                ))}
                            </div>
                        );
                    })()}
                </div>
            )}

            {/* Notification Modal */}
            {showNotifModal && (
                <div className="fixed inset-0 bg-black/50 flex items-center justify-center z-50 p-4">
                    <div className="bg-[var(--bg-card)] rounded-2xl shadow-2xl max-w-md w-full p-6">
                        <div className="flex items-center justify-between mb-5">
                            <h3 className="font-bold text-lg text-[var(--text-main)]">Push Notificatie Sturen</h3>
                            <button onClick={() => setShowNotifModal(false)} className="p-2 text-[var(--text-muted)] hover:text-[var(--text-main)] rounded-lg transition"><X className="h-5 w-5" /></button>
                        </div>
                        <div className="space-y-4">
                            <Field label="Titel">
                                <input type="text" value={notif.title} onChange={e => setNotif({ ...notif, title: e.target.value })} placeholder="Notificatie titel" className={inputClass} />
                            </Field>
                            <Field label="Bericht">
                                <textarea value={notif.body} onChange={e => setNotif({ ...notif, body: e.target.value })} rows={4} placeholder="Notificatie bericht" className={inputClass} />
                            </Field>
                            <div className="flex items-center gap-2">
                                <input type="checkbox" id="include-parents" checked={notif.includeParents} onChange={e => setNotif({ ...notif, includeParents: e.target.checked })} className="rounded" />
                                <label htmlFor="include-parents" className="text-sm text-[var(--text-main)]">Verstuur naar Intro Ouders (met account)</label>
                            </div>
                            <div className="bg-yellow-50 dark:bg-yellow-900/20 border border-yellow-200 dark:border-yellow-800 rounded-xl p-3 text-xs text-yellow-700 dark:text-yellow-300">
                                Intro aanmeldingen zijn anoniem; notificaties gaan alleen naar ingelogde Intro Ouders.
                            </div>
                        </div>
                        <div className="flex gap-3 mt-6">
                            <button onClick={handleSendNotification} disabled={sendingNotif || !notif.includeParents} className="flex-1 flex items-center justify-center gap-2 px-5 py-2.5 bg-[var(--theme-purple)] text-white rounded-xl font-bold text-sm hover:opacity-90 transition disabled:opacity-40">
                                {sendingNotif ? <Loader2 className="h-4 w-4 animate-spin" /> : <Bell className="h-4 w-4" />}
                                {sendingNotif ? 'Verzenden...' : 'Versturen'}
                            </button>
                            <button onClick={() => setShowNotifModal(false)} disabled={sendingNotif} className="px-5 py-2.5 rounded-xl text-sm font-bold text-[var(--text-muted)] border border-[var(--border-color)] hover:bg-[var(--border-color)] transition">Annuleren</button>
                        </div>
                    </div>
                </div>
            )}
        </div>
    );
}

const inputClass = 'w-full px-4 py-2.5 rounded-xl bg-[var(--bg-main,_#f4f4f5)] border border-[var(--border-color)] text-[var(--text-main)] text-sm focus:ring-2 focus:ring-[var(--theme-purple)] focus:outline-none transition';

function Field({ label, children }: { label: string; children: React.ReactNode }) {
    return (
        <div className="space-y-1.5">
            <label className="text-xs font-bold uppercase tracking-wider text-[var(--text-muted)]">{label}</label>
            {children}
        </div>
    );
}

'use client';

import { useState, useTransition, useEffect } from 'react';
import { 
    Plus, 
    Settings, 
    Loader2, 
    Beer, 
    ChevronLeft,
    AlertCircle
} from 'lucide-react';
import Link from 'next/link';
import { useRouter } from 'next/navigation';
import { 
    deletePubCrawlSignup, 
    toggleKroegentochtVisibility,
    getPubCrawlSignups
} from '@/server/actions/admin-kroegentocht.actions';

import EventSelector from '@/components/admin/kroegentocht/EventSelector';
import KroegStats from '@/components/admin/kroegentocht/KroegStats';
import SignupList from '@/components/admin/kroegentocht/SignupList';

interface KroegentochtManagementIslandProps {
    initialEvents: any[];
    initialSettings: { show: boolean };
}

export default function KroegentochtManagementIsland({
    initialEvents,
    initialSettings
}: KroegentochtManagementIslandProps) {
    const router = useRouter();
    const [events] = useState(initialEvents);
    const [selectedEvent, setSelectedEvent] = useState<any | null>(
        initialEvents.find(e => new Date(e.date) >= new Date()) || initialEvents[0] || null
    );
    const [signups, setSignups] = useState<any[]>([]);
    const [isLoadingSignups, setIsLoadingSignups] = useState(false);
    const [showPastEvents, setShowPastEvents] = useState(false);
    const [settings, setSettings] = useState(initialSettings);
    const [error, setError] = useState<string | null>(null);
    const [isPending, startTransition] = useTransition();

    // Load signups when event changes
    const loadSignups = async (eventId: number) => {
        setIsLoadingSignups(true);
        setError(null);
        try {
            const data = await getPubCrawlSignups(eventId);
            setSignups(data);
        } catch (err) {
            console.error(err);
            setError('Kon aanmeldingen niet laden. Controleer je verbinding of probeer het later opnieuw.');
        } finally {
            setIsLoadingSignups(false);
        }
    };

    // Trigger initial load or on change
    useEffect(() => {
        if (selectedEvent) loadSignups(selectedEvent.id);
    }, [selectedEvent?.id]);

    const handleEventSelect = (event: any) => {
        setSelectedEvent(event);
        loadSignups(event.id);
    };

    const handleToggleVisibility = () => {
        startTransition(async () => {
            try {
                const result = await toggleKroegentochtVisibility(settings.show);
                setSettings({ show: result.show });
            } catch (err) {
                console.error(err);
            }
        });
    };

    const handleDeleteSignup = async (id: number) => {
        if (!selectedEvent) return;
        if (!confirm('Weet je zeker dat je deze inschrijving wilt verwijderen?')) return;

        try {
            await deletePubCrawlSignup(id, selectedEvent.id);
            setSignups(prev => prev.filter(s => s.id !== id));
        } catch (err) {
            alert('Fout bij verwijderen: ' + err);
        }
    };

    return (
        <div className="container mx-auto px-4 py-8 max-w-7xl animate-in fade-in slide-in-from-bottom-4 duration-700">
            {/* Top Toolbar */}
            <div className="flex flex-col md:flex-row justify-between items-start md:items-center mb-10 gap-6">
                <div className="flex items-center gap-4">
                    <Link 
                        href="/beheer" 
                        className="p-3 rounded-[var(--radius-xl)] bg-[var(--bg-card)] border border-[var(--border-color)] text-[var(--text-muted)] hover:text-[var(--theme-purple)] transition-all active:scale-90"
                    >
                        <ChevronLeft className="h-5 w-5" />
                    </Link>
                    <div>
                        <h1 className="text-3xl font-black text-[var(--text-main)] tracking-tighter uppercase">Kroegentocht <span className="text-[var(--theme-purple)]">Beheer</span></h1>
                        <p className="text-[10px] font-bold text-[var(--text-muted)] uppercase tracking-widest">Aanmeldingen, tickets & event instellingen</p>
                    </div>
                </div>

                <div className="flex flex-wrap items-center gap-3 w-full md:w-auto">
                    <div className="flex items-center gap-3 px-4 py-2 bg-[var(--bg-card)] border border-[var(--border-color)] rounded-[var(--radius-xl)]">
                        <span className="text-[10px] font-black uppercase tracking-widest text-[var(--text-subtle)]">Zichtbaarheid</span>
                        <button
                            onClick={handleToggleVisibility}
                            disabled={isPending}
                            className={`w-12 h-6 rounded-full p-1 transition-colors relative ${settings.show ? 'bg-green-500' : 'bg-red-500'}`}
                        >
                            <div className={`w-4 h-4 bg-white rounded-full transition-transform ${settings.show ? 'translate-x-6' : 'translate-x-0'}`} />
                        </button>
                    </div>

                    <Link 
                        href="/beheer/kroegentocht/nieuw"
                        className="flex-1 md:flex-none flex items-center justify-center gap-2 px-6 py-3 bg-[var(--theme-purple)] text-white font-black text-xs uppercase tracking-widest rounded-[var(--radius-xl)] shadow-[var(--shadow-glow)] hover:opacity-90 transition-all active:scale-95"
                    >
                        <Plus className="h-4 w-4" />
                        Nieuw Event
                    </Link>
                    {/* # TODO: Implement Admin QR Scanner for Kroegentocht here */}
                </div>
            </div>

            {/* Event Selector Section */}
            <div className="mb-10">
                <EventSelector 
                    events={events}
                    selectedEventId={selectedEvent?.id || null}
                    onSelect={handleEventSelect}
                    showPastEvents={showPastEvents}
                    setShowPastEvents={setShowPastEvents}
                />
            </div>

            {selectedEvent ? (
                <div className="space-y-8 animate-in fade-in zoom-in-95 duration-500">
                    <div className="flex items-center justify-between">
                        <div className="flex items-center gap-3">
                            <Beer className="h-6 w-6 text-[var(--theme-purple)]" />
                            <h2 className="text-2xl font-black text-[var(--text-main)] tracking-tight uppercase">
                                {selectedEvent.name}
                            </h2>
                        </div>
                        <Link 
                            href={`/beheer/kroegentocht/bewerk/${selectedEvent.id}`}
                            className="flex items-center gap-2 px-4 py-2 bg-[var(--bg-main)]/50 border border-[var(--border-color)] rounded-[var(--radius-xl)] text-xs font-bold text-[var(--text-subtle)] hover:border-[var(--theme-purple)]/50 transition-all"
                        >
                            <Settings className="h-4 w-4" />
                            Event Details
                        </Link>
                    </div>

                    <KroegStats signups={signups} />

                    {error && (
                        <div className="flex flex-col items-center justify-center py-16 bg-red-50 dark:bg-red-900/10 rounded-[var(--radius-2xl)] border border-red-200 dark:border-red-900/30 text-red-600 dark:text-red-400 mb-8">
                            <AlertCircle className="h-10 w-10 mb-3" />
                            <p className="text-sm font-bold uppercase tracking-wider">{error}</p>
                            <button 
                                onClick={() => selectedEvent && loadSignups(selectedEvent.id)}
                                className="mt-4 px-4 py-2 bg-red-600 text-white rounded-lg text-xs font-bold uppercase tracking-widest hover:bg-red-700 transition"
                            >
                                Opnieuw Proberen
                            </button>
                        </div>
                    )}

                    {isLoadingSignups ? (
                        <div className="flex flex-col items-center justify-center py-32 bg-[var(--bg-card)]/40 rounded-[var(--radius-2xl)] border-2 border-dashed border-[var(--border-color)]/30">
                            <Loader2 className="h-10 w-10 animate-spin text-[var(--theme-purple)] mb-4" />
                            <p className="text-[10px] font-black uppercase tracking-widest text-[var(--text-muted)]">Aanmeldingen laden...</p>
                        </div>
                    ) : (
                        <SignupList 
                            signups={signups}
                            eventId={selectedEvent.id}
                            eventName={selectedEvent.name}
                            onDelete={handleDeleteSignup}
                            onEdit={(id) => router.push(`/beheer/kroegentocht/deelnemer/${id}`)}
                        />
                    )}
                </div>
            ) : (
                <div className="text-center py-20 bg-[var(--bg-card)]/40 rounded-[var(--radius-2xl)] border-2 border-dashed border-[var(--border-color)]/30">
                    <AlertCircle className="h-16 w-16 text-[var(--text-muted)] opacity-20 mx-auto mb-4" />
                    <h2 className="text-xl font-black text-[var(--text-main)] uppercase tracking-tight">Geen Event Geselecteerd</h2>
                    <p className="text-sm text-[var(--text-subtle)] mt-2">Kies een event hierboven om de data te bekijken.</p>
                </div>
            )}
        </div>
    );
}

'use client';

import { useState, useTransition, useActionState, useMemo, useEffect } from 'react';
import { useRouter, useSearchParams } from 'next/navigation';
import { 
    Loader2, 
    Plus, 
    Edit2, 
    Trash2, 
    Save, 
    X, 
    Users,
    ChevronRight,
    AlertCircle,
    Info,
    Layers,
    Euro
} from 'lucide-react';
import { createTripActivity, updateTripActivity, deleteTripActivity } from '@/server/actions/reis-admin-activities.actions';
import { getImageUrl } from '@/lib/image-utils';
import type { Trip, TripActivity } from '@salvemundi/validations';

interface ReisActiviteitenIslandProps {
    initialTrips: Trip[];
    initialActivities: TripActivity[];
    initialSelectedTripId: number;
    initialSignupsByActivity: Record<number, any[]>;
}

export default function ReisActiviteitenIsland({ 
    initialTrips, 
    initialActivities, 
    initialSelectedTripId,
    initialSignupsByActivity
}: ReisActiviteitenIslandProps) {
    const router = useRouter();
    const [trips] = useState<Trip[]>(initialTrips);
    const [selectedTripId, setSelectedTripId] = useState<number>(initialSelectedTripId);
    const [activities, setActivities] = useState<TripActivity[]>(initialActivities);
    const [signupsByActivity] = useState<Record<number, any[]>>(initialSignupsByActivity);

    const [error, setError] = useState<string | null>(null);
    const [isPending, startTransition] = useTransition();

    const [editingActivity, setEditingActivity] = useState<TripActivity | null>(null);
    const [isAddingNew, setIsAddingNew] = useState(false);

    const [viewingSignupsId, setViewingSignupsId] = useState<number | null>(null);

    // Sync state with props when trip changes via URL
    useEffect(() => {
        setActivities(initialActivities);
        setSelectedTripId(initialSelectedTripId);
    }, [initialActivities, initialSelectedTripId]);

    // Handle trip selection via URL
    const handleTripChange = (e: React.ChangeEvent<HTMLSelectElement>) => {
        const id = parseInt(e.target.value);
        router.push(`/beheer/reis/activiteiten?tripId=${id}`);
    };

    const handleDelete = async (id: number) => {
        if (!confirm('Weet je zeker dat je deze activiteit wilt verwijderen?')) return;

        startTransition(async () => {
            const res = await deleteTripActivity(id);
            if (res.success) {
                setActivities(prev => prev.filter(a => a.id !== id));
            } else {
                alert(res.error || 'Verwijderen mislukt');
            }
        });
    };

    return (
        <div className="container mx-auto px-4 py-8 max-w-6xl animate-in fade-in duration-500">
            {/* Trip Selector Card */}
            <div className="bg-[var(--bg-card)]/80 backdrop-blur-md rounded-[var(--radius-2xl)] shadow-[var(--shadow-card)] ring-1 ring-[var(--border-color)] p-6 mb-8 transition-all hover:shadow-[var(--shadow-glow)]">
                <div className="flex flex-col md:flex-row md:items-center justify-between gap-6">
                    <div className="flex-1">
                        <label className="block text-[10px] font-bold uppercase tracking-widest text-[var(--text-muted)] mb-2 px-1">
                            Selecteer Reis
                        </label>
                        <div className="relative group">
                            <select
                                value={selectedTripId}
                                onChange={handleTripChange}
                                className="w-full pl-4 pr-10 py-3 bg-[var(--bg-main)] border-0 ring-1 ring-[var(--border-color)] rounded-[var(--radius-xl)] text-[var(--text-main)] font-semibold focus:ring-2 focus:ring-[var(--theme-purple)] transition-all appearance-none cursor-pointer"
                            >
                                {trips.map(trip => (
                                    <option key={trip.id} value={trip.id}>{trip.name}</option>
                                ))}
                            </select>
                            <ChevronRight className="absolute right-4 top-1/2 -translate-y-1/2 rotate-90 h-5 w-5 text-[var(--text-muted)] pointer-events-none group-hover:text-[var(--theme-purple)] transition-colors" />
                        </div>
                    </div>

                    <button
                        onClick={() => {
                            setIsAddingNew(true);
                            setEditingActivity(null);
                        }}
                        className="flex items-center justify-center gap-2 px-8 py-4 bg-[var(--theme-purple)] hover:opacity-90 text-white rounded-[var(--radius-xl)] font-bold shadow-lg shadow-[var(--theme-purple)]/20 transition-all active:scale-95"
                    >
                        <Plus className="h-5 w-5" />
                        Nieuwe Activiteit
                    </button>
                </div>
            </div>

            {error && (
                <div className="mb-8 p-4 bg-[var(--theme-error)]/10 text-[var(--theme-error)] rounded-[var(--radius-xl)] border border-[var(--theme-error)]/20 flex items-center gap-3">
                    <AlertCircle className="h-5 w-5 shrink-0" />
                    <p className="font-semibold">{error}</p>
                </div>
            )}

            {/* List or Form */}
            {isAddingNew || editingActivity ? (
                <ActivityForm 
                    activity={editingActivity} 
                    tripId={selectedTripId} 
                    onCancel={() => {
                        setIsAddingNew(false);
                        setEditingActivity(null);
                    }}
                    onSuccess={() => {
                        setIsAddingNew(false);
                        setEditingActivity(null);
                        // Data will refresh via revalidatePath in the action
                    }}
                />
            ) : (
                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
                    {activities.length === 0 ? (
                        <div className="col-span-full py-20 text-center bg-[var(--bg-card)]/40 rounded-[var(--radius-2xl)] border-2 border-dashed border-[var(--border-color)]">
                            <Layers className="h-12 w-12 text-[var(--text-light)] mx-auto mb-4" />
                            <p className="text-[var(--text-muted)] font-medium uppercase tracking-widest text-xs">Nog geen activiteiten voor deze reis</p>
                        </div>
                    ) : (
                        activities.map(activity => (
                            <ActivityCard 
                                key={activity.id} 
                                activity={activity} 
                                signupCount={signupsByActivity[activity.id]?.length || 0}
                                onEdit={() => setEditingActivity(activity)}
                                onDelete={() => handleDelete(activity.id)}
                                onViewSignups={() => setViewingSignupsId(activity.id)}
                            />
                        ))
                    )}
                </div>
            )}

            {/* Signups Modal */}
            {viewingSignupsId && (
                <SignupsModal 
                    activity={activities.find(a => a.id === viewingSignupsId)!}
                    signups={signupsByActivity[viewingSignupsId] || []}
                    onClose={() => setViewingSignupsId(null)}
                />
            )}
        </div>
    );
}

