'use client';

import { useState, useTransition, useActionState } from 'react';
import { 
    Plus, 
    Edit2, 
    Trash2, 
    Save, 
    X, 
    Upload, 
    Calendar, 
    Users, 
    DollarSign,
    Loader2,
    Info,
    CheckCircle,
    AlertCircle,
    ChevronDown,
    Image as ImageIcon
} from 'lucide-react';
import { format } from 'date-fns';
import { nl } from 'date-fns/locale';
import { createTrip, updateTrip, deleteTrip } from '@/server/actions/reis-admin-core.actions';
import { getImageUrl } from '@/lib/image-utils';
import type { Trip } from '@salvemundi/validations';

interface ReisInstellingenIslandProps {
    initialTrips: Trip[];
}

export default function ReisInstellingenIsland({ initialTrips }: ReisInstellingenIslandProps) {
    const [trips, setTrips] = useState<Trip[]>(initialTrips);
    const [editingTrip, setEditingTrip] = useState<Trip | null>(null);
    const [isAdding, setIsAdding] = useState(false);
    const [isDeleting, setIsDeleting] = useState<number | null>(null);

    const [createState, createAction, isCreating] = useActionState(createTrip, null);
    const [updateState, updateAction, isUpdating] = useActionState(
        (prevState: any, formData: FormData) => updateTrip(editingTrip?.id!, prevState, formData), 
        null
    );

    const handleEdit = (trip: Trip) => {
        setEditingTrip(trip);
        setIsAdding(false);
    };

    const handleAdd = () => {
        setEditingTrip(null);
        setIsAdding(true);
    };

    const handleCancel = () => {
        setEditingTrip(null);
        setIsAdding(false);
    };

    const handleDelete = async (id: number) => {
        if (!confirm('Weet je zeker dat je deze reis wilt verwijderen? Dit verwijdert ook alle aanmeldingen!')) return;

        setIsDeleting(id);
        try {
            const res = await deleteTrip(id);
            if (res.success) {
                setTrips(prev => prev.filter(t => t.id !== id));
            } else {
                alert(res.error || 'Verwijderen mislukt');
            }
        } catch (err) {
            alert('Er is een fout opgetreden');
        } finally {
            setIsDeleting(null);
        }
    };

    const state = editingTrip ? updateState : createState;
    const pending = editingTrip ? isUpdating : isCreating;

    if (state?.success && (isAdding || editingTrip)) {
        // Refresh and close on success
        window.location.reload();
    }

    return (
        <div className="container mx-auto px-4 py-8 max-w-6xl animate-in fade-in duration-700">
            {/* Header Actions */}
            {!isAdding && !editingTrip && (
                <div className="mb-10 flex justify-between items-center">
                    <div>
                        <h2 className="text-2xl font-bold text-[var(--text-main)] italic">Reizen Beheren</h2>
                        <p className="text-[10px] font-bold text-[var(--text-muted)] uppercase tracking-widest mt-1">Configureer reis details en prijzen</p>
                    </div>
                    <button
                        onClick={handleAdd}
                        className="px-8 py-4 bg-[var(--theme-purple)] hover:opacity-95 text-white rounded-2xl font-bold shadow-xl shadow-[var(--theme-purple)]/20 transition-all active:scale-95 flex items-center gap-2 group"
                    >
                        <Plus className="h-5 w-5 group-hover:rotate-90 transition-transform" />
                        <span className="italic">Nieuwe Reis</span>
                    </button>
                </div>
            )}

            {/* Error Display */}
            {state?.error && (
                <div className="mb-8 p-4 bg-[var(--theme-error)]/10 text-[var(--theme-error)] rounded-2xl border border-[var(--theme-error)]/20 flex items-center gap-3 animate-in slide-in-from-top-4">
                    <AlertCircle className="h-5 w-5 flex-shrink-0" />
                    <div>
                        <p className="font-bold">{state.error}</p>
                        {state.fieldErrors && (
                            <ul className="text-xs mt-1 list-disc list-inside opacity-80">
                                {Object.entries(state.fieldErrors).map(([field, msgs]: any) => (
                                    <li key={field}>{field}: {msgs.join(', ')}</li>
                                ))}
                            </ul>
                        )}
                    </div>
                </div>
            )}

            {/* Form (Add/Edit) */}
            {(isAdding || editingTrip) && (
                <div className="mb-12 bg-[var(--bg-card)] rounded-[var(--radius-2xl)] shadow-[var(--shadow-card)] ring-1 ring-[var(--border-color)] overflow-hidden animate-in slide-in-from-bottom-8 duration-500">
                    <div className="p-8 border-b border-[var(--border-color)]/20 bg-[var(--bg-main)]/30 backdrop-blur-sm flex justify-between items-center">
                        <div className="flex items-center gap-4">
                            <div className="h-12 w-12 rounded-2xl bg-[var(--theme-purple)]/10 text-[var(--theme-purple)] flex items-center justify-center">
                                {isAdding ? <Plus className="h-6 w-6" /> : <Edit2 className="h-6 w-6" />}
                            </div>
                            <div>
                                <h2 className="text-xl font-bold text-[var(--text-main)] italic">
                                    {isAdding ? 'Nieuwe Reis Toevoegen' : `${editingTrip?.name} Bewerken`}
                                </h2>
                                <p className="text-[10px] font-bold text-[var(--text-muted)] uppercase tracking-widest">Vul alle verplichte velden in</p>
                            </div>
                        </div>
                        <button 
                            onClick={handleCancel}
                            className="p-3 hover:bg-[var(--border-color)]/10 rounded-xl transition-colors text-[var(--text-muted)]"
                        >
                            <X className="h-6 w-6" />
                        </button>
                    </div>

                    <form action={editingTrip ? updateAction : createAction} className="p-8">
                        <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                            {/* Left Column: Basic Info */}
                            <div className="space-y-6">
                                <InputField 
                                    label="Naam van de reis" 
                                    name="name" 
                                    defaultValue={editingTrip?.name} 
                                    placeholder="Bijv. Skiereis 2025" 
                                    required 
                                />
                                <div className="space-y-2">
                                    <label className="text-[10px] font-bold uppercase tracking-widest text-[var(--text-muted)] ml-1">Beschrijving</label>
                                    <textarea 
                                        name="description"
                                        defaultValue={editingTrip?.description || ''}
                                        rows={4}
                                        className="w-full px-6 py-4 bg-[var(--bg-main)]/50 border-0 ring-1 ring-[var(--border-color)]/30 rounded-2xl text-sm text-[var(--text-main)] transition-all resize-none font-semibold focus:ring-2 focus:ring-[var(--theme-purple)]"
                                        placeholder="Korte omschrijving voor de deelnemers..."
                                    />
                                </div>
                                <div className="grid grid-cols-2 gap-4">
                                    <InputField label="Start Datum" name="start_date" type="date" defaultValue={editingTrip?.start_date?.split('T')[0]} required />
                                    <InputField label="Eind Datum" name="end_date" type="date" defaultValue={editingTrip?.end_date?.split('T')[0]} />
                                </div>
                                <div className="grid grid-cols-2 gap-4">
                                    <InputField label="Max Deelnemers" name="max_participants" type="number" defaultValue={editingTrip?.max_participants} required />
                                    <InputField label="Aantal Crew" name="max_crew" type="number" defaultValue={editingTrip?.max_crew || 0} required />
                                </div>
                            </div>

                            {/* Right Column: Pricing & Logistics */}
                            <div className="space-y-6">
                                <div className="grid grid-cols-2 gap-4">
                                    <InputField label="Basis Prijs (€)" name="base_price" type="number" step="0.01" defaultValue={editingTrip?.base_price} required />
                                    <InputField label="Aanbetaling (€)" name="deposit_amount" type="number" step="0.01" defaultValue={editingTrip?.deposit_amount} required />
                                </div>
                                <InputField label="Crew Korting (€)" name="crew_discount" type="number" step="0.01" defaultValue={editingTrip?.crew_discount} />
                                <InputField label="Banner Image ID (Directus)" name="image" defaultValue={editingTrip?.image} />

                                <div className="p-6 bg-[var(--bg-main)]/50 rounded-3xl border border-[var(--border-color)]/20 space-y-4">
                                    <ToggleField label="Inschrijving nu Open" name="registration_open" defaultChecked={editingTrip?.registration_open} />
                                    <ToggleField label="Restbetalingen toestaan" name="allow_final_payments" defaultChecked={editingTrip?.allow_final_payments} />
                                    <ToggleField label="Busreis (Vraag rijbewijs)" name="is_bus_trip" defaultChecked={editingTrip?.is_bus_trip} />
                                </div>

                                <div className="space-y-2">
                                    <label className="text-[10px] font-bold uppercase tracking-widest text-[var(--text-muted)] ml-1">Auto-open Datum</label>
                                    <input 
                                        type="datetime-local" 
                                        name="registration_start_date"
                                        defaultValue={editingTrip?.registration_start_date ? new Date(editingTrip.registration_start_date).toISOString().slice(0,16) : ''}
                                        className="w-full px-6 py-4 bg-[var(--bg-main)]/50 border-0 ring-1 ring-[var(--border-color)]/30 rounded-2xl text-sm text-[var(--text-main)] transition-all font-semibold focus:ring-2 focus:ring-[var(--theme-purple)]"
                                    />
                                </div>
                            </div>
                        </div>

                        <div className="mt-10 pt-8 border-t border-[var(--border-color)]/10 flex justify-end gap-4">
                            <button
                                type="button"
                                onClick={handleCancel}
                                className="px-8 py-4 text-[var(--text-muted)] hover:text-[var(--text-main)] font-bold transition-colors uppercase tracking-widest text-xs"
                            >
                                Annuleren
                            </button>
                            <button
                                type="submit"
                                disabled={pending}
                                className="px-12 py-4 bg-[var(--theme-purple)] hover:opacity-95 text-white rounded-2xl font-bold shadow-2xl shadow-[var(--theme-purple)]/30 transition-all active:scale-95 disabled:opacity-50 flex items-center gap-3"
                            >
                                {pending ? <Loader2 className="h-5 w-5 animate-spin" /> : <Save className="h-5 w-5" />}
                                <span className="italic">Gegevens Opslaan</span>
                            </button>
                        </div>
                    </form>
                </div>
            )}

            {/* Trips List */}
            {!isAdding && !editingTrip && (
                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8 mb-20 animate-in fade-in duration-1000">
                    {trips.map((trip) => (
                        <TripCard 
                            key={trip.id} 
                            trip={trip} 
                            onEdit={() => handleEdit(trip)} 
                            onDelete={() => handleDelete(trip.id)}
                            isDeleting={isDeleting === trip.id}
                        />
                    ))}
                    {trips.length === 0 && (
                        <div className="col-span-full py-20 text-center">
                            <Info className="h-12 w-12 text-[var(--text-muted)] mx-auto mb-4 opacity-20" />
                            <p className="text-[var(--text-muted)] font-bold italic">Nog geen reizen gepland...</p>
                        </div>
                    )}
                </div>
            )}
        </div>
    );
}

function TripCard({ trip, onEdit, onDelete, isDeleting }: any) {
    const sd = trip.start_date || trip.event_date;
    const ed = trip.end_date;

    let dateRange = 'Onbekend';
    if (sd) {
        const start = new Date(sd);
        if (ed) {
            const end = new Date(ed);
            dateRange = `${format(start, 'd MMM', { locale: nl })} - ${format(end, 'd MMM yyyy', { locale: nl })}`;
        } else {
            dateRange = format(start, 'd MMMM yyyy', { locale: nl });
        }
    }

    return (
        <div className="group bg-[var(--bg-card)] rounded-[var(--radius-2xl)] shadow-[var(--shadow-card)] ring-1 ring-[var(--border-color)] overflow-hidden flex flex-col transition-all hover:translate-y-[-4px] hover:shadow-2xl">
            {/* Trip Status Overlays */}
            <div className="relative h-48 bg-[var(--border-color)]/5 flex items-center justify-center overflow-hidden">
                <div className={`absolute top-4 left-4 z-10 px-3 py-1.5 rounded-xl backdrop-blur-md font-black italic text-[10px] uppercase tracking-widest ${
                    trip.registration_open ? 'bg-[var(--theme-success)] text-white shadow-lg shadow-[var(--theme-success)]/20' : 'bg-[var(--theme-error)] text-white shadow-lg shadow-[var(--theme-error)]/20'
                }`}>
                    {trip.registration_open ? 'Open' : 'Gesloten'}
                </div>
                {trip.is_bus_trip && (
                    <div className="absolute top-4 right-4 z-10 px-3 py-1.5 rounded-xl bg-[var(--theme-info)] text-white shadow-lg shadow-[var(--theme-info)]/20 backdrop-blur-md font-black italic text-[10px] uppercase tracking-widest">
                        Busreis
                    </div>
                )}

                {trip.image ? (
                    <img 
                        src={getImageUrl(trip.image, { width: 600, height: 400, fit: 'cover' }) || '/img/newlogo.png'} 
                        alt={trip.name}
                        className="w-full h-full object-cover transition-transform duration-700 group-hover:scale-110"
                    />
                ) : (
                    <div className="text-[var(--text-muted)] opacity-30">
                        <ImageIcon className="h-12 w-12" />
                    </div>
                )}
            </div>

            <div className="p-6 flex-1 flex flex-col">
                <h3 className="text-xl font-bold text-[var(--text-main)] italic mb-2 line-clamp-1 group-hover:text-[var(--theme-purple)] transition-colors">{trip.name}</h3>

                <div className="space-y-3 mb-6 flex-1">
                    <div className="flex items-center gap-3 text-[var(--text-muted)]">
                        <Calendar className="h-4 w-4" />
                        <span className="text-xs font-bold">{dateRange}</span>
                    </div>
                    <div className="flex items-center gap-3 text-[var(--text-muted)]">
                        <Users className="h-4 w-4" />
                        <span className="text-xs font-bold">{trip.max_participants} deelnemers {trip.max_crew > 0 && `(+${trip.max_crew} crew)`}</span>
                    </div>
                    <div className="flex items-center gap-3 text-[var(--theme-purple)]">
                        <DollarSign className="h-4 w-4" />
                        <span className="text-sm font-black italic">€{trip.base_price.toFixed(2)}</span>
                    </div>
                </div>

                <div className="grid grid-cols-2 gap-3 pt-4 border-t border-[var(--border-color)]/10">
                    <button
                        onClick={onEdit}
                        className="flex items-center justify-center gap-2 px-4 py-3 bg-[var(--bg-main)] hover:bg-[var(--border-color)]/10 text-[var(--text-main)] rounded-xl text-xs font-black uppercase tracking-widest transition-all ring-1 ring-[var(--border-color)]/50"
                    >
                        <Edit2 className="h-3.5 w-3.5" />
                        Bewerken
                    </button>
                    <button
                        onClick={onDelete}
                        disabled={isDeleting}
                        className="flex items-center justify-center gap-2 px-4 py-3 bg-[var(--theme-error)]/5 hover:bg-[var(--theme-error)]/10 text-[var(--theme-error)] rounded-xl text-xs font-black uppercase tracking-widest transition-all ring-1 ring-[var(--theme-error)]/20"
                    >
                        {isDeleting ? <Loader2 className="h-3.5 w-3.5 animate-spin" /> : <Trash2 className="h-3.5 w-3.5" />}
                        Wissen
                    </button>
                </div>
            </div>
        </div>
    );
}

function InputField({ label, name, type = 'text', defaultValue, placeholder, required, step }: any) {
    return (
        <div className="space-y-2">
            <label className="text-[10px] font-bold uppercase tracking-widest text-[var(--text-muted)] ml-1">
                {label} {required && <span className="text-[var(--theme-error)]">*</span>}
            </label>
            <input 
                type={type} 
                name={name}
                step={step}
                defaultValue={defaultValue}
                placeholder={placeholder}
                required={required}
                className="w-full px-6 py-4 bg-[var(--bg-main)]/50 border-0 ring-1 ring-[var(--border-color)]/30 rounded-2xl text-sm text-[var(--text-main)] transition-all font-semibold focus:ring-2 focus:ring-[var(--theme-purple)]"
            />
        </div>
    );
}

function ToggleField({ label, name, defaultChecked }: any) {
    return (
        <label className="flex items-center justify-between cursor-pointer group">
            <span className="text-xs font-bold text-[var(--text-main)] group-hover:text-[var(--theme-purple)] transition-colors">{label}</span>
            <div className="relative">
                <input 
                    type="checkbox" 
                    name={name} 
                    defaultChecked={defaultChecked}
                    className="sr-only peer"
                />
                <div className="w-12 h-6 bg-[var(--border-color)]/20 rounded-full peer peer-checked:bg-[var(--theme-purple)] transition-all after:content-[''] after:absolute after:top-1 after:left-1 after:bg-[var(--bg-card)] after:rounded-full after:h-4 after:w-4 after:transition-all peer-checked:after:translate-x-6 shadow-inner ring-1 ring-[var(--border-color)]/30"></div>
            </div>
        </label>
    );
}

'use client';

import { useState, useEffect, useMemo, useTransition } from 'react';
import { useRouter } from 'next/navigation';
import { 
    Mail, 
    Send, 
    Users, 
    Filter, 
    CheckCircle, 
    AlertCircle, 
    Loader2, 
    ChevronDown, 
    Search,
    Info,
    Layout,
    Check
} from 'lucide-react';
import { sendBulkTripEmail, sendBulkPaymentEmails } from '@/server/actions/reis-admin-mail.actions';
import type { Trip, TripSignup } from '@salvemundi/validations';

interface ReisMailIslandProps {
    trips: Trip[];
    initialSignups: TripSignup[];
    initialSelectedTripId: number;
}

export default function ReisMailIsland({ trips, initialSignups, initialSelectedTripId }: ReisMailIslandProps) {
    const router = useRouter();
    const [selectedTripId, setSelectedTripId] = useState<number>(initialSelectedTripId);
    const [signups, setSignups] = useState<TripSignup[]>(initialSignups);
    const [sending, setSending] = useState(false);
    const [error, setError] = useState<string | null>(null);
    const [success, setSuccess] = useState<string | null>(null);

    // Filters
    const [filterStatus, setFilterStatus] = useState<string>('all');
    const [filterRole, setFilterRole] = useState<string>('all');
    const [filterPayment, setFilterPayment] = useState<string>('all');
    const [searchTerm, setSearchTerm] = useState('');

    // Email Config
    const [emailType, setEmailType] = useState<'custom' | 'deposit_request' | 'final_request'>('custom');
    const [subject, setSubject] = useState('');
    const [message, setMessage] = useState('');

    // Sync state with props when trip changes via URL
    useEffect(() => {
        setSignups(initialSignups);
        setSelectedTripId(initialSelectedTripId);
    }, [initialSignups, initialSelectedTripId]);

    const handleTripChange = (e: React.ChangeEvent<HTMLSelectElement>) => {
        const id = parseInt(e.target.value);
        router.push(`/beheer/reis/mail?tripId=${id}`);
    };

    const filteredRecipients = useMemo(() => {
        return signups.filter(s => {
            const matchesSearch = `${s.first_name} ${s.last_name} ${s.email}`.toLowerCase().includes(searchTerm.toLowerCase());
            const matchesStatus = filterStatus === 'all' || s.status === filterStatus;
            const matchesRole = filterRole === 'all' || s.role === filterRole;
            const matchesPayment = 
                filterPayment === 'all' ? true :
                filterPayment === 'unpaid' ? (!s.deposit_paid && !s.full_payment_paid) :
                filterPayment === 'deposit_paid' ? (s.deposit_paid && !s.full_payment_paid) :
                filterPayment === 'full_paid' ? s.full_payment_paid : true;

            return matchesSearch && matchesStatus && matchesRole && matchesPayment;
        });
    }, [signups, searchTerm, filterStatus, filterRole, filterPayment]);

    const handleSend = async () => {
        if (filteredRecipients.length === 0) return;

        const confirmMsg = emailType === 'custom' 
            ? `Weet je zeker dat je deze email wilt sturen naar ${filteredRecipients.length} deelnemers?`
            : `Weet je zeker dat je een ${emailType === 'deposit_request' ? 'aanbetaling' : 'restbetaling'} verzoek wilt sturen naar ${filteredRecipients.length} deelnemers?`;

        if (!confirm(confirmMsg)) return;

        setSending(true);
        setError(null);
        setSuccess(null);

        try {
            if (emailType === 'custom') {
                const res = await sendBulkTripEmail({
                    tripId: selectedTripId,
                    recipients: filteredRecipients.map(r => ({ email: r.email, name: `${r.first_name} ${r.last_name}` })),
                    subject,
                    message
                });
                if (res.success) {
                    setSuccess(`Email succesvol verzonden naar ${filteredRecipients.length} deelnemers!`);
                    setSubject('');
                    setMessage('');
                } else {
                    setError(res.error || 'Fout bij het verzenden');
                }
            } else {
                const res = await sendBulkPaymentEmails(
                    selectedTripId, 
                    filteredRecipients.map(r => r.id), 
                    emailType === 'deposit_request' ? 'deposit' : 'final'
                );
                if (res.success) {
                    setSuccess(`${filteredRecipients.length} betalingsverzoeken succesvol verstuurd!`);
                } else {
                    setError(`Verzenden voltooid: ${res.successCount || 0} gelukt, ${res.failCount || 0} mislukt.`);
                }
            }
        } catch (err) {
            setError('Er is een onverwachte fout opgetreden');
        } finally {
            setSending(false);
        }
    };

    return (
        <div className="container mx-auto px-4 py-8 max-w-6xl animate-in fade-in duration-700">
            {/* Alerts */}
            {success && (
                <div className="mb-6 p-4 bg-[var(--theme-success)]/10 text-[var(--theme-success)] rounded-[var(--radius-xl)] border border-[var(--theme-success)]/20 flex items-center gap-3 animate-in slide-in-from-top-4">
                    <CheckCircle className="h-5 w-5" />
                    <p className="font-semibold">{success}</p>
                </div>
            )}
            {error && (
                <div className="mb-6 p-4 bg-[var(--theme-error)]/10 text-[var(--theme-error)] rounded-[var(--radius-xl)] border border-[var(--theme-error)]/20 flex items-center gap-3 animate-in slide-in-from-top-4">
                    <AlertCircle className="h-5 w-5" />
                    <p className="font-semibold">{error}</p>
                </div>
            )}

            <div className="grid grid-cols-1 lg:grid-cols-4 gap-8">
                {/* Left Column: Config & Filters */}
                <div className="lg:col-span-1 space-y-6">
                    {/* Trip Selector */}
                    <Card title="Selecteer Reis" icon={<Layout className="h-4 w-4" />}>
                        <div className="relative group">
                            <select 
                                value={selectedTripId}
                                onChange={handleTripChange}
                                className="w-full pl-4 pr-10 py-3 bg-[var(--bg-main)] border-0 ring-1 ring-[var(--border-color)]/50 rounded-xl text-sm font-bold text-[var(--text-main)] focus:ring-2 focus:ring-[var(--theme-purple)] transition-all appearance-none cursor-pointer"
                            >
                                {trips.map(trip => (
                                    <option key={trip.id} value={trip.id}>{trip.name}</option>
                                ))}
                            </select>
                            <ChevronDown className="absolute right-4 top-1/2 -translate-y-1/2 h-4 w-4 text-[var(--text-muted)] pointer-events-none group-hover:text-[var(--theme-purple)] transition-colors" />
                        </div>
                    </Card>

                    {/* Filters */}
                    <Card title="Recipients Filter" icon={<Filter className="h-4 w-4" />}>
                        <div className="space-y-4">
                            <FilterField label="Status" value={filterStatus} onChange={setFilterStatus}>
                                <option value="all">Alle Statussen</option>
                                <option value="registered">Geregistreerd</option>
                                <option value="confirmed">Bevestigd</option>
                                <option value="waitlist">Wachtlijst</option>
                                <option value="cancelled">Geannuleerd</option>
                            </FilterField>
                            <FilterField label="Rol" value={filterRole} onChange={setFilterRole}>
                                <option value="all">Alle Rollen</option>
                                <option value="participant">Deelnemer</option>
                                <option value="crew">Crew</option>
                            </FilterField>
                            <FilterField label="Betaling" value={filterPayment} onChange={setFilterPayment}>
                                <option value="all">Alle Betalingen</option>
                                <option value="unpaid">Onbetaald</option>
                                <option value="deposit_paid">Aanbetaling OK</option>
                                <option value="full_paid">Volledig OK</option>
                            </FilterField>
                            <div className="relative">
                                <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-3.5 w-3.5 text-[var(--text-muted)]" />
                                <input 
                                    type="text" 
                                    placeholder="Zoek deelnemer..."
                                    value={searchTerm}
                                    onChange={(e) => setSearchTerm(e.target.value)}
                                    className="w-full pl-10 pr-4 py-2 bg-[var(--bg-main)] hover:bg-[var(--border-color)]/5 ring-1 ring-[var(--border-color)]/50 rounded-xl text-[10px] uppercase font-bold tracking-widest text-[var(--text-main)] placeholder:text-[var(--text-muted)] focus:ring-2 focus:ring-[var(--theme-purple)] transition-all"
                                />
                            </div>
                        </div>
                    </Card>

                    {/* Summary */}
                    <div className="bg-[var(--theme-purple)]/5 rounded-[var(--radius-xl)] ring-1 ring-[var(--theme-purple)]/20 p-6 shadow-sm">
                        <div className="flex items-center gap-3 mb-2 text-[var(--theme-purple)]">
                            <Users className="h-5 w-5" />
                            <span className="text-2xl font-black italic">{filteredRecipients.length}</span>
                        </div>
                        <p className="text-[10px] font-bold uppercase tracking-widest text-[var(--text-muted)]">
                            Ontvangers geselecteerd
                        </p>
                    </div>
                </div>

                {/* Right Column: Content Editor */}
                <div className="lg:col-span-3 space-y-8">
                    <div className="bg-[var(--bg-card)] rounded-[var(--radius-2xl)] shadow-[var(--shadow-card)] ring-1 ring-[var(--border-color)] overflow-hidden">
                        {/* Editor Header */}
                        <div className="p-8 border-b border-[var(--border-color)]/20 bg-[var(--bg-main)]/30 backdrop-blur-sm">
                            <div className="flex flex-col md:flex-row md:items-center justify-between gap-6">
                                <div className="flex items-center gap-4">
                                    <div className="h-12 w-12 rounded-2xl bg-[var(--theme-purple)] text-white flex items-center justify-center shadow-lg shadow-[var(--theme-purple)]/20">
                                        <Mail className="h-6 w-6" />
                                    </div>
                                    <div>
                                        <h2 className="text-xl font-bold text-[var(--text-main)] italic">Bericht Componeren</h2>
                                        <p className="text-[10px] font-bold text-[var(--text-muted)] uppercase tracking-widest">Verzend bulk communicatie</p>
                                    </div>
                                </div>
                                <div className="flex bg-[var(--bg-main)] p-1.5 rounded-2xl ring-1 ring-[var(--border-color)]/50 shadow-inner">
                                    <TypeTab active={emailType === 'custom'} onClick={() => setEmailType('custom')}>Custom</TypeTab>
                                    <TypeTab active={emailType === 'deposit_request'} onClick={() => setEmailType('deposit_request')}>Deposit</TypeTab>
                                    <TypeTab active={emailType === 'final_request'} onClick={() => setEmailType('final_request')}>Final</TypeTab>
                                </div>
                            </div>
                        </div>

                        {/* Editor Body */}
                        <div className="p-8 space-y-8">
                            {emailType === 'custom' ? (
                                <div className="space-y-6 animate-in fade-in slide-in-from-bottom-4 duration-500">
                                    <div className="space-y-2">
                                        <label className="text-[10px] font-bold uppercase tracking-widest text-[var(--text-muted)] ml-1">Onderwerp</label>
                                        <input 
                                            type="text" 
                                            placeholder="Bijv: Belangrijke update over de reis"
                                            value={subject}
                                            onChange={(e) => setSubject(e.target.value)}
                                            className="w-full px-6 py-4 bg-[var(--bg-main)]/50 border-0 ring-1 ring-[var(--border-color)]/30 rounded-2xl text-base text-[var(--text-main)] focus:ring-2 focus:ring-[var(--theme-purple)] transition-all font-semibold"
                                        />
                                    </div>
                                    <div className="space-y-2">
                                        <label className="text-[10px] font-bold uppercase tracking-widest text-[var(--text-muted)] ml-1">Bericht</label>
                                        <textarea 
                                            rows={12}
                                            placeholder="Typ hier je bericht..."
                                            value={message}
                                            onChange={(e) => setMessage(e.target.value)}
                                            className="w-full px-6 py-4 bg-[var(--bg-main)]/50 border-0 ring-1 ring-[var(--border-color)]/30 rounded-2xl text-base text-[var(--text-main)] focus:ring-2 focus:ring-[var(--theme-purple)] transition-all resize-none custom-scrollbar"
                                        />
                                    </div>
                                </div>
                            ) : (
                                <div className="p-8 bg-[var(--theme-purple)]/5 rounded-3xl border border-[var(--theme-purple)]/10 flex items-start gap-6 animate-in zoom-in-95 duration-500">
                                    <div className="p-4 bg-[var(--theme-purple)]/10 rounded-2xl text-[var(--theme-purple)]">
                                        <Info className="h-8 w-8" />
                                    </div>
                                    <div className="space-y-4">
                                        <h3 className="text-lg font-bold text-[var(--text-main)] italic">Automatisch Verzoek</h3>
                                        <p className="text-sm text-[var(--text-muted)] leading-relaxed">
                                            Je staat op het punt om een automatisch gegenereerde <strong>{emailType === 'deposit_request' ? 'aanbetaling' : 'restbetaling'}</strong> email te sturen.
                                            Dit bericht bevat:
                                        </p>
                                        <ul className="space-y-2">
                                            <TickItem>Gepersonaliseerde begroeting</TickItem>
                                            <TickItem>Bedrag informatie en betaallink</TickItem>
                                            <TickItem>Instructies voor de betreffende betaling</TickItem>
                                            {emailType === 'final_request' && <TickItem>Overzicht van geselecteerde activiteiten</TickItem>}
                                        </ul>
                                    </div>
                                </div>
                            )}

                            {/* Actions */}
                            <div className="pt-8 flex items-center justify-between border-t border-[var(--border-color)]/10">
                                <p className="text-[10px] font-bold uppercase tracking-wider text-[var(--text-muted)] italic">
                                    Controleer de filters voordat je verstuurt.
                                </p>
                                <button
                                    onClick={handleSend}
                                    disabled={sending || filteredRecipients.length === 0 || (emailType === 'custom' && (!subject.trim() || !message.trim()))}
                                    className="px-12 py-5 bg-[var(--theme-purple)] hover:opacity-95 text-white rounded-2xl font-bold shadow-2xl shadow-[var(--theme-purple)]/30 transition-all active:scale-95 disabled:opacity-50 flex items-center gap-3 group"
                                >
                                    {sending ? <Loader2 className="h-6 w-6 animate-spin" /> : <Send className="h-6 w-6 group-hover:translate-x-1 group-hover:-translate-y-1 transition-transform" />}
                                    <span className="text-xl italic">Verzenden</span>
                                </button>
                            </div>
                        </div>
                    </div>
                </div>
            </div>
        </div>
    );
}

function Card({ title, icon, children }: any) {
    return (
        <div className="bg-[var(--bg-card)] rounded-[var(--radius-xl)] shadow-[var(--shadow-card)] ring-1 ring-[var(--border-color)] p-6">
            <div className="flex items-center gap-2 mb-4 text-[var(--text-muted)]">
                {icon}
                <span className="text-[10px] font-bold uppercase tracking-widest">{title}</span>
            </div>
            {children}
        </div>
    );
}

function FilterField({ label, value, onChange, children }: any) {
    return (
        <div className="space-y-1">
            <label className="text-[9px] font-bold uppercase tracking-tighter text-[var(--text-muted)] ml-1">{label}</label>
            <div className="relative group">
                <select 
                    value={value}
                    onChange={(e) => onChange(e.target.value)}
                    className="w-full pl-3 pr-8 py-2 bg-[var(--bg-main)] border-0 ring-1 ring-[var(--border-color)]/30 rounded-xl text-xs font-bold text-[var(--text-subtle)] focus:ring-2 focus:ring-[var(--theme-purple)] transition-all appearance-none cursor-pointer"
                >
                    {children}
                </select>
                <ChevronDown className="absolute right-3 top-1/2 -translate-y-1/2 h-4 w-4 text-[var(--text-light)] pointer-events-none group-hover:text-[var(--theme-purple)] transition-colors" />
            </div>
        </div>
    );
}

function TypeTab({ active, onClick, children }: any) {
    return (
        <button 
            onClick={onClick}
            className={`px-4 py-2 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all ${
                active 
                    ? 'bg-[var(--bg-card)] shadow-sm text-[var(--theme-purple)] ring-1 ring-[var(--border-color)]/20' 
                    : 'text-[var(--text-muted)] hover:text-[var(--text-main)]'
            }`}
        >
            {children}
        </button>
    );
}

function TickItem({ children }: any) {
    return (
        <li className="flex items-center gap-2 text-xs font-bold text-[var(--text-muted)]">
            <Check className="h-3 w-3 text-[var(--theme-purple)]" />
            {children}
        </li>
    );
}

'use client';

import { useState, useTransition } from 'react';
import { 
    MapPin, 
    ChevronLeft, 
    RefreshCcw,
    AlertCircle
} from 'lucide-react';
import Link from 'next/link';
import { deleteSticker } from '@/server/actions/admin-stickers.actions';

import StickerStats from '@/components/admin/stickers/StickerStats';
import StickersTable from '@/components/admin/stickers/StickersTable';

interface StickerManagementIslandProps {
    initialStickers: any[];
}

export default function StickerManagementIsland({
    initialStickers
}: StickerManagementIslandProps) {
    const [stickers, setStickers] = useState(initialStickers);
    const [isPending, startTransition] = useTransition();

    const handleDelete = async (id: number) => {
        try {
            await deleteSticker(id);
            setStickers(prev => prev.filter(s => s.id !== id));
        } catch (err) {
            alert('Fout bij verwijderen: ' + err);
        }
    };

    const handleRefresh = () => {
        startTransition(() => {
            // refresh logic is handled via router.refresh in server component usually,
            // but for simple local state update we can just trigger a re-fetch if we had a get function here.
            // For now, we rely on the initialStickers prop being updated via server refresh.
            window.location.reload();
        });
    };

    return (
        <div className="container mx-auto px-4 py-8 max-w-7xl animate-in fade-in slide-in-from-bottom-4 duration-700">
            {/* Top Toolbar */}
            <div className="flex flex-col md:flex-row justify-between items-start md:items-center mb-10 gap-6">
                <div className="flex items-center gap-4">
                    <Link 
                        href="/beheer" 
                        className="p-3 rounded-[var(--radius-xl)] bg-[var(--bg-card)] border border-[var(--border-color)] text-[var(--text-muted)] hover:text-[var(--theme-purple)] transition-all active:scale-90"
                    >
                        <ChevronLeft className="h-5 w-5" />
                    </Link>
                    <div>
                        <h1 className="text-3xl font-black text-[var(--text-main)] tracking-tighter uppercase">Sticker <span className="text-[var(--theme-purple)]">Beheer</span></h1>
                        <p className="text-[10px] font-bold text-[var(--text-muted)] uppercase tracking-widest">Moderatie van geplakte stickers wereldwijd</p>
                    </div>
                </div>

                <button
                    onClick={handleRefresh}
                    disabled={isPending}
                    className="flex items-center gap-2 px-6 py-3 bg-[var(--bg-card)] border border-[var(--border-color)] rounded-[var(--radius-xl)] text-xs font-black uppercase tracking-widest text-[var(--text-subtle)] hover:border-[var(--theme-purple)]/50 transition-all active:scale-95 disabled:opacity-50"
                >
                    <RefreshCcw className={`h-4 w-4 ${isPending ? 'animate-spin' : ''}`} />
                    Vernieuwen
                </button>
            </div>

            {/* Stats */}
            <StickerStats stickers={stickers} />

            {/* Table */}
            <div className="animate-in fade-in zoom-in-95 duration-500">
                <div className="flex items-center gap-3 mb-6">
                    <MapPin className="h-6 w-6 text-[var(--theme-purple)]" />
                    <h2 className="text-2xl font-black text-[var(--text-main)] tracking-tight uppercase">
                        Geregistreerde <span className="text-[var(--theme-purple)]">Locaties</span>
                    </h2>
                </div>

                {stickers.length > 0 ? (
                    <StickersTable 
                        stickers={stickers} 
                        onDelete={handleDelete} 
                    />
                ) : (
                    <div className="text-center py-32 bg-[var(--bg-card)]/40 rounded-[var(--radius-2xl)] border-2 border-dashed border-[var(--border-color)]/30">
                        <AlertCircle className="h-16 w-16 text-[var(--text-muted)] opacity-20 mx-auto mb-4" />
                        <h2 className="text-xl font-black text-[var(--text-main)] uppercase tracking-tight">Geen stickers gevonden</h2>
                        <p className="text-sm text-[var(--text-subtle)] mt-2">Er zijn nog geen stickers geregistreerd in het systeem.</p>
                    </div>
                )}
            </div>
        </div>
    );
}

'use client';

import { useState, useCallback } from 'react';
import {
    Users, UserPlus, UserMinus, Shield, Mail, Info, Search,
    Loader2, RefreshCw, Settings, ExternalLink, Save, X, ChevronRight, CheckCircle,
    Award, History, ShieldAlert
} from 'lucide-react';
import type { Committee, CommitteeMember } from '@/server/actions/admin-committees.actions';
import {
    getCommittees,
    getCommitteeMembers,
    addCommitteeMember,
    removeCommitteeMember,
    toggleCommitteeLeader,
    updateCommitteeDetails,
} from '@/server/actions/admin-committees.actions';

const STANDARD_COMMITTEES = [
    'feestcommissie', 'mediacommissie', 'introcommissie', 'kascommissie',
    'ict-commissie', 'ictcommissie', 'kampcommissie', 'activiteitencommissie',
    'studiecommissie', 'reiscommissie', 'marketingcommissie',
];

const normalizeName = (name: string) =>
    name.toLowerCase().replace(/\s*(\|\||\|)\s*salve mundi/gi, '').trim();

interface Props {
    initialCommittees: Committee[];
}

export default function VerenigingManagementIsland({ initialCommittees }: Props) {
    const [committees, setCommittees] = useState<Committee[]>(initialCommittees);
    const [selected, setSelected] = useState<Committee | null>(null);
    const [members, setMembers] = useState<CommitteeMember[]>([]);

    const [searchQuery, setSearchQuery] = useState('');
    const [showAll, setShowAll] = useState(false);

    const [membersLoading, setMembersLoading] = useState(false);
    const [refreshing, setRefreshing] = useState(false);
    const [actionLoading, setActionLoading] = useState<string | null>(null);

    const [newMemberEmail, setNewMemberEmail] = useState('');
    const [addingMember, setAddingMember] = useState(false);
    const [addError, setAddError] = useState<string | null>(null);

    const [editingDetail, setEditingDetail] = useState(false);
    const [editShortDesc, setEditShortDesc] = useState('');
    const [editDesc, setEditDesc] = useState('');
    const [savingDetail, setSavingDetail] = useState(false);

    // Filtering
    const sorted = [...committees]
        .map(c => ({ ...c, isStandard: STANDARD_COMMITTEES.includes(normalizeName(c.name)) }))
        .sort((a, b) => {
            if (a.isStandard && !b.isStandard) return -1;
            if (!a.isStandard && b.isStandard) return 1;
            return a.name.localeCompare(b.name);
        });

    const filtered = sorted.filter(c => {
        if (!c.name.toLowerCase().includes(searchQuery.toLowerCase())) return false;
        return showAll ? true : c.isStandard;
    });

    const handleRefresh = async () => {
        setRefreshing(true);
        const fresh = await getCommittees().catch(() => committees);
        setCommittees(fresh);
        setRefreshing(false);
    };

    const handleSelectCommittee = useCallback(async (c: Committee) => {
        setSelected(c);
        setEditingDetail(false);
        setEditShortDesc(c.short_description || '');
        setEditDesc(c.description || '');
        setAddError(null);
        setNewMemberEmail('');
        setMembersLoading(true);
        const m = await getCommitteeMembers(c.id.toString()).catch(() => []);
        setMembers(m);
        setMembersLoading(false);
    }, []);

    const handleAddMember = async (e: React.FormEvent) => {
        e.preventDefault();
        if (!selected?.azure_group_id || !newMemberEmail) return;
        setAddingMember(true);
        setAddError(null);
        const res = await addCommitteeMember(selected.azure_group_id, selected.id.toString(), newMemberEmail);
        if (!res.success) {
            setAddError(res.error ?? 'Toevoegen mislukt');
        } else {
            setNewMemberEmail('');
            // Reload members after short delay to allow Azure propagation
            setTimeout(() => handleSelectCommittee(selected), 1500);
        }
        setAddingMember(false);
    };

    const handleRemoveMember = async (member: CommitteeMember) => {
        if (!selected?.azure_group_id) return;
        if (!confirm(`Weet je zeker dat je ${member.displayName} wilt verwijderen uit ${selected.name}?`)) return;
        setActionLoading(`remove-${member.entraId}`);
        const res = await removeCommitteeMember(selected.azure_group_id, member.entraId);
        if (res.success) setMembers(prev => prev.filter(m => m.entraId !== member.entraId));
        else alert(res.error ?? 'Verwijderen mislukt');
        setActionLoading(null);
    };

    const handleToggleLeader = async (member: CommitteeMember) => {
        if (!member.directusMembershipId) {
            alert('Lidmaatschapsrecord niet gevonden. Wacht even op de synchronisatie.');
            return;
        }
        setActionLoading(`leader-${member.entraId}`);
        const res = await toggleCommitteeLeader(
            member.directusMembershipId,
            member.isLeader,
            selected?.azure_group_id,
            member.entraId
        );
        if (res.success) setMembers(prev => prev.map(m => m.entraId === member.entraId ? { ...m, isLeader: !m.isLeader } : m));
        else alert(res.error ?? 'Bijwerken mislukt');
        setActionLoading(null);
    };

    const handleSaveDetail = async () => {
        if (!selected) return;
        setSavingDetail(true);
        const res = await updateCommitteeDetails(selected.id.toString(), {
            short_description: editShortDesc,
            description: editDesc,
        });
        if (res.success) {
            setSelected(prev => prev ? { ...prev, short_description: editShortDesc, description: editDesc } : prev);
            setEditingDetail(false);
        } else alert(res.error ?? 'Opslaan mislukt');
        setSavingDetail(false);
    };

    const slugify = (name: string) =>
        name.toLowerCase().replace(/\s*(\|\||\|)\s*salve mundi/gi, '').trim().replace(/\s+/g, '-').replace(/[^a-z0-9-]/g, '');

    return (
        <div className="container mx-auto px-4 py-12 max-w-7xl">
            {/* Header Area */}
            <div className="flex flex-col md:flex-row md:items-end justify-between gap-6 mb-12">
                <div>
                    <div className="flex items-center gap-3 mb-2">
                        <div className="h-12 w-12 rounded-2xl bg-primary/10 flex items-center justify-center text-primary shadow-sm ring-1 ring-primary/20">
                            <Shield className="h-6 w-6" />
                        </div>
                        <h1 className="text-4xl font-black text-slate-900 dark:text-white tracking-tight">
                            Vereniging <span className="text-primary italic">Beheer</span>
                        </h1>
                    </div>
                    <p className="text-slate-500 dark:text-slate-400 font-medium ml-1">
                        Beheer commissies, leden en Azure-groepslidmaatschappen.
                    </p>
                </div>

                <button
                    onClick={handleRefresh}
                    disabled={refreshing}
                    className="flex items-center gap-2 px-6 py-3 bg-white dark:bg-slate-800 text-slate-600 dark:text-slate-300 rounded-2xl font-bold text-sm shadow-sm ring-1 ring-slate-200 dark:ring-slate-700 hover:ring-primary hover:text-primary transition-all disabled:opacity-50"
                >
                    <RefreshCw className={`h-4 w-4 ${refreshing ? 'animate-spin' : ''}`} />
                    Gegevens Verversen
                </button>
            </div>

            <div className="grid grid-cols-1 lg:grid-cols-12 gap-8 items-start">
                {/* ── Left Sidebar: Committee Selection ── */}
                <div className="lg:col-span-4 space-y-6">
                    <div className="bg-white dark:bg-slate-800 rounded-[2rem] shadow-sm ring-1 ring-slate-200 dark:ring-slate-700 overflow-hidden">
                        <div className="p-6 border-b border-slate-100 dark:border-slate-700/50">
                            <h2 className="text-lg font-black text-slate-900 dark:text-white flex items-center gap-2 mb-4">
                                <Users className="h-5 w-5 text-primary" />
                                Commissies
                            </h2>

                            <div className="space-y-3">
                                <div className="relative group">
                                    <Search className="absolute left-4 top-1/2 -translate-y-1/2 h-4 w-4 text-slate-400 group-focus-within:text-primary transition-colors" />
                                    <input
                                        type="text"
                                        placeholder="Zoek commissie..."
                                        value={searchQuery}
                                        onChange={e => setSearchQuery(e.target.value)}
                                        className="w-full pl-11 pr-4 py-3 bg-slate-50 dark:bg-slate-900/50 border-none rounded-2xl text-sm text-slate-900 dark:text-white placeholder:text-slate-400 focus:ring-2 focus:ring-primary/20 transition-all"
                                    />
                                </div>
                                <div className="flex p-1 bg-slate-100 dark:bg-slate-900/50 rounded-xl">
                                    <button
                                        onClick={() => setShowAll(false)}
                                        className={`flex-1 py-1.5 rounded-lg text-xs font-bold transition-all ${!showAll ? 'bg-white dark:bg-slate-800 text-primary shadow-sm' : 'text-slate-500 hover:text-slate-700 dark:hover:text-slate-300'}`}
                                    >
                                        Standaard
                                    </button>
                                    <button
                                        onClick={() => setShowAll(true)}
                                        className={`flex-1 py-1.5 rounded-lg text-xs font-bold transition-all ${showAll ? 'bg-white dark:bg-slate-800 text-primary shadow-sm' : 'text-slate-500 hover:text-slate-700 dark:hover:text-slate-300'}`}
                                    >
                                        Alle Groepen
                                    </button>
                                </div>
                            </div>
                        </div>

                        <div className="max-h-[500px] overflow-y-auto custom-scrollbar p-3 space-y-1">
                            {filtered.length === 0 ? (
                                <div className="py-12 text-center">
                                    <Search className="h-8 w-8 text-slate-200 mx-auto mb-2" />
                                    <p className="text-slate-400 text-sm italic">Geen resultaten</p>
                                </div>
                            ) : (
                                filtered.map(c => (
                                    <button
                                        key={c.id}
                                        onClick={() => handleSelectCommittee(c)}
                                        className={`w-full group flex items-center justify-between p-4 rounded-2xl transition-all ${selected?.id === c.id
                                            ? 'bg-primary text-white shadow-lg shadow-primary/20'
                                            : 'hover:bg-slate-50 dark:hover:bg-slate-700/30'}`}
                                    >
                                        <div className="text-left min-w-0">
                                            <div className={`font-bold truncate ${selected?.id === c.id ? 'text-white' : 'text-slate-700 dark:text-slate-200'}`}>
                                                {normalizeName(c.name)}
                                            </div>
                                            {c.email && (
                                                <div className={`text-[10px] truncate flex items-center gap-1 mt-0.5 ${selected?.id === c.id ? 'text-white/70' : 'text-slate-400'}`}>
                                                    <Mail className="h-2.5 w-2.5" />
                                                    {c.email}
                                                </div>
                                            )}
                                        </div>
                                        <ChevronRight className={`h-4 w-4 shrink-0 transition-transform ${selected?.id === c.id ? 'translate-x-1 text-white' : 'text-slate-300 group-hover:text-slate-500'}`} />
                                    </button>
                                ))
                            )}
                        </div>
                    </div>
                </div>

                {/* ── Right Content: Management Area ── */}
                <div className="lg:col-span-8">
                    {!selected ? (
                        <div className="bg-white dark:bg-slate-800 rounded-[2rem] shadow-sm ring-1 ring-slate-200 dark:ring-slate-700 p-20 text-center border-2 border-dashed border-slate-200 dark:border-slate-700 relative overflow-hidden">
                            <div className="relative z-10">
                                <div className="h-20 w-20 rounded-3xl bg-slate-50 dark:bg-slate-900/50 flex items-center justify-center mx-auto mb-6 text-slate-200 dark:text-slate-700">
                                    <Users className="h-10 w-10" />
                                </div>
                                <h3 className="text-xl font-black text-slate-900 dark:text-white mb-2">Geen commissie geselecteerd</h3>
                                <p className="text-slate-500 dark:text-slate-400 font-medium max-w-xs mx-auto">
                                    Kies een commissie uit de lijst aan de linkerkant om leden en details te beheren.
                                </p>
                            </div>
                            <div className="absolute top-0 right-0 p-8 opacity-5">
                                <Shield className="h-64 w-64 rotate-12" />
                            </div>
                        </div>
                    ) : (
                        <div className="space-y-6">
                            {/* Main Info Card */}
                            <div className="bg-white dark:bg-slate-800 rounded-[2rem] shadow-sm ring-1 ring-slate-200 dark:ring-slate-700 p-8">
                                <div className="flex flex-col sm:flex-row justify-between items-start gap-6">
                                    <div className="flex-1">
                                        <div className="flex items-center gap-3 mb-4">
                                            <div className="h-14 w-14 rounded-2xl bg-primary text-white flex items-center justify-center shadow-lg shadow-primary/20">
                                                <Users className="h-7 w-7" />
                                            </div>
                                            <div>
                                                <h2 className="text-2xl font-black text-slate-900 dark:text-white leading-tight">
                                                    {selected.name}
                                                </h2>
                                                {selected.email && (
                                                    <a href={`mailto:${selected.email}`} className="text-primary font-bold text-sm hover:underline flex items-center gap-1 mt-1">
                                                        <Mail className="h-3.5 w-3.5" />
                                                        {selected.email}
                                                    </a>
                                                )}
                                            </div>
                                        </div>

                                        {!editingDetail && selected.short_description && (
                                            <p className="text-slate-600 dark:text-slate-300 font-medium text-sm leading-relaxed mb-4">
                                                {selected.short_description}
                                            </p>
                                        )}
                                    </div>

                                    <div className="flex gap-2">
                                        <a
                                            href={`/vereniging/commissies/${slugify(selected.name)}`}
                                            target="_blank"
                                            rel="noopener noreferrer"
                                            className="flex items-center gap-2 px-4 py-2 bg-slate-100 dark:bg-slate-900/50 text-slate-600 dark:text-slate-300 rounded-xl font-bold text-xs ring-1 ring-slate-200 dark:ring-slate-700 hover:bg-white dark:hover:bg-slate-700 transition"
                                        >
                                            <ExternalLink className="h-3.5 w-3.5" /> Website
                                        </a>
                                        <button
                                            onClick={() => setEditingDetail(!editingDetail)}
                                            className={`flex items-center gap-2 px-4 py-2 rounded-xl font-bold text-xs transition-all ${editingDetail ? 'bg-primary text-white shadow-md' : 'bg-slate-100 dark:bg-slate-900/50 text-slate-600 dark:text-slate-300 ring-1 ring-slate-200 dark:ring-slate-700 hover:bg-white dark:hover:bg-slate-700'}`}
                                        >
                                            <Settings className="h-3.5 w-3.5" /> {editingDetail ? 'Annuleren' : 'Bewerken'}
                                        </button>
                                    </div>
                                </div>

                                {editingDetail && (
                                    <div className="mt-8 pt-8 border-t border-slate-100 dark:border-slate-700/50 space-y-6">
                                        <div className="grid grid-cols-1 gap-6">
                                            <div>
                                                <label className="text-xs font-black uppercase text-slate-400 tracking-widest block mb-2">Korte Beschrijving</label>
                                                <textarea
                                                    value={editShortDesc}
                                                    onChange={e => setEditShortDesc(e.target.value)}
                                                    rows={2}
                                                    className="w-full px-5 py-3 rounded-2xl bg-slate-50 dark:bg-slate-900 border-none text-sm text-slate-900 dark:text-white placeholder:text-slate-400 focus:ring-2 focus:ring-primary/20 transition-all resize-none"
                                                    placeholder="Korte tekst voor previews..."
                                                />
                                            </div>
                                            <div>
                                                <label className="text-xs font-black uppercase text-slate-400 tracking-widest block mb-2">Inhoud (HTML ondersteund)</label>
                                                <textarea
                                                    value={editDesc}
                                                    onChange={e => setEditDesc(e.target.value)}
                                                    rows={10}
                                                    className="w-full px-5 py-3 rounded-2xl bg-slate-50 dark:bg-slate-900 border-none text-sm text-slate-900 dark:text-white placeholder:text-slate-400 focus:ring-2 focus:ring-primary/20 transition-all font-mono"
                                                    placeholder="Schrijf hier de volledige tekst..."
                                                />
                                            </div>
                                        </div>
                                        <button
                                            onClick={handleSaveDetail}
                                            disabled={savingDetail}
                                            className="w-full flex items-center justify-center gap-2 py-4 bg-primary text-white rounded-2xl font-black text-sm shadow-lg shadow-primary/20 hover:opacity-90 transition disabled:opacity-50"
                                        >
                                            {savingDetail ? <Loader2 className="h-5 w-5 animate-spin" /> : <Save className="h-5 w-5" />}
                                            Wijzigingen Opslaan
                                        </button>
                                    </div>
                                )}
                            </div>

                            {/* Members Management Section */}
                            <div className="bg-white dark:bg-slate-800 rounded-[2rem] shadow-sm ring-1 ring-slate-200 dark:ring-slate-700 overflow-hidden">
                                <div className="p-8 border-b border-slate-100 dark:border-slate-700/50 flex flex-col md:flex-row md:items-center justify-between gap-6">
                                    <div>
                                        <h3 className="text-xl font-black text-slate-900 dark:text-white">Leden & Rechten</h3>
                                        <p className="text-sm text-slate-500 font-medium">Beheer wie toegang heeft tot de Azure-groep.</p>
                                    </div>

                                    {selected.azure_group_id ? (
                                        <div className="flex-1 max-w-md">
                                            <form onSubmit={handleAddMember} className="relative group">
                                                <div className="absolute left-4 top-1/2 -translate-y-1/2 flex items-center gap-2 text-slate-400 group-focus-within:text-primary transition-colors">
                                                    <UserPlus className="h-4 w-4" />
                                                </div>
                                                <input
                                                    type="email"
                                                    placeholder="Nieuw lid toevoegen (e-mail)..."
                                                    value={newMemberEmail}
                                                    onChange={e => { setNewMemberEmail(e.target.value); setAddError(null); }}
                                                    required
                                                    className="w-full pl-12 pr-24 py-3 bg-slate-50 dark:bg-slate-900 border-none rounded-2xl text-sm text-slate-900 dark:text-white placeholder:text-slate-400 focus:ring-2 focus:ring-primary/20 transition-all"
                                                />
                                                <button
                                                    type="submit"
                                                    disabled={addingMember || !newMemberEmail}
