                                                                    <div className="flex items-center gap-1 px-1.5 py-0.5 bg-amber-500 text-white text-[8px] font-black rounded-full uppercase tracking-tighter shadow-sm">
                                                                        <Award className="h-2 w-2" /> Leider
                                                                    </div>
                                                                )}
