                                <div className={`h-3 w-3 rounded-full mb-3 ${status === 'published' ? 'bg-primary animate-pulse' : 'bg-slate-300'}`} />
                                <span className="block font-bold dark:text-white">Direct publiceren</span>
                                <span className="text-xs text-slate-500 mt-1 block">Zichtbaar voor iedereen</span>
                            </button>
                            <button 
                                type="button"
                                onClick={() => setStatus('draft')}
                                className={`p-4 rounded-2xl border-2 text-left transition-all cursor-pointer ${status === 'draft' ? 'border-primary bg-primary/5 ring-4 ring-primary/10' : 'border-slate-100 dark:border-slate-700 hover:border-slate-200 dark:hover:border-slate-600'}`}
                            >
                                <div className={`h-3 w-3 rounded-full mb-3 ${status === 'draft' ? 'bg-primary' : 'bg-slate-300'}`} />
                                <span className="block font-bold dark:text-white">Opslaan als concept</span>
                                <span className="text-xs text-slate-500 mt-1 block">Alleen zichtbaar in beheer</span>
                            </button>
                            <button 
                                type="button"
                                onClick={() => setStatus('scheduled')}
                                className={`p-4 rounded-2xl border-2 text-left transition-all cursor-pointer ${status === 'scheduled' ? 'border-primary bg-primary/5 ring-4 ring-primary/10' : 'border-slate-100 dark:border-slate-700 hover:border-slate-200 dark:hover:border-slate-600'}`}
                            >
                                <div className={`h-3 w-3 rounded-full mb-3 ${status === 'scheduled' ? 'bg-primary' : 'bg-slate-300'}`} />
                                <span className="block font-bold dark:text-white">Inplannen</span>
                                <span className="text-xs text-slate-500 mt-1 block">Publiceren op een later moment</span>
                            </button>
                        </div>

                        {status === 'scheduled' && (
                            <div className="animate-in fade-in slide-in-from-top-2 duration-300 bg-primary/5 p-6 rounded-2xl border border-primary/20 space-y-3">
                                <label htmlFor="publish_date" className="block text-sm font-bold text-primary">Publicatiedatum & Tijd *</label>
                                <input type="datetime-local" id="publish_date" name="publish_date" className="w-full px-4 py-3 rounded-xl border border-primary/20 bg-white dark:bg-slate-900 outline-none focus:ring-4 focus:ring-primary/10 transition-all font-medium" />
                                <p className="text-xs text-slate-500">De activiteit zal automatisch op "published" worden gezet op dit tijdstip.</p>
                            </div>
                        )}
                    </div>

                    {/* Footer Actions */}
                    <div className="flex flex-wrap items-center justify-end gap-4 pt-10 border-t border-slate-100 dark:border-slate-700/50">
                        <button 
                            type="button" 
                            onClick={() => router.back()} 
                            className="px-8 py-4 rounded-2xl font-bold text-slate-500 hover:bg-slate-100 dark:hover:bg-slate-800 transition-all cursor-pointer"
                        >
                            Annuleren
                        </button>
                        <button 
                            type="submit" 
                            disabled={optimisticSaving}
                            className="px-10 py-4 bg-primary text-white rounded-2xl font-bold shadow-xl shadow-primary/20 hover:shadow-2xl hover:scale-[1.02] active:scale-[0.98] transition-all flex items-center gap-3 disabled:opacity-70 disabled:grayscale disabled:cursor-not-allowed cursor-pointer"
                        >
                            {optimisticSaving ? <Loader2 className="h-6 w-6 animate-spin" /> : <Save className="h-6 w-6" />}
                            {optimisticSaving ? 'Activiteit wordt aangemaakt...' : 'Activiteit Aanmaken'}
                        </button>
                    </div>
                </div>
            </form>

            {/* Premium Toast System */}
            {toast && (
                <div className="fixed bottom-8 right-8 z-50 animate-in fade-in slide-in-from-right-8 duration-500">
                    <div className={`px-8 py-5 rounded-3xl shadow-2xl flex items-center gap-4 backdrop-blur-md border ${toast.type === 'success' ? 'bg-green-500/90 border-green-400 text-white' : 'bg-red-500/90 border-red-400 text-white'}`}>
                        <div className="h-10 w-10 rounded-2xl bg-white/20 flex items-center justify-center font-bold text-xl">
                            {toast.type === 'success' ? '✓' : '!'}
                        </div>
                        <span className="font-bold text-lg">{toast.message}</span>
                    </div>
                </div>
            )}
        </div>
    );
}

'use client';

import { useState, useMemo, useTransition, useEffect } from 'react';
import { useRouter } from 'next/navigation';
import Image from 'next/image';
import { Calendar, Users, Edit, Trash2, Eye, Plus, Search, Bell, Send, MapPin, Mail, Euro, X, Loader2 } from 'lucide-react';
import { deleteActivity, sendActivityReminder, sendActivityCustomNotification } from '@/server/actions/activiteiten.actions';
import PageHeader from '@/components/ui/layout/PageHeader';
import { format } from 'date-fns';
import { nl } from 'date-fns/locale';
import { getImageUrl } from '@/lib/image-utils';
import { isSuperAdmin } from '@/lib/auth-utils';

interface AdminActivity {
    id: number;
    name: string;
    event_date: string;
    event_date_end?: string | null;
    description?: string | null;
    location?: string | null;
    max_sign_ups?: number | null;
    price_members?: number | null;
    price_non_members?: number | null;
    registration_deadline?: string | null;
    contact?: string | null;
    image?: { id: string } | string | null;
    committee_id?: number | null;
    status?: 'published' | 'draft' | 'archived' | 'scheduled' | null;
    publish_date?: string | null;
    signup_count?: number;
}

export default function AdminActivitiesIsland({
    initialEvents,
    userId,
    userCommittees = [],
    initialSearch = '',
    initialFilter = 'all'
}: {
    initialEvents: AdminActivity[],
    userId?: string,
    userCommittees?: any[],
    initialSearch?: string,
    initialFilter?: 'all' | 'upcoming' | 'past'
}) {
    const router = useRouter();
    const [events, setEvents] = useState(initialEvents);
    const [searchQuery, setSearchQuery] = useState(initialSearch);
    const [filter, setFilter] = useState<'all' | 'upcoming' | 'past'>(initialFilter);
    const [pageSize, setPageSize] = useState<number | -1>(10);

    // Notification states
    const [showModal, setShowModal] = useState(false);
    const [customNotification, setCustomNotification] = useState({ title: '', body: '', eventId: 0 });
    const [isSending, setIsSending] = useState(false);

    const [isPending, startTransition] = useTransition();

    // URL Sync logic
    const updateUrl = (q: string, f: string) => {
        const params = new URLSearchParams();
        if (q) params.set('q', q);
        if (f && f !== 'all') params.set('filter', f);

        const queryString = params.toString();
        router.push(`/beheer/activiteiten${queryString ? `?${queryString}` : ''}`);
    };

    // Sync state with props when they change (e.g. from router.push)
    useEffect(() => {
        setEvents(initialEvents);
        setSearchQuery(initialSearch);
        setFilter(initialFilter);
    }, [initialEvents, initialSearch, initialFilter]);

    // Search debounce
    useEffect(() => {
        if (searchQuery === initialSearch) return;

        const timer = setTimeout(() => {
            updateUrl(searchQuery, filter);
        }, 500);

        return () => clearTimeout(timer);
    }, [searchQuery]);

    const handleFilterChange = (newFilter: 'all' | 'upcoming' | 'past') => {
        if (newFilter === filter) return;
        setFilter(newFilter);
        updateUrl(searchQuery, newFilter);
    };

    const displayedEvents = pageSize === -1 ? events : events.slice(0, pageSize);

    const handleDelete = async (eventId: number, eventName: string) => {
        if (!confirm(`Weet je zeker dat je "${eventName}" wilt verwijderen?`)) return;
        startTransition(async () => {
            const res = await deleteActivity(eventId);
            if (res.success) {
                setEvents(prev => prev.filter(e => e.id !== eventId));
            } else {
                alert(res.error);
            }
        });
    };

    const handleReminder = async (eventId: number, eventName: string) => {
        if (!confirm(`Wil je een herinnering sturen naar alle deelnemers van "${eventName}"?`)) return;
        setIsSending(true);
        const res = await sendActivityReminder(eventId);
        setIsSending(false);
        if (res.success) alert(`Herinnering verstuurd naar ${res.sent} deelnemers!`);
        else alert(res.error);
    };

    const handleCustomNotify = async () => {
        setIsSending(true);
        const res = await sendActivityCustomNotification(
            customNotification.eventId,
            customNotification.title,
            customNotification.body
        );
        setIsSending(false);
        if (res.success) {
            alert(`Notificatie verstuurd naar ${res.sent} deelnemers!`);
            setShowModal(false);
        } else {
            alert(res.error);
        }
    };


    const formatDate = (date: string) => {
        return format(new Date(date), 'dd MMMM yyyy', { locale: nl });
    };

    // Global admin privileges
    const superAdmin = useMemo(() => isSuperAdmin(userCommittees), [userCommittees]);

    return (
        <div className="container mx-auto px-4 py-8 max-w-7xl">
            {/* Actions Bar */}
            <div className="mb-8 flex flex-col sm:flex-row gap-4 items-start sm:items-center justify-between">
                <div className="w-full flex items-center justify-between gap-4">
                    <div className="flex items-center gap-4">
                        <button
                            onClick={() => router.push('/beheer/activiteiten/nieuw')}
                            className="bg-purple-600 dark:bg-purple-500 text-white px-6 py-3 rounded-full font-bold shadow-lg hover:shadow-xl transition-all hover:-translate-y-0.5 flex items-center gap-2 cursor-pointer"
                        >
                            <Plus className="h-5 w-5" />
                            <span>Nieuwe Activiteit</span>
                        </button>
                        <div className="flex items-center gap-3">
                            <label className="text-sm font-bold text-slate-500 sr-only sm:not-sr-only">Toon</label>
                            <select
                                value={pageSize === -1 ? 'all' : pageSize}
                                onChange={(e) => setPageSize(e.target.value === 'all' ? -1 : parseInt(e.target.value, 10))}
                                className="rounded-full border border-slate-200 dark:border-slate-700 bg-white dark:bg-slate-800 text-slate-700 dark:text-slate-200 text-sm px-4 py-2 outline-none cursor-pointer font-medium"
                            >
                                <option value="10">10</option>
                                <option value="15">15</option>
                                <option value="all">Alles</option>
                            </select>
                        </div>
                    </div>
                    <div className="hidden sm:flex gap-2">
                        {['all', 'upcoming', 'past'].map(f => (
                            <button
                                key={f}
                                onClick={() => handleFilterChange(f as any)}
                                className={`px-5 py-2 rounded-full font-bold transition-all cursor-pointer ${filter === f ? 'bg-purple-600 text-white shadow-md' : 'bg-slate-100 dark:bg-slate-800 text-slate-600 dark:text-slate-400 hover:bg-slate-200 dark:hover:bg-slate-700'}`}
                            >
                                {f === 'all' ? 'Alle' : f === 'upcoming' ? 'Aankomend' : 'Verleden'}
                            </button>
                        ))}
                    </div>
                </div>
            </div>

            {/* Search Bar */}
            <div className="mb-8 relative max-w-md group">
                <Search className="absolute left-4 top-1/2 -translate-y-1/2 h-5 w-5 text-slate-400 group-focus-within:text-purple-500 transition-colors pointer-events-none z-20" />
                <input
                    type="text"
                    placeholder="Zoek activiteiten..."
                    value={searchQuery}
                    onChange={(e) => setSearchQuery(e.target.value)}
                    className="w-full pl-12 pr-4 py-4 rounded-full border border-slate-200 dark:border-slate-700 bg-white dark:bg-slate-900 text-slate-900 dark:text-white focus:ring-4 focus:ring-purple-500/10 focus:border-purple-500 outline-none transition-all shadow-sm"
                />
            </div>

            {/* Activities List */}
            <div className="grid grid-cols-1 gap-6">
                {displayedEvents.map(event => {
                    const eventDate = new Date(event.event_date);
                    const isPast = eventDate < new Date();
                    const isDraft = event.status === 'draft';
                    const isScheduled = event.status === 'published' && event.publish_date && new Date(event.publish_date) > new Date();
                    const canEdit = superAdmin || (event.committee_id && userCommittees.some(c => String(c.id) === String(event.committee_id)));

                    return (
                        <div
                            key={event.id}
                            className={`bg-white dark:bg-slate-800 rounded-2xl shadow-lg p-4 sm:p-6 transition-all border border-slate-100 dark:border-slate-700/50 hover:shadow-2xl hover:scale-[1.005] group/card ${isPast ? 'opacity-80' : ''}`}
                        >
                            <div className="flex flex-col md:flex-row gap-6">
                                {/* Image & Main Info */}
                                <div className="flex-1 min-w-0">
                                    <div className="flex items-start justify-between mb-4">
                                        <div className="flex items-start gap-5 flex-1 min-w-0">
                                            <div className="relative w-16 h-16 sm:w-20 sm:h-20 md:w-28 md:h-28 flex-shrink-0 group-hover/card:scale-105 transition-transform duration-500">
                                                <Image
                                                    src={getImageUrl(event.image) || '/img/placeholder.svg'}
                                                    alt={event.name}
                                                    fill
                                                    className="object-cover rounded-2xl shadow-md border border-slate-100 dark:border-slate-700"
                                                    sizes="112px"
                                                />
                                            </div>
                                            <div className="flex-1 min-w-0">
                                                <div className="flex flex-wrap items-center gap-2 mb-2">
                                                    <h3 className="text-xl sm:text-2xl font-bold text-slate-900 dark:text-white truncate pr-2">
                                                        {event.name}
                                                    </h3>
                                                    {isDraft && <span className="px-3 py-1 text-xs font-black bg-slate-500 text-white rounded-full uppercase tracking-tighter">Draft</span>}
                                                    {isScheduled && <span className="px-3 py-1 text-xs font-black bg-blue-500 text-white rounded-full uppercase tracking-tighter">Scheduled</span>}
                                                    {isPast && <span className="px-3 py-1 text-xs font-black bg-slate-100 dark:bg-slate-700 text-slate-500 dark:text-slate-400 rounded-full uppercase tracking-tighter">Past</span>}
                                                </div>
                                                <div className="flex flex-wrap gap-4 text-sm font-medium text-slate-500 dark:text-slate-400">
                                                    <div className="flex items-center gap-2">
                                                        <Calendar className="h-4 w-4 text-purple-500" />
                                                        <span>{formatDate(event.event_date)}</span>
                                                    </div>
                                                    {event.location && (
                                                        <div className="flex items-center gap-2">
                                                            <MapPin className="h-4 w-4 text-red-500" />
                                                            <span className="truncate max-w-[150px] sm:max-w-none">{event.location}</span>
                                                        </div>
                                                    )}
                                                    {event.contact && (
                                                        <div className="flex items-center gap-2">
                                                            <Mail className="h-4 w-4 text-blue-500" />
                                                            <span className="truncate max-w-[150px] sm:max-w-none">{event.contact}</span>
                                                        </div>
                                                    )}
                                                </div>
                                            </div>
                                        </div>
                                    </div>

                                    {event.description && (
                                        <p className="text-slate-600 dark:text-slate-300 text-sm mb-4 line-clamp-2 leading-relaxed">
                                            {event.description}
                                        </p>
                                    )}

                                    <div className="flex flex-wrap gap-6 items-center">
                                        <div className="flex items-center gap-2 bg-purple-50 dark:bg-purple-900/20 px-4 py-2 rounded-xl">
                                            <Users className="h-4 w-4 text-purple-600 dark:text-purple-400" />
                                            <span className="font-black text-purple-600 dark:text-purple-400">{event.signup_count || 0}</span>
                                            {event.max_sign_ups && <span className="text-purple-400 dark:text-purple-600 font-bold">/ {event.max_sign_ups}</span>}
                                            <span className="text-xs font-bold text-purple-500/70 uppercase ml-1">aanmeldingen</span>
                                        </div>
                                        {(event.price_members !== undefined || event.price_non_members !== undefined) && (
                                            <div className="flex items-center gap-3 text-sm font-bold text-slate-600 dark:text-slate-300">
                                                <Euro className="h-4 w-4 text-green-500" />
                                                <span>
                                                    {event.price_members === 0 && event.price_non_members === 0 ? (
                                                        <span className="text-green-600 dark:text-green-400 font-black">GRATIS</span>
                                                    ) : (
                                                        <span>€{event.price_members || 0} <span className="text-slate-400 font-medium">/</span> €{event.price_non_members || 0}</span>
                                                    )}
                                                </span>
                                            </div>
                                        )}
                                    </div>
                                </div>

                                {/* Actions */}
                                <div className="flex flex-row md:flex-col gap-3 justify-end items-end w-full md:w-auto flex-wrap pt-4 md:pt-0 border-t md:border-t-0 border-slate-100 dark:border-slate-700">
                                    <button
                                        onClick={() => router.push(`/beheer/activiteiten/${event.id}/aanmeldingen`)}
                                        className="btn-secondary flex items-center gap-2 px-4 py-3 text-sm bg-blue-50 text-blue-600 hover:bg-blue-100 dark:bg-blue-900/30 dark:text-white dark:hover:bg-blue-800/50 rounded-xl transition-all font-bold cursor-pointer"
                                    >
                                        <Eye className="h-4 w-4" />
                                        <span>Show Signups</span>
                                    </button>

                                    {!isPast && !isDraft && (
                                        <div className="flex gap-2 w-full md:w-auto">
                                            <button
                                                onClick={() => handleReminder(event.id, event.name)}
                                                disabled={isSending}
                                                className="flex-1 md:flex-none flex items-center justify-center gap-2 px-4 py-3 text-sm bg-amber-50 text-amber-600 hover:bg-amber-100 dark:bg-amber-900/30 dark:text-white rounded-xl transition-all font-bold disabled:opacity-50 cursor-pointer"
                                                title="Stuur herinnering naar alle deelnemers"
                                            >
                                                <Bell className="h-4 w-4" />
                                                <span className="md:hidden lg:inline">Reminder</span>
                                            </button>
                                            <button
                                                onClick={() => {
                                                    setCustomNotification({ title: `Update: ${event.name}`, body: '', eventId: event.id });
                                                    setShowModal(true);
                                                }}
                                                disabled={isSending}
                                                className="flex-1 md:flex-none flex items-center justify-center gap-2 px-4 py-3 text-sm bg-indigo-50 text-indigo-600 hover:bg-indigo-100 dark:bg-indigo-900/30 dark:text-white rounded-xl transition-all font-bold disabled:opacity-50 cursor-pointer"
                                                title="Stuur custom notificatie"
                                            >
                                                <Send className="h-4 w-4" />
                                                <span className="md:hidden lg:inline">Custom</span>
                                            </button>
                                        </div>
                                    )}

                                    {canEdit && (
                                        <div className="flex gap-2 w-full md:w-auto">
                                            <button
                                                onClick={() => router.push(`/beheer/activiteiten/${event.id}/bewerken`)}
                                                className="flex-1 md:flex-none flex items-center justify-center gap-2 px-4 py-3 text-sm bg-slate-100 text-slate-700 hover:bg-slate-200 dark:bg-slate-700 dark:text-slate-200 dark:hover:bg-slate-600 rounded-xl transition-all font-bold cursor-pointer"
                                            >
                                                <Edit className="h-4 w-4" />
                                                <span>Edit</span>
                                            </button>
                                            <button
                                                onClick={() => handleDelete(event.id, event.name)}
                                                disabled={isPending}
                                                className="flex-1 md:flex-none flex items-center justify-center gap-2 px-4 py-3 text-sm bg-red-50 text-red-600 hover:bg-red-100 dark:bg-red-900/30 dark:text-white rounded-xl transition-all font-bold disabled:opacity-50 cursor-pointer"
                                            >
                                                <Trash2 className="h-4 w-4" />
                                                <span className="inline md:hidden lg:inline">Delete</span>
                                            </button>
                                        </div>
                                    )}
                                </div>
                            </div>
                        </div>
                    );
                })}
            </div>

            {/* Custom Notification Modal */}
            {showModal && (
                <div className="fixed inset-0 bg-black/60 backdrop-blur-sm flex items-center justify-center z-50 p-4 animate-in fade-in duration-300">
                    <div className="bg-white dark:bg-slate-800 rounded-3xl shadow-2xl max-w-lg w-full p-8 border border-slate-200 dark:border-slate-700 scale-in-center">
                        <div className="flex items-center justify-between mb-6">
                            <h3 className="text-2xl font-black text-slate-900 dark:text-white uppercase tracking-tight">
                                Custom Notificatie
                            </h3>
                            <button onClick={() => setShowModal(false)} className="p-2 hover:bg-slate-100 dark:hover:bg-slate-700 rounded-full transition-colors cursor-pointer">
                                <X className="h-6 w-6 text-slate-400" />
                            </button>
                        </div>

                        <div className="space-y-6 mb-8">
                            <div className="space-y-2">
                                <label className="block text-xs font-black text-slate-500 uppercase tracking-widest">
                                    Titel
                                </label>
                                <input
                                    type="text"
                                    value={customNotification.title}
                                    onChange={(e) => setCustomNotification({ ...customNotification, title: e.target.value })}
                                    className="w-full px-5 py-3 rounded-xl border border-slate-200 dark:border-slate-700 bg-slate-50 dark:bg-slate-900 text-slate-900 dark:text-white focus:ring-4 focus:ring-purple-500/10 focus:border-purple-500 outline-none transition-all font-bold"
                                    placeholder="Reminder: Activiteit..."
                                />
                            </div>

                            <div className="space-y-2">
                                <label className="block text-xs font-black text-slate-500 uppercase tracking-widest">
                                    Bericht
                                </label>
                                <textarea
                                    value={customNotification.body}
                                    onChange={(e) => setCustomNotification({ ...customNotification, body: e.target.value })}
                                    rows={4}
                                    className="w-full px-5 py-3 rounded-xl border border-slate-200 dark:border-slate-700 bg-slate-50 dark:bg-slate-900 text-slate-900 dark:text-white focus:ring-4 focus:ring-purple-500/10 focus:border-purple-500 outline-none transition-all resize-none font-medium"
                                    placeholder="Belangrijke update voor deelnemers..."
                                />
                            </div>
                        </div>

                        <div className="flex gap-4">
                            <button
                                onClick={handleCustomNotify}
                                disabled={isSending || !customNotification.title || !customNotification.body}
                                className="flex-1 px-8 py-4 bg-purple-600 text-white rounded-2xl hover:bg-purple-700 transition-all font-black shadow-xl shadow-purple-500/20 flex items-center justify-center gap-3 disabled:opacity-50 disabled:cursor-not-allowed cursor-pointer active:scale-95"
                            >
                                {isSending ? <Loader2 className="h-5 w-5 animate-spin" /> : <Send className="h-5 w-5" />}
                                <span>VERSTUREN</span>
                            </button>
                            <button
                                onClick={() => setShowModal(false)}
                                disabled={isSending}
                                className="px-8 py-4 bg-slate-100 dark:bg-slate-700 text-slate-600 dark:text-slate-300 rounded-2xl hover:bg-slate-200 dark:hover:bg-slate-600 transition-all font-bold cursor-pointer"
                            >
                                Annuleer
                            </button>
                        </div>
                    </div>
                </div>
            )}
        </div>
    );
}

'use client';

import { useState, useEffect } from 'react';
import { X, Search, Check, Loader2, User, UserPlus, XCircle, CheckCircle } from 'lucide-react';
import { searchMembersAction, createManualSignupAction } from '@/server/actions/aanmeldingen.actions';

function useDebounce<T>(value: T, delay: number): T {
    const [debouncedValue, setDebouncedValue] = useState<T>(value);
    useEffect(() => {
        const timer = setTimeout(() => setDebouncedValue(value), delay);
        return () => clearTimeout(timer);
    }, [value, delay]);
    return debouncedValue;
}

interface ManualSignupModalProps {
    isOpen: boolean;
    onClose: () => void;
    eventId: string | number;
    eventName: string;
    eventPrice: number;
}

interface UserResult {
    id: string;
    first_name: string;
    last_name: string;
    email: string;
}

export default function ManualSignupModal({ isOpen, onClose, eventId, eventName, eventPrice }: ManualSignupModalProps) {
    const [activeTab, setActiveTab] = useState<'member' | 'guest'>('member');
    const [isLoading, setIsLoading] = useState(false);
    const [error, setError] = useState<string | null>(null);
    const [successMessage, setSuccessMessage] = useState<string | null>(null);

    // Member specific state
    const [memberQuery, setMemberQuery] = useState('');
    const [memberResults, setMemberResults] = useState<UserResult[]>([]);
    const [selectedMember, setSelectedMember] = useState<UserResult | null>(null);
    const [isSearchingMember, setIsSearchingMember] = useState(false);
    const debouncedMemberQuery = useDebounce(memberQuery, 300);

    // Guest specific state
    const [guestName, setGuestName] = useState('');
    const [guestEmail, setGuestEmail] = useState('');
    const [guestPhone, setGuestPhone] = useState('');

    useEffect(() => {
        if (!isOpen) {
            resetForm();
        }
    }, [isOpen]);

    // Effect for searching members
    useEffect(() => {
        const searchMembers = async () => {
            if (debouncedMemberQuery.length < 2) {
                setMemberResults([]);
                return;
            }

            setIsSearchingMember(true);
            const res = await searchMembersAction(debouncedMemberQuery);
            if (res.success && res.data) {
                setMemberResults(res.data as any);
            } else {
                setMemberResults([]);
            }
            setIsSearchingMember(false);
        };

        searchMembers();
    }, [debouncedMemberQuery]);

    const resetForm = () => {
        setActiveTab('member');
        setIsLoading(false);
        setError(null);
        setSuccessMessage(null);
        setMemberQuery('');
        setMemberResults([]);
        setSelectedMember(null);
        setGuestName('');
        setGuestEmail('');
        setGuestPhone('');
    };

    const handleMemberSelect = (user: UserResult) => {
        setSelectedMember(user);
        setMemberResults([]);
    };

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        setError(null);
        setIsLoading(true);

        const guestData = activeTab === 'guest' ? { name: guestName, email: guestEmail, phone: guestPhone } : undefined;
        const memberData = activeTab === 'member' ? selectedMember : undefined;

        if (activeTab === 'member' && !selectedMember) {
            setError('Selecteer een lid');
            setIsLoading(false);
            return;
        }

        const res = await createManualSignupAction(Number(eventId), eventName, activeTab, guestData, memberData);

        if (res.success) {
            const name = activeTab === 'member' ? `${selectedMember!.first_name} ${selectedMember!.last_name || ''}` : guestName;
            setSuccessMessage(`Succesvol ingeschreven: ${name}`);
            setTimeout(() => {
                onClose();
                window.location.reload();
            }, 1000);
        } else {
            setError(res.error || 'Er is een fout opgetreden.');
        }

        setIsLoading(false);
    };

    if (!isOpen) return null;

    return (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4">
            <div className="absolute inset-0 bg-slate-900/50 backdrop-blur-sm" onClick={onClose} />
            <div className="bg-white dark:bg-slate-800 w-full max-w-xl rounded-3xl shadow-2xl overflow-hidden flex flex-col max-h-[90vh] relative z-10 scale-100 animate-in zoom-in-95 duration-200 ring-1 ring-slate-200 dark:ring-slate-700/50">
                {/* Header */}
                <div className="p-6 border-b border-slate-100 dark:border-slate-700/50 flex justify-between items-center bg-slate-50/50 dark:bg-slate-800/80">
                    <h2 className="text-xl font-extrabold text-slate-900 dark:text-white flex items-center gap-3">
                        <div className="bg-purple-100 text-purple-600 dark:bg-purple-500/20 dark:text-purple-400 p-2 rounded-xl">
                            <UserPlus className="h-5 w-5" />
                        </div>
                        Handmatig Inschrijven
                    </h2>
                    <button onClick={onClose} className="text-slate-400 hover:text-slate-600 dark:hover:text-slate-300 hover:bg-slate-100 dark:hover:bg-slate-700 p-2 rounded-full transition-colors focus:outline-none focus:ring-2 focus:ring-slate-300">
                        <X className="h-5 w-5" />
                    </button>
                </div>

                {/* Tabs */}
                <div className="flex bg-slate-50 dark:bg-slate-900/50 p-2 border-b border-slate-100 dark:border-slate-700/50 gap-2">
                    <button
                        className={`flex-1 py-3 text-sm font-bold rounded-xl transition-all flex justify-center items-center gap-2 ${activeTab === 'member'
                            ? 'bg-white text-purple-600 shadow-sm ring-1 ring-slate-200 select-none dark:bg-slate-800 dark:ring-slate-700 dark:text-purple-400'
                            : 'text-slate-500 hover:text-slate-700 hover:bg-slate-100 dark:text-slate-400 dark:hover:bg-slate-800/50 dark:hover:text-slate-300'
                            }`}
                        onClick={() => setActiveTab('member')}
                    >
                        <User className="h-4 w-4" />
                        Geregistreerd Lid
                    </button>
                    <button
                        className={`flex-1 py-3 text-sm font-bold rounded-xl transition-all flex justify-center items-center gap-2 ${activeTab === 'guest'
                            ? 'bg-white text-purple-600 shadow-sm ring-1 ring-slate-200 select-none dark:bg-slate-800 dark:ring-slate-700 dark:text-purple-400'
                            : 'text-slate-500 hover:text-slate-700 hover:bg-slate-100 dark:text-slate-400 dark:hover:bg-slate-800/50 dark:hover:text-slate-300'
                            }`}
                        onClick={() => setActiveTab('guest')}
                    >
                        <UserPlus className="h-4 w-4" />
                        Gast (Niet-lid)
                    </button>
                </div>

                {/* Body */}
                <div className="p-8 overflow-y-auto">
                    {error && (
                        <div className="mb-6 p-4 bg-red-50 dark:bg-red-500/10 text-red-700 dark:text-red-400 rounded-xl text-sm border border-red-200 dark:border-red-500/20 flex items-start gap-3">
                            <XCircle className="h-5 w-5 shrink-0" />
                            <span className="font-medium leading-relaxed">{error}</span>
                        </div>
                    )}
                    {successMessage && (
                        <div className="mb-6 p-4 bg-green-50 dark:bg-green-500/10 text-green-700 dark:text-green-400 rounded-xl text-sm border border-green-200 dark:border-green-500/20 flex items-center gap-3">
                            <CheckCircle className="h-5 w-5 shrink-0" />
                            <span className="font-medium leading-relaxed">{successMessage}</span>
                        </div>
                    )}

                    <form onSubmit={handleSubmit} className="space-y-6">
                        {activeTab === 'member' ? (
                            <div className="relative">
                                <label className="block text-sm font-bold text-slate-700 dark:text-slate-300 mb-2">
                                    Zoek bestaand lid
                                </label>
                                {selectedMember ? (
                                    <div className="flex items-center justify-between p-4 bg-slate-50 dark:bg-slate-900/50 ring-1 ring-slate-200 dark:ring-slate-700/50 rounded-2xl">
                                        <div className="flex items-center gap-4">
                                            <div className="h-10 w-10 flex items-center justify-center bg-purple-100 text-purple-600 dark:bg-purple-500/20 dark:text-purple-400 font-bold rounded-full">
                                                {selectedMember.first_name[0]}{selectedMember.last_name?.[0] || ''}
                                            </div>
                                            <div>
                                                <p className="font-bold text-slate-900 dark:text-white">
                                                    {selectedMember.first_name} {selectedMember.last_name}
                                                </p>
                                                <p className="text-sm text-slate-500 dark:text-slate-400">{selectedMember.email}</p>
                                            </div>
                                        </div>
                                        <button
                                            type="button"
                                            onClick={() => setSelectedMember(null)}
                                            className="w-8 h-8 flex items-center justify-center rounded-full text-slate-400 hover:text-red-500 hover:bg-red-50 dark:hover:bg-red-500/10 transition-colors"
                                        >
                                            <X className="h-4 w-4" />
                                        </button>
                                    </div>
                                ) : (
                                    <div>
                                        <div className="relative">
                                            <Search className="absolute left-4 top-1/2 -translate-y-1/2 h-5 w-5 text-slate-400" />
                                            <input
                                                suppressHydrationWarning
                                                type="text"
                                                placeholder="Typ om te zoeken op voornaam..."
                                                value={memberQuery}
                                                onChange={(e) => setMemberQuery(e.target.value)}
                                                onKeyDown={(e) => {
                                                    if (e.key === 'Enter') {
                                                        e.preventDefault();
                                                        if (memberResults.length > 0) {
                                                            handleMemberSelect(memberResults[0]);
                                                        }
                                                    }
                                                }}
                                                className="w-full pl-12 pr-10 py-3 rounded-2xl bg-white dark:bg-slate-900 ring-1 ring-slate-200 dark:ring-slate-700 text-slate-900 dark:text-white placeholder:text-slate-400 focus:ring-2 focus:ring-purple-500 outline-none transition-all font-medium"
                                                autoFocus
                                            />
                                            {isSearchingMember && (
                                                <div className="absolute right-4 top-1/2 -translate-y-1/2">
                                                    <Loader2 className="h-5 w-5 animate-spin text-purple-500" />
                                                </div>
                                            )}
                                        </div>

                                        {/* Dropdown Results */}
                                        {memberResults.length > 0 && !selectedMember && (
                                            <div className="w-full mt-2 bg-white dark:bg-slate-800 border border-slate-200 dark:border-slate-700 rounded-2xl shadow-xl max-h-60 overflow-y-auto py-2">
                                                {memberResults.map((user) => (
                                                    <button
                                                        key={user.id}
                                                        type="button"
                                                        onClick={() => handleMemberSelect(user)}
                                                        className="w-full text-left px-5 py-3 hover:bg-slate-50 dark:hover:bg-slate-700/50 transition-colors flex flex-col items-start gap-0.5"
                                                    >
                                                        <span className="font-bold text-slate-900 dark:text-white">{user.first_name} {user.last_name}</span>
                                                        <span className="text-sm font-medium text-slate-500 dark:text-slate-400">{user.email}</span>
                                                    </button>
                                                ))}
                                            </div>
                                        )}
                                        {memberQuery.length >= 2 && !isSearchingMember && memberResults.length === 0 && (
                                            <p className="mt-3 ml-2 text-sm font-medium text-slate-500 dark:text-slate-400">Niemand gevonden.</p>
                                        )}
                                    </div>
                                )}
                            </div>
                        ) : (
                            // Guest Form
                            <div className="space-y-4">
                                <div>
                                    <label className="block text-sm font-bold text-slate-700 dark:text-slate-300 mb-2">Naam Gast *</label>
                                    <input
                                        suppressHydrationWarning
                                        type="text"
                                        required
                                        value={guestName}
                                        onChange={(e) => setGuestName(e.target.value)}
                                        className="w-full px-4 py-3 rounded-2xl bg-white dark:bg-slate-900 ring-1 ring-slate-200 dark:ring-slate-700 text-slate-900 dark:text-white focus:ring-2 focus:ring-purple-500 outline-none transition-all font-medium"
                                        placeholder="Volledige naam"
                                    />
                                </div>
                                <div>
                                    <label className="block text-sm font-bold text-slate-700 dark:text-slate-300 mb-2">E-mailadres *</label>
                                    <input
                                        suppressHydrationWarning
                                        type="email"
                                        required
                                        value={guestEmail}
                                        onChange={(e) => setGuestEmail(e.target.value)}
                                        className="w-full px-4 py-3 rounded-2xl bg-white dark:bg-slate-900 ring-1 ring-slate-200 dark:ring-slate-700 text-slate-900 dark:text-white focus:ring-2 focus:ring-purple-500 outline-none transition-all font-medium"
                                        placeholder="email@voorbeeld.nl"
                                    />
                                </div>
                                <div>
                                    <label className="block text-sm font-bold text-slate-700 dark:text-slate-300 mb-2">Telefoonnummer</label>
                                    <input
                                        suppressHydrationWarning
                                        type="tel"
                                        value={guestPhone}
                                        onChange={(e) => setGuestPhone(e.target.value)}
                                        className="w-full px-4 py-3 rounded-2xl bg-white dark:bg-slate-900 ring-1 ring-slate-200 dark:ring-slate-700 text-slate-900 dark:text-white focus:ring-2 focus:ring-purple-500 outline-none transition-all font-medium"
                                        placeholder="Optioneel"
                                    />
                                </div>
                            </div>
                        )}

                        <div className="flex gap-4 pt-6 mt-4 border-t border-slate-100 dark:border-slate-700/50">
                            <button
                                type="button"
                                onClick={onClose}
                                className="flex-1 px-4 py-3 bg-slate-100 hover:bg-slate-200 dark:bg-slate-700 dark:hover:bg-slate-600 text-slate-700 dark:text-slate-200 rounded-xl font-bold transition-all"
                                disabled={isLoading}
                            >
                                Annuleren
                            </button>
                            <button
                                type="submit"
                                disabled={isLoading}
                                className="flex-1 px-4 py-3 bg-purple-600 hover:bg-purple-700 text-white rounded-xl shadow-sm font-bold transition-all disabled:opacity-50 disabled:cursor-not-allowed flex items-center justify-center gap-2 hover:-translate-y-0.5"
                            >
                                {isLoading ? (
                                    <>
                                        <Loader2 className="h-5 w-5 animate-spin" />
                                        Bezig...
                                    </>
                                ) : (
                                    'Bevestig Inschrijving'
                                )}
                            </button>
                        </div>
                    </form>
                </div>
            </div>
        </div>
    );
}

'use client';

import { useState, useMemo, useOptimistic, useTransition } from 'react';
import {
    Calendar,
    Phone,
    Shield,
    Clock,
    Award,
    Hash,
    Layers,
    Mail,
    User as UserIcon,
    History,
    Settings,
    Plus,
    Trash2,
    CheckCircle2,
    Circle,
    Loader2,
    CheckCircle,
    XCircle,
    Info,
    Edit,
    Save,
    X,
    RefreshCw,
    CalendarPlus,
    ShieldAlert,
    AlertCircle
} from 'lucide-react';
import { format } from 'date-fns';
import { nl } from 'date-fns/locale';
import { 
    manageAzureMembershipAction, 
    updateMemberProfileAction, 
    renewMembershipAction,
    provisionAzureAccountAction 
} from '@/server/actions/leden.actions';
import { triggerUserSyncAction } from '@/server/actions/azure-sync.actions';
import { getImageUrl } from '@/lib/image-utils';

interface Member {
    id: string;
    first_name: string;
    last_name: string;
    email: string;
    date_of_birth: string | null;
    membership_expiry: string | null;
    status: string;
    phone_number: string | null;
    avatar: string | null;
    entra_id?: string | null;
}

interface CommitteeMembership {
    id: string;
    is_leader: boolean;
    committee_id: {
        id: string;
        name: string;
        is_visible: boolean;
        azure_group_id?: string | null;
    };
}

interface Signup {
    id: number;
    payment_status?: string;
    created_at: string;
    event_id: {
        id: string;
        name: string;
        event_date: string;
    };
}

export default function LedenDetailIsland({ 
    member, 
    initialMemberships, 
    signups,
    allCommittees,
    isAdmin 
}: { 
    member: Member, 
    initialMemberships: CommitteeMembership[],
    signups: Signup[],
    allCommittees: any[],
    isAdmin: boolean
}) {
    const [activeTab, setActiveTab] = useState<'profiel' | 'activiteiten' | 'beheer'>('profiel');
    const [isPending, startTransition] = useTransition();
    const [isActionInProgress, setIsActionInProgress] = useState<string | null>(null);

    // Profile editing
    const [isEditingProfile, setIsEditingProfile] = useState(false);
    const [editProfile, setEditProfile] = useState({
        first_name: member.first_name,
        last_name: member.last_name,
        phone_number: member.phone_number || '',
        date_of_birth: member.date_of_birth || '',
    });
    const [savingProfile, setSavingProfile] = useState(false);
    const [profileError, setProfileError] = useState<string | null>(null);
    const [localMember, setLocalMember] = useState(member);

    // Membership renewal
    const [renewMonths, setRenewMonths] = useState(12);
    const [renewLoading, setRenewLoading] = useState(false);
    const [renewResult, setRenewResult] = useState<string | null>(null);

    // Force sync
    const [syncLoading, setSyncLoading] = useState(false);
    const [syncResult, setSyncResult] = useState<string | null>(null);

    // Provisioning
    const [provisioningLoading, setProvisioningLoading] = useState(false);
    const [provisioningResult, setProvisioningResult] = useState<string | null>(null);

    // Optimistic memberships
    const [optimisticMemberships, setOptimisticMemberships] = useOptimistic(
        initialMemberships,
        (state: CommitteeMembership[], { action, membership }: { action: 'add' | 'remove' | 'toggle', membership: any }) => {
            if (action === 'add') return [...state, membership];
            if (action === 'remove') return state.filter(m => m.id !== membership.id);
            if (action === 'toggle') return state.map(m => m.id === membership.id ? { ...m, is_leader: !m.is_leader } : m);
            return state;
        }
    );

    const cleanName = (name: string) => {
        return name
            .replace(/\s*(\|\||\||–|-)\s*Salve\s*Mundi/gi, '')
            .replace(/\s*SaMu\s*(\|\||\|)\s*/gi, '')
            .trim();
    };

    const { realCommittees, otherGroups } = useMemo(() => {
        const EXCLUDED_GROUPS = ['Alle gebruikers', 'Leden_Actief_Lidmaatschap', 'Leden_Verlopen_Lidmaatschap'];
        const real: CommitteeMembership[] = [];
        const groups: CommitteeMembership[] = [];

        optimisticMemberships.forEach(cm => {
            const rawName = cm.committee_id?.name || 'Onbekend';
            if (!rawName || EXCLUDED_GROUPS.includes(rawName)) return;

            if (cm.committee_id?.is_visible === true) {
                real.push(cm);
            } else {
                groups.push(cm);
            }
        });

        return { realCommittees: real, otherGroups: groups };
    }, [optimisticMemberships]);

    const formatDate = (dateString: string | null) => {
        if (!dateString) return 'Onbekend';
        try {
            return format(new Date(dateString), 'd MMMM yyyy', { locale: nl });
        } catch (e) {
            return 'Onbekend';
        }
    };

    const isMembershipActive = useMemo(() => {
        if (!member.membership_expiry) return false;
        const todayStr = new Date().toISOString().substring(0, 10);
        return member.membership_expiry.substring(0, 10) >= todayStr;
    }, [member.membership_expiry]);

    async function handleMembershipChange(azureGroupId: string, action: 'add' | 'remove', committeeName: string) {
        if (!localMember.entra_id) {
            alert("Dit lid heeft geen gekoppeld Azure account! Maak deze eerst aan onder het tabblad 'Beheer'.");
            setActiveTab('beheer');
            return;
        }

        if (action === 'remove' && !confirm(`Weet je zeker dat je ${localMember.first_name} wilt verwijderen uit ${committeeName}? Dit wordt direct in Azure aangepast.`)) {
            return;
        }

        setIsActionInProgress(`${action}-${azureGroupId}`);
        startTransition(async () => {
             const res = await manageAzureMembershipAction(localMember.entra_id!, azureGroupId, action, localMember.id);
             if (!res.success) {
                  alert(res.error || "Fout bij het bijwerken van lidmaatschap");
             }
        });
        setIsActionInProgress(null);
    }

    async function handleSaveProfile() {
        setSavingProfile(true);
        setProfileError(null);
        const res = await updateMemberProfileAction(localMember.id, editProfile);
        if (res.success) {
            setLocalMember(prev => ({ ...prev, ...editProfile }));
            setIsEditingProfile(false);
        } else {
            setProfileError(res.error ?? 'Opslaan mislukt');
        }
        setSavingProfile(false);
    }

    async function handleRenewMembership() {
        if (!confirm(`Weet je zeker dat je het lidmaatschap van ${localMember.first_name} ${localMember.last_name} met ${renewMonths} maand(en) verlengt?`)) return;
        setRenewLoading(true);
        setRenewResult(null);
        const res = await renewMembershipAction(localMember.id, renewMonths);
        if (res.success) {
            setRenewResult(`✓ Verlengd tot ${res.newExpiry}`);
            setLocalMember(prev => ({ ...prev, membership_expiry: res.newExpiry ?? prev.membership_expiry }));
        } else {
            setRenewResult(`✗ ${res.error}`);
        }
        setRenewLoading(false);
    }

    async function handleForceSync() {
        setSyncLoading(true);
        setSyncResult(null);
        const res = await triggerUserSyncAction(localMember.id);
        setSyncResult(res.success ? '✓ Synchronisatie gestart' : `✗ ${res.error}`);
        setSyncLoading(false);
    }

    async function handleProvisionAzure() {
        if (!confirm(`Weet je zeker dat je een Azure account wilt aanmaken voor ${localMember.first_name}? Er wordt direct een welkom-mail verstuurd.`)) return;
        setProvisioningLoading(true);
        setProvisioningResult(null);
        const res = await provisionAzureAccountAction(localMember.id);
        if (res.success) {
            setProvisioningResult('✓ Aanvraag ingediend! Het account wordt binnen enkele minuten aangemaakt en de welkomstmail verzonden.');
        } else {
            setProvisioningResult(`✗ ${res.error}`);
        }
        setProvisioningLoading(false);
    }

    const availableCommittees = useMemo(() => {
        const currentIds = new Set(optimisticMemberships.map(m => m.committee_id.id));
        return allCommittees.filter(c => !currentIds.has(c.id) && c.azure_group_id);
    }, [allCommittees, optimisticMemberships]);

    return (
        <div className="container mx-auto px-4 py-8 max-w-7xl">
            {/* Header info moved to page.tsx PageHeader, but we add a mini profile header here if needed */}
            <div className="flex flex-col md:flex-row md:items-center gap-6 mb-12">
                            <div className="relative group">
                    <div className="h-24 w-24 rounded-3xl bg-primary/10 flex items-center justify-center text-primary font-black text-3xl shadow-xl ring-4 ring-white dark:ring-slate-800 transition-transform group-hover:scale-105">
                        {localMember.avatar ? (
                            <img src={getImageUrl(localMember.avatar, { width: 100, height: 100, fit: 'cover' }) || ''} alt="avatar" className="h-full w-full object-cover rounded-3xl" />
                        ) : (
                            <>{localMember.first_name?.[0]}{localMember.last_name?.[0]}</>
                        )}
                    </div>
                </div>
                <div className="space-y-2">
                    <h1 className="text-3xl font-black text-slate-900 dark:text-white leading-none">
                        {localMember.first_name} {localMember.last_name}
                    </h1>
                    <div className="flex flex-wrap items-center gap-3">
                        <span className="text-slate-500 dark:text-slate-400 font-bold flex items-center gap-1.5 text-sm">
                            <Mail className="h-4 w-4" /> {localMember.email}
                        </span>
                        <div suppressHydrationWarning className={`px-3 py-1 rounded-full text-[10px] font-black uppercase tracking-widest ${isMembershipActive
                                ? 'bg-green-100 text-green-700 dark:bg-green-500/10 dark:text-green-400'
                                : 'bg-red-100 text-red-700 dark:bg-red-500/10 dark:text-red-400'
                            }`}>
                            {isMembershipActive ? 'Actief Lidmaatschap' : 'Lidmaatschap Verlopen'}
                        </div>
                    </div>
                </div>
            </div>

            {/* Tabs Navigation */}
            <div className="flex gap-1 mb-8 bg-slate-100 dark:bg-slate-900/50 p-1 rounded-2xl w-fit">
                <button
                    onClick={() => setActiveTab('profiel')}
                    className={`flex items-center gap-2 px-6 py-2.5 rounded-xl font-bold transition-all text-sm ${activeTab === 'profiel' ? 'bg-white dark:bg-slate-800 shadow-sm text-primary' : 'text-slate-500 hover:text-slate-700 dark:hover:text-slate-300'}`}
                >
                    <UserIcon className="h-4 w-4" /> Profiel
                </button>
                <button
                    onClick={() => setActiveTab('activiteiten')}
