'use client';

import React, { useState } from 'react';
import { submitIntroSignup } from '@/server/actions/intro.actions';
import { FormField } from '@/shared/ui/FormField';
import { Input } from '@/shared/ui/Input';
import { PhoneInput } from '@/shared/ui/PhoneInput';
import { isValidPhoneNumber } from '@/shared/lib/phone-validation';
import { Users, CheckCircle2 } from 'lucide-react';

export const IntroStudentIsland = () => {
    const [form, setForm] = useState({
        voornaam: '',
        tussenvoegsel: '',
        achternaam: '',
        geboortedatum: '',
        email: '',
        telefoonnummer: '',
        favorieteGif: '',
        website: '', // Honeypot
    });

    const [submitted, setSubmitted] = useState(false);
    const [isSubmitting, setIsSubmitting] = useState(false);
    const [error, setError] = useState<string | null>(null);
    const [phoneError, setPhoneError] = useState<string | null>(null);

    const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement>) => {
        setForm({ ...form, [e.target.name]: e.target.value });
        if (error) setError(null);
        if (e.target.name === 'telefoonnummer' && phoneError) setPhoneError(null);
    };

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        setError(null);
        setPhoneError(null);

        // Filter bots
        if (form.website) {
            setSubmitted(true);
            return;
        }

        if ((form.voornaam + form.achternaam).match(/https?:\/\//)) {
            setError('Ongeldige invoer.');
            return;
        }

        if (!isValidPhoneNumber(form.telefoonnummer)) {
            setPhoneError('Ongeldig telefoonnummer');
            return;
        }

        setIsSubmitting(true);

        try {
            const result = await submitIntroSignup(form);
            if (result.success) {
                setSubmitted(true);
            }
        } catch (err) {
            const message = err instanceof Error ? err.message : 'Er is een fout opgetreden bij het versturen van je inschrijving.';
            setError(message);
        } finally {
            setIsSubmitting(false);
        }
    };

    if (submitted) {
        return (
            <div className="bg-gradient-theme rounded-2xl lg:rounded-3xl p-6 lg:p-8 text-center shadow-lg">
                <CheckCircle2 className="w-12 h-12 lg:w-16 lg:h-16 text-white mx-auto mb-4" />
                <h2 className="text-2xl lg:text-3xl font-bold text-theme-purple-lighter mb-4">Bedankt!</h2>
                <p className="text-theme-white text-base lg:text-lg">We hebben je inschrijving ontvangen.</p>
            </div>
        );
    }

    return (
        <form onSubmit={handleSubmit} className="space-y-4 lg:space-y-6">
            <FormField label="Voornaam" required>
                <Input
                    name="voornaam"
                    value={form.voornaam}
                    onChange={handleChange}
                    required
                    autoComplete="given-name"
                />
            </FormField>

            <FormField label="Tussenvoegsel">
                <Input
                    name="tussenvoegsel"
                    value={form.tussenvoegsel}
                    onChange={handleChange}
                    autoComplete="additional-name"
                />
            </FormField>

            <FormField label="Achternaam" required>
                <Input
                    name="achternaam"
                    value={form.achternaam}
                    onChange={handleChange}
                    required
                    autoComplete="family-name"
                />
            </FormField>

            <FormField label="Geboortedatum" required>
                <Input
                    type="date"
                    name="geboortedatum"
                    value={form.geboortedatum}
                    onChange={handleChange}
                    required
                    autoComplete="bday"
                />
            </FormField>

            <FormField label="E-mailadres" required>
                <Input
                    type="email"
                    name="email"
                    value={form.email}
                    onChange={handleChange}
                    required
                    autoComplete="email"
                />
            </FormField>

            <FormField label="Telefoonnummer" required error={phoneError ?? undefined}>
                <PhoneInput
                    name="telefoonnummer"
                    value={form.telefoonnummer}
                    onChange={handleChange}
                    required
                    autoComplete="tel"
                    error={!!phoneError}
                />
            </FormField>

            <FormField label="Favoriete GIF URL (optioneel)">
                <Input
                    type="url"
                    name="favorieteGif"
                    value={form.favorieteGif}
                    onChange={handleChange}
                    placeholder="https://..."
                />
            </FormField>
            {error && <p className="text-red-500 dark:text-red-400 text-xs lg:text-sm">{error}</p>}
            <button
                type="submit"
                disabled={isSubmitting}
                className="form-button w-full mt-4"
            >
                {isSubmitting ? 'Bezig...' : 'Verstuur'}
            </button>
        </form>
    );
};

'use client';

import React, { useEffect, useState, useTransition } from 'react';
import { useRouter, useSearchParams } from 'next/navigation';
import { getKroegentochtStatus } from '@/server/actions/kroegentocht.actions';
import { CheckCircle2, XCircle, Loader2, Home, ArrowRight } from 'lucide-react';
import Link from 'next/link';

export default function KroegentochtConfirmationIsland() {
    const router = useRouter();
    const searchParams = useSearchParams();
    const signupId = searchParams.get('id');

    const [status, setStatus] = useState<'loading' | 'paid' | 'failed' | 'open'>('loading');
    const [signupData, setSignupData] = useState<any>(null);
    const [attempts, setAttempts] = useState(0);

    useEffect(() => {
        if (!signupId) {
            setStatus('failed');
            return;
        }

        const checkStatus = async () => {
            const result = await getKroegentochtStatus(signupId);

            if (result.status === 'paid') {
                setStatus('paid');
                setSignupData(result.signup);
            } else if (result.status === 'failed' || result.status === 'error') {
                setStatus('failed');
            } else {
                // Keep polling if open, up to 10 times
                if (attempts < 10) {
                    setTimeout(() => setAttempts(a => a + 1), 2000);
                } else {
                    setStatus('failed');
                }
            }
        };

        checkStatus();
    }, [signupId, attempts]);

    if (status === 'loading' || (status === 'open' && attempts < 10)) {
        return (
            <div className="flex flex-col items-center justify-center py-20 animate-in fade-in duration-700">
                <Loader2 className="w-12 h-12 text-[var(--color-purple-theme)] animate-spin mb-6" />
                <h1 className="text-2xl font-black mb-2">Betaling verwerken...</h1>
                <p className="text-slate-500 dark:text-slate-400">Een ogenblik geduld, we checken de status van je transactie.</p>
            </div>
        );
    }

    if (status === 'paid') {
        return (
            <div className="flex flex-col items-center py-10 sm:py-20 animate-in zoom-in-95 duration-500">
                <div className="w-20 h-20 bg-green-100 dark:bg-green-500/20 rounded-full flex items-center justify-center mb-8 shadow-lg shadow-green-500/20">
                    <CheckCircle2 className="w-10 h-10 text-green-600 dark:text-green-500" />
                </div>

                <h1 className="text-3xl sm:text-4xl font-black text-center mb-4">
                    Betaling Gelukt!
                </h1>
                <p className="text-slate-600 dark:text-slate-400 text-center max-w-md mb-10 leading-relaxed px-4">
                    Je bent officieel ingeschreven voor de Kroegentocht. We hebben de tickets ook naar je e-mailadres gestuurd.
                </p>

                <div className="grid grid-cols-1 sm:grid-cols-2 gap-4 w-full max-w-lg px-4">
                    <Link 
