                    )}

                    {/* Onderste acties: stickers-link + uitlogknop */}
                    <div className="mt-auto w-full">
                        <div className="flex items-center justify-between px-2">
                            <Link
                                href={ROUTES.SAFE_HAVENS}
                                onClick={() => setMenuOpen(false)}
