/**
 * Authentication and authorization utilities for Salve Mundi V7.
 */

import { hasPermission, type Committee } from '@/shared/lib/permissions';
import { AdminResource } from '@/shared/lib/permissions-config';

/**
 * Checks if a user has "Super Admin" privileges.
 * This logic is used both on the server and client to gate administrative features.
 * 
 * @param committees List of committees
 * @returns boolean
 */
export function isSuperAdmin(committees: Committee[] | null | undefined): boolean {
    if (!committees || !Array.isArray(committees)) return false;

    // We use the Intro resource as a general "SuperAdmin" check
    return hasPermission(committees, AdminResource.Intro);
}

/**
 * Checks if a user is a member of any committee.
 * 
 * @param committees List of committees
 * @returns boolean
 */
export function isCommitteeMember(committees: any[] | null | undefined): boolean {
    return Array.isArray(committees) && committees.length > 0;
}

import { cookies } from 'next/headers';
import { getSystemDirectus } from './directus';

/**
 * Get a Directus client that automatically applies the Impersonate Token.
 * Gebruik deze async functie in Next.js Server Components en Server Actions.
 */
/**
 * Get a Directus client with system-level permissions.
 * Consistent with the "no user token" policy.
 */
export async function getDirectusClient() {
    return getSystemDirectus();
}

import { createDirectus, rest, staticToken } from '@directus/sdk';
import { type DirectusSchema } from '@salvemundi/validations';

const directusUrl = process.env.DIRECTUS_SERVICE_URL!;

/**
 * Get a Directus client with system-level permissions.
 * Used for public data or background tasks.
 */
export function getSystemDirectus() {
    return createDirectus<DirectusSchema>(directusUrl, {
        globals: {
            fetch: (url, options) => {
                const urlStr = url.toString();
                // Add next tags for sticker-related items to enable granular revalidation
                const nextOptions: any = {};
                if (urlStr.includes('/items/Stickers')) {
                    nextOptions.tags = ['stickers'];
                }

                return fetch(url, {
                    ...options,
                    signal: AbortSignal.timeout(10000),
                    next: Object.keys(nextOptions).length > 0 ? nextOptions : undefined
                } as RequestInit);
            }
        }
    })
        .with(staticToken(process.env.DIRECTUS_STATIC_TOKEN!))
        .with(rest());
}

