export async function updatePubCrawlSignupWithQRToken(signupId: number | string, token: string) {
    try {
        await getSystemDirectus().request(updateItem(COLLECTIONS.PUB_CRAWL_SIGNUPS as any, signupId as any, {
            qr_token: token
        }));
    } catch (err) {
