        return await getSystemDirectus().request(readItems('event_signups', {
            filter: { event_id: { _eq: eventId } },
            fields: EVENT_SIGNUP_FIELDS as any
        })) as unknown as DbEventSignup[];
    } catch (error) {
        console.error(`[Activities] Error fetching signups for ${eventId}:`, error);
        return [];
    }
}

export async function getSignupStatus(id?: string, transactionId?: string) {
    if (transactionId) {
        try {
            const transactions = await getSystemDirectus().request(readItems('transactions', {
                fields: TRANSACTION_FIELDS,
                filter: { id: { _eq: transactionId } },
                limit: 1
            })) as unknown as DbTransaction[]; // Forced cast to satisfy compiler overlap checks with SDK return type

            const trans = transactions?.[0];

            if (!trans) return { status: 'error' };

            // Use explicit comparison with product_type, which is now correctly recognized via DbTransaction
            if (trans.product_type === 'event_signup') {
                const signups = await getSystemDirectus().request(readItems('event_signups', {
                    fields: ['id', 'payment_status', 'participant_name', { event_id: ['id', 'name'] }] as any,
                    filter: { id: { _eq: trans.registration } },
                    limit: 1
                }));
                const signup = signups?.[0];
                return { status: trans.payment_status, signup, transaction: trans };
            } else if (trans.product_type === 'pub_crawl_signup') {
                const signups = await getSystemDirectus().request(readItems('pub_crawl_signups', {
                    fields: [...PUB_CRAWL_SIGNUP_FIELDS, { pub_crawl_event_id: ['name'] }, { tickets: ['id', 'name', 'qr_token'] }] as any,
                    filter: { id: { _eq: trans.pub_crawl_signup } },
                    limit: 1
                }));
                const signup = signups?.[0];
                if (signup) {
                    // Inject ticket count for the UI overview
                    (signup as { amount_tickets?: number }).amount_tickets = (signup as { tickets?: unknown[] }).tickets?.length || 1;
                }
                return { status: trans.payment_status, signup, transaction: trans };
            } else if (trans.product_type === 'membership') {
                return { status: trans.payment_status, transaction: trans, isMembership: true };
            } else if (trans.product_type === 'trip_signup') {
                return { status: trans.payment_status, transaction: trans, isTrip: true };
            }
            return { status: trans.payment_status, transaction: trans };
        } catch (e) {
            console.error('[Activities] Error resolving transaction:', e);
            return { status: 'error' };
        }
    } else if (id) {
        try {
            const signups = await getSystemDirectus().request(readItems('event_signups', {
                fields: [...EVENT_SIGNUP_FIELDS, { event_id: ['id', 'name'] }] as any,
                filter: { id: { _eq: id } },
                limit: 1
            }));
            const signup = signups?.[0];
            if (!signup) return { status: 'error' };
            return { status: signup.payment_status || 'open', signup };
        } catch (e) {
            console.error('[Activities] Error fetching signup status:', e);
            return { status: 'error' };
        }
    }

    return { status: 'error' };
}

export async function getMyTickets() {
    const session = await auth.api.getSession({ headers: await headers() });
    const userId = session?.user?.id;
    if (!userId) return [];

    try {
        const query = {
            filter: {
                directus_relations: {
                    _eq: userId
                }
            },
            fields: [...EVENT_SIGNUP_FIELDS, { event_id: ['id', 'name', 'event_date', 'location'] }] as any,
            sort: ['-created_at']
        };

        // Explicitly cast query to any to bypass SDK internal tuple-widening issues with spread constants
        return await getSystemDirectus().request(readItems('event_signups', query as any)) as unknown as DbEventSignup[];
    } catch (error) {
        console.error('[Activities] Error fetching user tickets:', error);
        return [];
    }
}

'use server';

import { auth } from "@/server/auth/auth";
import { headers } from "next/headers";
import { revalidateTag, revalidatePath } from "next/cache";
import { cache } from "react";
import { getSystemDirectus } from "@/lib/directus";
import { 
    readItems, 
    createItem, 
    updateItem, 
    deleteItem, 
    uploadFiles,
    aggregate
} from "@directus/sdk";
import { 
    activityAdminSchema, 
    EVENT_FIELDS, 
    EVENT_ADMIN_FIELDS,
    AdminActivitySchema,
    type Activiteit
} from "@salvemundi/validations";
const EVENT_ID_FIELDS = ['id'] as const;
import { logAdminAction } from "./audit.actions";
import { isSuperAdmin } from "@/lib/auth-utils";

async function getSession() {
    return await auth.api.getSession({
        headers: await headers()
    });
}

const getNotificationUrl = (type: 'reminder' | 'custom') => {
    const baseUrl = process.env.INTERNAL_NOTIFICATION_API_URL || process.env.NEXT_PUBLIC_NOTIFICATION_API_URL;
    if (!baseUrl) return null;

    const url = new URL(baseUrl);
    url.pathname = url.pathname.replace(/\/send-email$/, type === 'reminder' ? '/send-reminder' : '/send-custom');
    return url.toString();
};

async function checkAdminAccess() {
    const session = await getSession();
    if (!session || !session.user) return null;

    const user = session.user as any;
    if (!isSuperAdmin((user as any).committees)) return null;
    return session;
}

export const getAdminActivities = cache(async (search?: string, filter: 'all' | 'upcoming' | 'past' = 'all') => {
    const session = await checkAdminAccess();
    if (!session) throw new Error("Unauthorized");

    try {
        const query: any = {
            fields: [
                ...EVENT_ADMIN_FIELDS,
                { image: ['id'] }
            ],
            sort: ['-event_date'],
            limit: -1,
            filter: {}
        };

        if (search) {
            query.filter._or = [
                { name: { _icontains: search } },
                { description: { _icontains: search } },
                { location: { _icontains: search } }
            ];
        }

        const now = new Date().toISOString();
        if (filter === 'upcoming') {
            query.filter.event_date = { _gte: now };
        } else if (filter === 'past') {
            query.filter.event_date = { _lt: now };
        }

        const events = await getSystemDirectus().request(readItems('events', query));

        const counts = await getSystemDirectus().request(
            aggregate('event_signups', {
                aggregate: { count: '*' },
                groupBy: ['event_id']
            })
        );

        const countMap = new Map((counts as any[]).map(c => [c.event_id, parseInt(c.count?.count || c.count || "0")]));

        const eventsWithCounts = events.map((event: any) => {
            return {
                ...event,
                signup_count: countMap.get(event.id) || 0
            };
        });

        return AdminActivitySchema.array().parse(eventsWithCounts);
    } catch (error) {
        console.error('[AdminActivities] Fetch failed:', error);
        return [];
    }
});

export async function sendActivityReminder(eventId: number) {
    if (!(await checkAdminAccess())) return { success: false, error: "Unauthorized" };

    try {
        const url = getNotificationUrl('reminder');
        if (!url) throw new Error("Notification API URL not configured");

        const response = await fetch(url, {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ eventId })
        });

        if (!response.ok) throw new Error("Failed to send reminder");
        const result = await response.json();

        return { success: true, sent: result.sent || 0 };
    } catch (error) {
        console.error("Failed to send activity reminder:", error);
        return { success: false, error: "Herinnering versturen mislukt" };
    }
}

export async function sendActivityCustomNotification(eventId: number, title: string, body: string) {
    if (!(await checkAdminAccess())) return { success: false, error: "Unauthorized" };

    try {
        const url = getNotificationUrl('custom');
        if (!url) throw new Error("Notification API URL not configured");

        const response = await fetch(url, {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({
                title,
                body,
                data: {
                    url: `/activiteit/${eventId}`,
                    eventId: eventId
                },
                tag: `custom-${eventId}`
            })
        });

        if (!response.ok) throw new Error("Failed to send custom notification");
        const result = await response.json();

        return { success: true, sent: result.sent || 0 };
    } catch (error) {
        console.error("Failed to send custom notification:", error);
        return { success: false, error: "Notificatie versturen mislukt" };
    }
}

export async function deleteActivity(eventId: number) {
    const session = await checkAdminAccess();
    if (!session) return { success: false, error: "Unauthorized" };

    try {
        await getSystemDirectus().request(deleteItem('events', eventId));
        await logAdminAction('activity_deleted', 'SUCCESS', { id: eventId });

        revalidateTag('events', 'default');
        revalidatePath('/beheer/activiteiten');
        revalidatePath('/beheer');
        return { success: true };
    } catch (error) {
        console.error("Failed to delete activity:", error);
        return { success: false, error: "Verwijderen mislukt" };
    }
}

export type CreateActivityResult = 
    | { success: true; id: number }
    | { success: false; error: string; fieldErrors?: Record<string, string[]> };

export async function createActivityAction(prevState: any, formData: FormData): Promise<CreateActivityResult> {
    const session = await checkAdminAccess();
    if (!session) return { error: "Unauthorized", success: false };

    const imageFile = formData.get('imageFile') as File | null;
    let imageId: string | null = null;

    if (imageFile && imageFile.size > 0 && imageFile.name !== 'undefined') {
        const fileData = new FormData();
        fileData.append('file', imageFile);
        try {
            const res = await getSystemDirectus().request(uploadFiles(fileData));
            imageId = res.id;
        } catch (e) {
            console.error('Image upload failed', e);
        }
    }

    const rawData: Record<string, any> = {};
    formData.forEach((value, key) => {
        if (key !== 'imageFile') rawData[key] = value;
    });

    const validated = activityAdminSchema.safeParse(rawData);
    if (!validated.success) {
        return { 
            error: "Validatie mislukt", 
            fieldErrors: validated.error.flatten().fieldErrors,
            success: false 
        };
    }

    const data = validated.data;
    const directusPayload: Record<string, any> = {
        ...data,
        status: data.status === 'scheduled' ? 'published' : data.status,
    };

    if (imageId) directusPayload.image = imageId;

    try {
        const res = await getSystemDirectus().request(createItem('events', directusPayload));
        await logAdminAction('activity_created', 'SUCCESS', { id: res.id, data: directusPayload });

        revalidateTag('events', 'default');
        revalidatePath('/beheer/activiteiten');
        revalidatePath('/beheer');
        if (typeof res.id !== 'number') {
            throw new Error('Geen ID teruggekregen van de database');
        }
        return { success: true, id: res.id };
    } catch (error) {
        console.error("Failed to create activity:", error);
        return { error: 'Fout bij opslaan in de database', success: false };
    }
}

export async function updateActivityAction(eventId: number, prevState: any, formData: FormData) {
    const session = await getSession();
    if (!session || !session.user) return { error: "Unauthorized", success: false };

    const user = session.user as any;
    const memberships = (user as any).committees || [];
    const isPowerful = isSuperAdmin(memberships);

    try {
        const existing = await getSystemDirectus().request(readItems('events', {
            fields: [...EVENT_ID_FIELDS, 'committee_id' as any],
            filter: { id: { _eq: eventId } },
            limit: 1
        }));

        if (!existing || existing.length === 0) return { error: "Activiteit niet gevonden", success: false };

        if (!isPowerful) {
            const isMember = existing[0].committee_id ? memberships.some((c: any) => String(c.id) === String(existing[0].committee_id)) : false;
            if (!isMember) return { error: "Geen rechten voor deze activiteit", success: false };
        }

        const imageFile = formData.get('imageFile') as File | null;
        let imageId: string | null | undefined = undefined;
        const removeImage = formData.get('removeImage') === 'true';

        if (imageFile && imageFile.size > 0 && imageFile.name !== 'undefined') {
            const fileData = new FormData();
            fileData.append('file', imageFile);
            const res = await getSystemDirectus().request(uploadFiles(fileData));
            imageId = res.id;
        } else if (removeImage) {
            imageId = null;
        }

        const rawData: Record<string, any> = {};
        formData.forEach((value, key) => {
            if (key !== 'imageFile' && key !== 'removeImage') rawData[key] = value;
        });

        const validated = activityAdminSchema.safeParse(rawData);
        if (!validated.success) {
            return { 
                error: "Validatie mislukt", 
                fieldErrors: validated.error.flatten().fieldErrors,
                success: false 
            };
        }

        const data = validated.data;
        const directusPayload: Record<string, any> = {
            ...data,
            status: data.status === 'scheduled' ? 'published' : data.status,
        };

        if (imageId !== undefined) directusPayload.image = imageId;

        await getSystemDirectus().request(updateItem('events', eventId, directusPayload));
        await logAdminAction('activity_updated', 'SUCCESS', { id: eventId, data: directusPayload });

        revalidateTag('events', 'default');
        revalidateTag(`event_${eventId}`, 'default');
        revalidatePath('/beheer/activiteiten');
        revalidatePath(`/beheer/activiteiten/${eventId}/bewerken`);
        revalidatePath('/beheer');

        return { success: true };
    } catch (error) {
        console.error("Failed to update activity:", error);
        return { error: 'Interne serverfout', success: false };
    }
}

'use server';

import { auth } from '@/server/auth/auth';
import { revalidateTag, revalidatePath } from "next/cache";
import { headers } from 'next/headers';

import { isSuperAdmin } from '@/lib/auth-utils';
import { getSystemDirectus } from '@/lib/directus';
import { readItems, updateItem, readUsers } from '@directus/sdk';
import { COMMITTEE_FIELDS, COMMITTEE_MEMBER_FIELDS, USER_ID_FIELDS } from '@salvemundi/validations';

const getAzureManagementUrl = () => process.env.AZURE_MANAGEMENT_SERVICE_URL;

const serviceHeaders = () => {
    const token = process.env.INTERNAL_SERVICE_TOKEN;
    if (!token) throw new Error('INTERNAL_SERVICE_TOKEN is missing');
    return { Authorization: `Bearer ${token}`, 'Content-Type': 'application/json' };
};

async function checkAccess() {
    const session = await auth.api.getSession({ headers: await headers() });
    if (!session?.user) throw new Error('Niet ingelogd');

    const user = session.user as any;
    if (!isSuperAdmin((user as any).committees)) {
        throw new Error('Geen toegang: SuperAdmin rechten vereist.');
    }

    return session;
}

export type Committee = {
    id: number;
    name: string;
    email?: string | null;
    azure_group_id?: string | null;
    description?: string | null;
    short_description?: string | null;
    image?: string | null;
};

export type CommitteeMember = {
    directusMembershipId?: number;
    entraId: string;
    displayName: string;
    email: string;
    isLeader: boolean;
};


export async function getCommittees(): Promise<Committee[]> {
    await checkAccess();
    try {
        const items = await getSystemDirectus().request(readItems('committees', {
            limit: 200,
            fields: [...COMMITTEE_FIELDS],
            sort: ['name']
        }));
        return (items ?? []).map(i => ({
            ...i,
            id: Number(i.id),
            name: i.name || '',
        })) as Committee[];
    } catch (e) {
        console.error('[AdminCommittees] Fetch failed:', e);
        throw new Error('Kon commissies niet ophalen');
    }
}

export async function updateCommitteeDetails(
    committeeId: string,
    payload: { short_description?: string; description?: string; image?: string }
): Promise<{ success: boolean; error?: string }> {
    const session = await checkAccess();

    try {
        await getSystemDirectus().request(updateItem('committees', committeeId, payload));
    revalidatePath(`/beheer/committees/${committeeId}`);
    revalidatePath('/beheer/committees');
    return { success: true };
    } catch (e) {
        console.error('[AdminCommittees] Update failed:', e);
        return { success: false, error: 'Opslaan mislukt' };
    }
}


export async function getCommitteeMembers(committeeId: string): Promise<CommitteeMember[]> {
    await checkAccess();
    try {
        const items = await getSystemDirectus().request(readItems('committee_members' as any, {
            filter: { committee_id: { _eq: committeeId } },
            fields: [
                ...COMMITTEE_MEMBER_FIELDS,
                { user_id: ['id', 'entra_id', 'first_name', 'last_name', 'email'] }
            ] as any,
            limit: 200
        }));

        return (items ?? [])
            .filter((r: any) => r.user_id)
            .map((r: any) => ({
                directusMembershipId: r.id,
                entraId: r.user_id.entra_id || r.user_id.id,
                displayName: `${r.user_id.first_name || ''} ${r.user_id.last_name || ''}`.trim() || r.user_id.email,
                email: r.user_id.email || '',
                isLeader: r.is_leader || false,
            }));
    } catch (e) {
        console.error('[AdminCommittees] Fetch members failed:', e);
        return [];
    }
}

export async function addCommitteeMember(
    azureGroupId: string,
    committeeId: string,
    userEmail: string
): Promise<{ success: boolean; error?: string }> {
    await checkAccess();

    const users = await getSystemDirectus().request(readUsers({
        filter: { email: { _eq: userEmail } },
        fields: [...USER_ID_FIELDS],
        limit: 1
    }));
    const user = users?.[0];
    if (!user?.entra_id) {
        return { success: false, error: 'Gebruiker niet gevonden in het systeem (email onbekend of niet gesynchroniseerd)' };
    }

    const azRes = await fetch(`${getAzureManagementUrl()}/api/groups/${encodeURIComponent(azureGroupId)}/members`, {
        method: 'POST',
        headers: serviceHeaders(),
        body: JSON.stringify({ userId: user.entra_id }),
    });
    if (!azRes.ok) {
        const err = await azRes.json().catch(() => ({}));
        console.error('[AdminCommittees] Add member Azure error:', err);
        return { success: false, error: 'Bewerking in Azure mislukt. Probeer het later opnieuw.' };
    }

    return { success: true };
}

export async function removeCommitteeMember(
    azureGroupId: string,
    entraId: string
): Promise<{ success: boolean; error?: string }> {
    await checkAccess();
    const azRes = await fetch(`${getAzureManagementUrl()}/api/groups/${encodeURIComponent(azureGroupId)}/members/${encodeURIComponent(entraId)}`, {
        method: 'DELETE',
        headers: serviceHeaders(),
    });
    if (!azRes.ok) {
        const err = await azRes.json().catch(() => ({}));
        console.error('[AdminCommittees] Remove member Azure error:', err);
        return { success: false, error: 'Verwijderen uit Azure groep mislukt.' };
    }
    return { success: true };
}

export async function toggleCommitteeLeader(
    membershipId: number,
    currentIsLeader: boolean,
    azureGroupId: string | null | undefined,
    entraId: string
): Promise<{ success: boolean; error?: string }> {
    const session = await checkAccess();

    try {
        await getSystemDirectus().request(updateItem('committee_members' as any, membershipId, { is_leader: !currentIsLeader }));
        revalidatePath('/beheer/vereniging');
    } catch (e) {
        console.error('[AdminCommittees] Toggle leader failed:', e);
        return { success: false, error: 'Bijwerken mislukt' };
    }

    if (azureGroupId) {
        const path = currentIsLeader
            ? `${getAzureManagementUrl()}/api/groups/${encodeURIComponent(azureGroupId)}/owners/${encodeURIComponent(entraId)}`
            : `${getAzureManagementUrl()}/api/groups/${encodeURIComponent(azureGroupId)}/owners`;
        const method = currentIsLeader ? 'DELETE' : 'POST';
        await fetch(path, {
            method,
            headers: serviceHeaders(),
            body: currentIsLeader ? undefined : JSON.stringify({ userId: entraId }),
        }).catch(e => console.warn('[committees] Azure owner sync failed:', e));
    }

    return { success: true };
}

'use server';

import { auth } from '@/server/auth/auth';
import { headers } from 'next/headers';
import { revalidatePath } from 'next/cache';
import { isSuperAdmin } from '@/lib/auth-utils';

import { getSystemDirectus } from '@/lib/directus';
import { 
    readItems, 
    updateItem, 
    deleteItem, 
    createItem 
} from '@directus/sdk';
import { COUPON_FIELDS } from '@salvemundi/validations';

import { AdminResource } from '@/shared/lib/permissions-config';
import { hasPermission } from '@/shared/lib/permissions';

async function checkAccess() {
    const session = await auth.api.getSession({ headers: await headers() });
    if (!session?.user) throw new Error('Niet ingelogd');

    const user = session.user as any;
    if (!hasPermission((user as any).committees, AdminResource.Coupons)) {
        throw new Error('Geen toegang: onvoldoende rechten voor coupon beheer');
    }

    return session;
}

export type Coupon = {
    id: number;
    coupon_code: string;
    discount_type: 'fixed' | 'percentage';
    discount_value: number;
    usage_count: number;
    usage_limit: number | null;
    valid_from: string | null;
    valid_until: string | null;
    is_active: boolean;
    date_created?: string;
};

export type CouponStatus = 'active' | 'expired' | 'maxed' | 'inactive' | 'pending';

export async function getCoupons(): Promise<Coupon[]> {
    await checkAccess();
    try {
        const items = await getSystemDirectus().request(readItems('coupons', {
            sort: ['-id'],
            limit: 500,
            fields: [...COUPON_FIELDS]
        }));
        return (items ?? []).map(i => ({
            ...i,
            id: Number(i.id),
            coupon_code: i.coupon_code || '',
            discount_type: (i.discount_type || 'percentage') as 'fixed' | 'percentage',
            discount_value: Number(i.discount_value),
            usage_count: Number(i.usage_count),
            is_active: !!i.is_active
        })) as Coupon[];
    } catch (e) {
        console.error('[AdminCoupons] Fetch failed:', e);
        throw new Error('Kon coupons niet ophalen');
    }
}

export async function createCoupon(formData: FormData): Promise<{ success: boolean; error?: string; fieldErrors?: Record<string, string[]> }> {
    await checkAccess();

    const code = formData.get('coupon_code') as string;
    const discountType = formData.get('discount_type') as string;
    const discountValueRaw = formData.get('discount_value') as string;
    const usageLimitRaw = formData.get('usage_limit') as string;
    const validFrom = formData.get('valid_from') as string;
    const validUntil = formData.get('valid_until') as string;
    const isActive = formData.get('is_active') === 'on';

    if (!code || !discountValueRaw) {
        return { success: false, error: 'Coupon code en waarde zijn verplicht' };
    }

    const discountValue = parseFloat(discountValueRaw.replace(',', '.'));
    if (isNaN(discountValue) || discountValue <= 0) {
        return { success: false, error: 'Ongeldige kortingswaarde: moet een positief getal zijn' };
    }

    if (discountType === 'percentage' && (discountValue > 100 || discountValue <= 0)) {
        return { success: false, error: 'Percentage moet tussen 0.01% en 100% liggen' };
    }

    let usageLimit: number | null = null;
    if (usageLimitRaw) {
        usageLimit = parseInt(usageLimitRaw);
        if (isNaN(usageLimit) || usageLimit < 1) {
            return { success: false, error: 'Gebruikslimiet moet minimaal 1 zijn (of leeg voor onbeperkt)' };
        }
    }

    const payload: Record<string, unknown> = {
        coupon_code: code.trim().toUpperCase(),
        discount_type: discountType,
        discount_value: discountValue,
        is_active: isActive,
        usage_count: 0,
        usage_limit: usageLimit,
        valid_from: validFrom || null,
        valid_until: validUntil || null,
    };

    const session = await auth.api.getSession({ headers: await headers() });
    if (!session) throw new Error('Unauthorized');
    try {
        await getSystemDirectus().request(createItem('coupons', payload));
        revalidatePath('/beheer/coupons');
        return { success: true };
    } catch (e) {
        console.error('[AdminCoupons] Create failed:', e);
        // Directus SDK errors might contain more info, but for simplicity:
        return { success: false, error: 'Aanmaken mislukt (controleer op unieke code)' };
    }
}

export async function deleteCoupon(id: number): Promise<{ success: boolean; error?: string }> {
    const session = await checkAccess();
    try {
        await getSystemDirectus().request(deleteItem('coupons', id));
