    const { success } = await rateLimit('file-upload', 5, 300);
    if (!success) {
        throw new Error('Te veel bestanden geüpload. Probeer het later opnieuw.');
    }
    try {
        const directus = getSystemDirectus();
        const result = await directus.request(uploadFiles(formData));
        return (result as any).id;
    } catch (error) {
        console.error('[Stickers] Photo upload failed:', error);
        throw new Error('Foto upload mislukt op de server.');
    }
}

'use server';

import { connection } from 'next/server';

import { documentenSchema, type Document, DOCUMENT_FIELDS, FEATURE_FLAG_FIELDS } from '@salvemundi/validations';

import { getSystemDirectus } from '@/lib/directus';
import { readItems } from '@directus/sdk';

export async function getDocumenten(): Promise<Document[]> {
    try {
        const rawData = await getSystemDirectus().request(readItems('documents', {
            fields: [...DOCUMENT_FIELDS],
            sort: ['display_order'],
            limit: 50
        }));

        const parsed = documentenSchema.safeParse(rawData);

        if (!parsed.success) {
            console.error('[website.actions#getDocumenten] Zod validation failed:', {
                fieldErrors: parsed.error.flatten().fieldErrors,
            });
            return [];
        }

        return parsed.data;
    } catch (err: unknown) {
        console.error(`[website.actions#getDocumenten] Fetch failed:`, err);
        return [];
    }
}

export async function getDisabledRoutes(): Promise<string[]> {
    await connection();
    try {
        const result = await getSystemDirectus().request(readItems('feature_flags', {
            filter: { is_active: { _eq: false } },
            fields: [...FEATURE_FLAG_FIELDS]
        }));

        return result
            .map((flag: any) => flag.route_match)
            .filter((route: string | null | undefined): route is string => Boolean(route));
    } catch (err) {
        console.error('[website.actions#getDisabledRoutes] Error:', err);
        return [];
    }
}

import { betterAuth } from "better-auth";
import { nextCookies } from "better-auth/next-js";
import { Pool } from "pg";
import { createRedisSessionPlugin } from "./redis-session-plugin";

// Database Pool — gebruik object config zodat speciale tekens in wachtwoorden
// geen URL-parseer problemen veroorzaken (bijv. @ of / in het wachtwoord).
const pool = new Pool({
    user: process.env.DB_USER,
    password: process.env.DB_PASSWORD,
    host: process.env.DB_HOST || process.env.INTERNAL_DB_HOST || 'v7-core-db',
    port: 5432,
    database: process.env.DB_NAME,
});

export const auth = betterAuth({
    database: pool,
    secret: process.env.BETTER_AUTH_SECRET,
    baseURL: process.env.BETTER_AUTH_URL,
    advanced: {
        trustHost: true
    } as any,
    trustedOrigins: process.env.BETTER_AUTH_TRUSTED_ORIGINS
        ? process.env.BETTER_AUTH_TRUSTED_ORIGINS.split(',')
        : [process.env.BETTER_AUTH_URL!],
    socialProviders: {
        microsoft: {
            clientId: process.env.AZURE_WEBSITEV7_AUTH_CLIENT_ID!,
            clientSecret: process.env.AZURE_WEBSITEV7_AUTH_CLIENT_SECRET!,
            tenantId: process.env.AZURE_WEBSITEV7_TENANT_ID!,
        },
    },
    user: {
        modelName: "directus_users",
        additionalFields: {
            first_name: { type: "string" },
            last_name: { type: "string" },
            membership_status: { type: "string" },
            membership_expiry: { type: "string" },
            phone_number: { type: "string" },
            date_of_birth: { type: "string" },
            avatar: { type: "string" },
